-- Poems batch 354
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('92771225-8223-48b9-8615-0f0037df54b8','風幡誰動','釋守卓','宋','宋诗','song-poetry','','[]','夢遊華頂過丹丘，躡盡寒雲倚石樓。',32,'全唐诗/poet.song.72000.json','["夢遊華頂過丹丘，躡盡寒雲倚石樓。", "貪看瀑泉瀉崖壁，豈知身在碧江頭。"]'),
('af3a7173-7403-4db1-a253-184bd406dfc1','目前無法意在目前','釋守卓','宋','宋诗','song-poetry','','[]','九轉靈丹難却易，一鎚便當易還難。',32,'全唐诗/poet.song.72000.json','["九轉靈丹難却易，一鎚便當易還難。", "相逢話盡壺中事，重把仙書子細看。"]'),
('010b7993-82f5-4ad9-9ae9-b1f77e6f28b6','昨日栽茄子','釋守卓','宋','宋诗','song-poetry','','[]','钁子頭邊得意時，開花著子不愁伊。',32,'全唐诗/poet.song.72000.json','["钁子頭邊得意時，開花著子不愁伊。", "幾多不善根株者，祇見枝頭又長枝。"]'),
('c9dfc201-b78e-4d30-b67b-d53fa5802f47','趙州勘婆','釋守卓','宋','宋诗','song-poetry','','[]','勘破誰知老趙州，玉鞭鞭起卧金牛。',32,'全唐诗/poet.song.72000.json','["勘破誰知老趙州，玉鞭鞭起卧金牛。", "臺山今古行人口，笑飲清風味轉幽。"]'),
('6e858b73-98b1-4987-8c7b-54e69290a032','智門蓮花','釋守卓','宋','宋诗','song-poetry','','[]','蓮花荷葉的須分，無限清香付與君。',32,'全唐诗/poet.song.72000.json','["蓮花荷葉的須分，無限清香付與君。", "彈指若知霄漢路，便能平地起烟雲。"]'),
('8d7a91a3-c22e-4818-8510-8d9733e06111','寒時寒殺闍黎','釋守卓','宋','宋诗','song-poetry','','[]','偏中有正正中偏，流落人間百萬年。',32,'全唐诗/poet.song.72000.json','["偏中有正正中偏，流落人間百萬年。", "幾度欲歸歸不得，門前依舊草芊芊。"]'),
('82d88ac9-67c7-4b26-83fe-aaad080bbc92','道吾生也不道','釋守卓','宋','宋诗','song-poetry','','[]','木人把板雲中唱，石女穿靴水上行。',32,'全唐诗/poet.song.72000.json','["木人把板雲中唱，石女穿靴水上行。", "生死死生休更問，從來日午打三更。"]'),
('43322099-14f5-44cb-8b0f-2c2ed5801c87','投子下繩床立','釋守卓','宋','宋诗','song-poetry','','[]','愛向江邊弄釣絲，碧潭深處有嘉魚。',32,'全唐诗/poet.song.72000.json','["愛向江邊弄釣絲，碧潭深處有嘉魚。", "鈎頭不是無香餌，箇底如何釣得渠。"]'),
('0ef290fb-7b63-4e0d-8d5a-4747e3200739','蝦蟆頭上戴青苔','釋守卓','宋','宋诗','song-poetry','','[]','蝦蟆頭上戴青苔，繡出鴛鴦孰辨猜。',32,'全唐诗/poet.song.72000.json','["蝦蟆頭上戴青苔，繡出鴛鴦孰辨猜。", "幾許離人消息斷，一聲鴻雁送愁來。"]'),
('89efda23-a415-43ae-8fde-2adea5a6955c','長沙令人問三聖南泉遷化向什麽處去','釋守卓','宋','宋诗','song-poetry','','[]','探花蝴蝶舞三臺，啄木掉頭鳴訝鼓。',32,'全唐诗/poet.song.72000.json','["探花蝴蝶舞三臺，啄木掉頭鳴訝鼓。", "處處相逢岑大蟲，元來便是玄沙虎。"]'),
('30e69fb0-b0ab-4bd1-b68e-9af19e5e16cb','巖頭甘贄家過夏因緣二頌  其一','釋守卓','宋','宋诗','song-poetry','','[]','一回喫水一回噎，百鍊精金要人別。',32,'全唐诗/poet.song.72000.json','["一回喫水一回噎，百鍊精金要人別。", "門前誰解倒剎竿，甕裏何曾失却鼈。"]'),
('7771e4f9-7319-4359-a7ad-bfc38e51185a','巖頭甘贄家過夏因緣二頌  其二','釋守卓','宋','宋诗','song-poetry','','[]','針頭扎去幾人知，婦兒女子莫猜疑。',32,'全唐诗/poet.song.72000.json','["針頭扎去幾人知，婦兒女子莫猜疑。", "聖凡命脈果何在，向此須明上上機。"]'),
('2209936c-a0b4-4bab-aac4-18390c91e7e8','世尊拈花迦葉微笑','釋守卓','宋','宋诗','song-poetry','','[]','世尊拈花，迦葉微笑。',46,'全唐诗/poet.song.72000.json','["世尊拈花，迦葉微笑。", "不落宮商，是何曲調。", "古洞風清，寒潭月皎。", "報公知，須曉了，融峰最好音聲鳥。"]'),
('b8d86978-ba24-4d58-92dc-62d53d9e1fd2','日面佛月面佛','釋守卓','宋','宋诗','song-poetry','','[]','日面佛，月面佛，大海波翻，須彌突兀。',44,'全唐诗/poet.song.72000.json','["日面佛，月面佛，大海波翻，須彌突兀。", "磕破腦門，額頭汗出。", "明眼衲僧未辨明，擡頭好看沖天鶻。"]'),
('0e160bf6-a43b-43bf-821f-c4e94412f161','德山棒臨濟喝','釋守卓','宋','宋诗','song-poetry','','[]','德山棒，臨濟喝。',45,'全唐诗/poet.song.72000.json','["德山棒，臨濟喝。", "銅金剛，鐵菩薩。", "轟雷發處，有耳皆聾。", "撒星來時，無眼不瞎，瞎與公重指曹溪月。"]'),
('949dfff5-08dd-4882-9bbe-7d795b63e951','三聖到德山即展坐具','釋守卓','宋','宋诗','song-poetry','','[]','呼爲雲，吸爲雨，襲襲清風動寰宇。',60,'全唐诗/poet.song.72000.json','["呼爲雲，吸爲雨，襲襲清風動寰宇。", "笑哭不是等閑聲，路見不平應有主。", "要斬不平人，不與平人語。", "而今何處見蹤由，剔起眉毛看鷂子。"]'),
('93048268-3e0c-41d9-98f1-44d23e2fff50','定上座橋上立有座主問如何是禪河深處須窮底','釋守卓','宋','宋诗','song-poetry','','[]','辨金要識鍮，覓髓須打骨。',56,'全唐诗/poet.song.72000.json','["辨金要識鍮，覓髓須打骨。", "平地激風波，禪河沒窠窟。", "黨理亦黨親，成家又成國。", "拗拗墝墝，突突兀兀。", "無限傍人，眼睛凸出。"]'),
('f2620de5-a6a0-4b41-b5d1-8b193f886cb0','睦州擔板','釋守卓','宋','宋诗','song-poetry','','[]','腦後與一錐，頭頭墮坑坎。',40,'全唐诗/poet.song.72000.json','["腦後與一錐，頭頭墮坑坎。", "直饒喚不迴，也是虛擔板。", "休擔板，透過睦州關，乾坤一隻眼。"]'),
('8f7a1986-4ec1-4152-b5df-26d0ccee4cd4','雲門俱子','釋守卓','宋','宋诗','song-poetry','','[]','俱，俱，本祖丕圖。',45,'全唐诗/poet.song.72000.json','["俱，俱，本祖丕圖。", "淳風一振，處處歡呼。", "百草頭上，薦獻還殊。", "七佛之師親識面，元來祇是古文殊。"]'),
('fd9a1737-bea6-4410-9902-e40518e6fab3','曹山向火因緣日照寒潭明更明','釋守卓','宋','宋诗','song-poetry','','[]','日照寒潭明更明，寥寥虎嘯清風生。',48,'全唐诗/poet.song.72000.json','["日照寒潭明更明，寥寥虎嘯清風生。", "寰中閫外應須辨，白玉盤盛鐵眼睛。", "曹山老，曹山老，正去偏來沒處討。"]'),
('2f2d8ee3-721a-4dd4-b3e8-f7470111d3b4','三界唯心萬法唯識','釋守卓','宋','宋诗','song-poetry','','[]','三界唯心，海嶽銷沈。',70,'全唐诗/poet.song.72000.json','["三界唯心，海嶽銷沈。", "萬法唯識，青黄曲直。", "天上人間，迺規迺則。", "眼耳即真，見聞俱惑。", "孰爲言宣，詎假玄默。", "混爾圓常，分爾百億。", "迷悟不來，塵毛匪忒。"]'),
('e5b1f150-c029-459f-9d88-315f0a085874','雲門餬餠','釋守卓','宋','宋诗','song-poetry','','[]','左眼半斤，右眼八兩。',20,'全唐诗/poet.song.72000.json','["左眼半斤，右眼八兩。", "不問親疏，有功者賞。"]'),
('3e23d6cb-f6d9-4ddb-b14c-d0715eb194a6','乾峰十方薄伽梵','釋守卓','宋','宋诗','song-poetry','','[]','須彌頭倒卓，碧海起清風。',24,'全唐诗/poet.song.72000.json','["須彌頭倒卓，碧海起清風。", "東弗已摇落，西瞿花正紅。"]'),
('d3b0cb58-5737-40a6-bf7f-52338fb679be','即心即佛','釋守卓','宋','宋诗','song-poetry','','[]','風勁葉頻落，山高日易沈。',24,'全唐诗/poet.song.72000.json','["風勁葉頻落，山高日易沈。", "坐中人不見，窗外白雲深。"]'),
('f20bf4dd-92cc-4e71-9099-19e33c8a96a8','僧問四料揀因而頌之  其一','釋守卓','宋','宋诗','song-poetry','','[]','奪人不奪境，山河光炯炯。',24,'全唐诗/poet.song.72000.json','["奪人不奪境，山河光炯炯。", "若謂露全身，重添眼中眚。"]'),
('cf870d6e-a9fe-4923-97d0-88bf1f58c2fc','僧問四料揀因而頌之  其二','釋守卓','宋','宋诗','song-poetry','','[]','奪境不奪人，虛空問四鄰。',24,'全唐诗/poet.song.72000.json','["奪境不奪人，虛空問四鄰。", "從來無眹兆，何事起埃塵。"]'),
('4bcc130e-7628-4c5e-bdc5-75c80c81104e','僧問四料揀因而頌之  其三','釋守卓','宋','宋诗','song-poetry','','[]','人境兩俱奪，倒轉舌頭說。',24,'全唐诗/poet.song.72000.json','["人境兩俱奪，倒轉舌頭說。", "四句若爲分，曇花生枯枿。"]'),
('c2230454-fadc-4e0f-a4da-f963318f7532','僧問四料揀因而頌之  其四','釋守卓','宋','宋诗','song-poetry','','[]','人境俱不奪，東西任該抹。',24,'全唐诗/poet.song.72000.json','["人境俱不奪，東西任該抹。", "七九六十三，相逢阿喇喇。"]'),
('6f7e6c1d-0f67-4ae5-a6a5-7204a0fb8180','總頌','釋守卓','宋','宋诗','song-poetry','','[]','人境奪不奪，千手未拈掇。',24,'全唐诗/poet.song.72000.json','["人境奪不奪，千手未拈掇。", "捧出黄金盤，贈君貯明月。"]'),
('305eb3a3-a7c3-4bf6-881c-dcd4989cc762','答問頌五首  其一','釋守卓','宋','宋诗','song-poetry','','[]','有賓有主，父子規程。',20,'全唐诗/poet.song.72000.json','["有賓有主，父子規程。", "子無線索，妙辨縱橫。"]'),
('a3ecf7d7-b05e-488e-8ae6-3acdf840daf5','答問頌五首  其二','釋守卓','宋','宋诗','song-poetry','','[]','一棒一條痕，蒺蔾好自吞。',24,'全唐诗/poet.song.72000.json','["一棒一條痕，蒺蔾好自吞。", "仙陀還蹉過，贏得瞎馿存。"]'),
('a7634ece-2de0-4c77-b2cb-54dac9f21118','答問頌五首  其三','釋守卓','宋','宋诗','song-poetry','','[]','東山水上行，枯骨壯韓情。',24,'全唐诗/poet.song.72000.json','["東山水上行，枯骨壯韓情。", "藤林荒已久，三句若爲明。"]'),
('2a63098e-b075-4c9c-b803-bce400204d7d','答問頌五首  其四','釋守卓','宋','宋诗','song-poetry','','[]','烏鷄頭带雪，偏正沒安排。',24,'全唐诗/poet.song.72000.json','["烏鷄頭带雪，偏正沒安排。", "明月堂前意，悠悠莫亂猜。"]'),
('4007e3bf-2348-4b9c-b49c-6363e4b4f306','答問頌五首  其五','釋守卓','宋','宋诗','song-poetry','','[]','問取修山主，淺淺實甚深。',24,'全唐诗/poet.song.72000.json','["問取修山主，淺淺實甚深。", "若謂唯心現，玄艘已陸沉。"]'),
('9dc449fa-6fad-4401-a368-8a4a88b5ccd6','宗門一句','釋守卓','宋','宋诗','song-poetry','','[]','宗門一句，明明獨露。',140,'全唐诗/poet.song.72000.json','["宗門一句，明明獨露。", "孰辨端倪，胡爲指注。", "指注不真，鏡像空塵。", "空塵何立，鏡像誰入。", "當機則應，頭頭非剩。", "觸處俱宣，句句通玄。", "門門賓主，互正互偏。", "含容透脫，千江一月。", "無在不在，誰憎誰愛。", "煥爾既明，森然不礙。", "不礙既明，金剛眼睛。", "窮幽測顯，神妙體靈。", "妙靈不住，無生不生。", "是宜超越，所以縱橫。"]'),
('3866c027-e17f-464a-9466-3dfa07fad856','迷悟何從','釋守卓','宋','宋诗','song-poetry','','[]','恰恰今人用，明明古佛心。',24,'全唐诗/poet.song.72000.json','["恰恰今人用，明明古佛心。", "寒雲歸碧嶂，幽鳥下青林。"]'),
('d1728107-298d-4dd5-b6b3-e115f7ad14d1','白珪無玷','釋守卓','宋','宋诗','song-poetry','','[]','雲生不翳空，日上難逃影。',24,'全唐诗/poet.song.72000.json','["雲生不翳空，日上難逃影。", "相逢一笑中，何須重反省。"]'),
('c68acb27-4500-4c65-9479-14d6b1c8f7b5','答客問','釋守卓','宋','宋诗','song-poetry','','[]','從來住處無人識，今日勞公扣指南。',32,'全唐诗/poet.song.72000.json','["從來住處無人識，今日勞公扣指南。", "是眼不應還見眼，從教佛祖競來參。"]'),
('7c5c56f2-c84e-493c-ae49-cd8727fd8260','示辨實','釋守卓','宋','宋诗','song-poetry','','[]','一酬一問分賓主，端的如何辨正邪。',32,'全唐诗/poet.song.72000.json','["一酬一問分賓主，端的如何辨正邪。", "卓爾未能超本際，茫茫難透眼前花。"]'),
('cf4320a7-cf2f-4927-b942-cc5dd90fcdc2','會同風','釋守卓','宋','宋诗','song-poetry','','[]','君子南北我東西，瞥爾惺惺忽爾迷。',32,'全唐诗/poet.song.72000.json','["君子南北我東西，瞥爾惺惺忽爾迷。", "一笑一狂誰會得，白雲深處有猿啼。"]'),
('eed0f5e8-1e19-4742-b905-f13d26d0396b','偶言','釋守卓','宋','宋诗','song-poetry','','[]','巖松森翠皆穿眼，澗水清泠亦到心。',32,'全唐诗/poet.song.72000.json','["巖松森翠皆穿眼，澗水清泠亦到心。", "自笑不能修白業，祇憑流水念觀音。"]'),
('ea56f476-1ea8-448e-8310-8bdb83369521','東山禮祖塔二首  其一','釋守卓','宋','宋诗','song-poetry','','[]','雲擁蓮峰插太虛，清香不付嶺南盧。',32,'全唐诗/poet.song.72000.json','["雲擁蓮峰插太虛，清香不付嶺南盧。", "而今五葉分明在，觸處離披見得無。"]'),
('5916a334-19b6-4c37-927c-c285780c253f','東山禮祖塔二首  其二','釋守卓','宋','宋诗','song-poetry','','[]','古鑑光分前後身，擬於何處拂埃塵。',32,'全唐诗/poet.song.72000.json','["古鑑光分前後身，擬於何處拂埃塵。", "易觀剎海毛端現，難把師心說向人。"]'),
('2b296204-1119-4e09-ab78-0e68456fa045','贊飲光','釋守卓','宋','宋诗','song-poetry','','[]','千聞巧演眉猶蹙，一見輕拈笑不休。',32,'全唐诗/poet.song.72000.json','["千聞巧演眉猶蹙，一見輕拈笑不休。", "笑裏藏鋒誰辨的，剎竿倒却有來由。"]'),
('59cbb771-3131-4bc1-95eb-bd249fcf1101','贊達磨','釋守卓','宋','宋诗','song-poetry','','[]','神光的的見聱訛，面壁喃喃語更多。',32,'全唐诗/poet.song.72000.json','["神光的的見聱訛，面壁喃喃語更多。", "不是梁王先勘破，脫身歸去奈渠何。"]'),
('38efe230-e1ab-462b-bdd8-845f4150d085','贊二祖','釋守卓','宋','宋诗','song-poetry','','[]','斷臂求師，平田失脚。',30,'全唐诗/poet.song.72000.json','["斷臂求師，平田失脚。", "三拜依位，誠人得謔。", "稽首高深，少峰伊洛。"]'),
('ade836f6-0c58-485b-9d84-8b34dadec007','贊三祖','釋守卓','宋','宋诗','song-poetry','','[]','白衣受道，瘥病非藥。',30,'全唐诗/poet.song.72000.json','["白衣受道，瘥病非藥。", "無欠無餘，有鎚有鑿。", "覓解脫門，汝爲誰縛。"]'),
('3305818c-380e-4fc1-95a3-60351805f43e','贊四祖','釋守卓','宋','宋诗','song-poetry','','[]','法法明心，塵塵垂手。',30,'全唐诗/poet.song.72000.json','["法法明心，塵塵垂手。", "正出黄梅，傍生牛首。", "巍巍雙峰，天長地久。"]'),
('556681fd-ee91-4ef8-960c-19018b385039','贊五祖','釋守卓','宋','宋诗','song-poetry','','[]','濁港轉身，破頭印法。',30,'全唐诗/poet.song.72000.json','["濁港轉身，破頭印法。", "五葉芬芳，千徒雜踏。", "於秀於能，誰離誰合。"]'),
('af34773f-1eaf-40fb-83e0-cfae96c03f4b','贊六祖','釋守卓','宋','宋诗','song-poetry','','[]','駕白牛車，受黄梅印。',56,'全唐诗/poet.song.72000.json','["駕白牛車，受黄梅印。", "沒體歸神，當機發迅。", "真軌無差，坤維大順。", "衣止不傳，法唯自信。", "曹源一滴起滔天，千古南宗誰獨振。"]'),
('ad4eba1d-afa2-489e-a6ad-167b7f16b19c','贊靈源和尚二首  其一','釋守卓','宋','宋诗','song-poetry','','[]','拳下翻身，竿頭進步。',40,'全唐诗/poet.song.72000.json','["拳下翻身，竿頭進步。", "萬派同歸，靈源獨露。", "瓦礫光輝，風雲流布。", "千眼那知，羣心自度。"]'),
('ea438798-3356-496f-841c-10061318901e','贊靈源和尚二首  其二','釋守卓','宋','宋诗','song-poetry','','[]','靈靈在源，昭昭而默。',80,'全唐诗/poet.song.72000.json','["靈靈在源，昭昭而默。", "不汝不誰，奔南走北。", "同佛同魔，佛魔自或。", "衲子之禍，偏見之賊。", "跛跛挈挈兮我師無師，渾渾侖侖兮人識不識。", "前三十年，拶破一拳。", "直至如今，虛空偪塞。"]'),
('e33f0c8b-3863-4e2d-b301-66f26ddcf976','贊太平懃禪師','釋守卓','宋','宋诗','song-poetry','','[]','鐵石咽喉，吞栗棘蓬於白雲山下。',76,'全唐诗/poet.song.72000.json','["鐵石咽喉，吞栗棘蓬於白雲山下。", "風霜號令，示金剛圈於皖伯臺前。", "十年據坐道場，四海喧騰聲價。", "無佛法可說，有公桉須行。", "望風何多，一進一退。", "稽首贊揚，得罪得罪。"]'),
('df70d41e-3dc1-4acf-98e1-bf8633789be3','師自作真贊  其一','釋守卓','宋','宋诗','song-poetry','','[]','錐扎不入，頑皮太煞。',30,'全唐诗/poet.song.72000.json','["錐扎不入，頑皮太煞。", "自無一文，隨方買賣。", "淮田神州，酬還宿債。"]'),
('cac860ac-53eb-4051-bd1a-d387f32bbb21','師自作真贊  其二','釋守卓','宋','宋诗','song-poetry','','[]','潰散百骸從齷齪，一長靈物熟知音。',32,'全唐诗/poet.song.72000.json','["潰散百骸從齷齪，一長靈物熟知音。", "銀蟾不落清江裏，坐對黄花秋已深。"]'),
('fb19cd50-86e0-4d14-906d-1e6b82eb7bf3','師自作真贊  其三','釋守卓','宋','宋诗','song-poetry','','[]','鏡中電影急觀瞻，水底燈毬休把捉。',32,'全唐诗/poet.song.72000.json','["鏡中電影急觀瞻，水底燈毬休把捉。", "忘言要辨此時機，萬里清秋看一鶚。"]'),
('b01df8f2-95ab-41b9-bc66-e7ce54d9b23c','師自作真贊  其四','釋守卓','宋','宋诗','song-poetry','','[]','南海之濱，兔生兩角。',40,'全唐诗/poet.song.72000.json','["南海之濱，兔生兩角。", "幕阜之頂，磽磽确确。", "從十年游，脚跟皴剝。", "討甚機鋒，七錯八錯。"]'),
('0438cd62-9ace-434a-b52f-c3732d640df9','師自作真贊  其五','釋守卓','宋','宋诗','song-poetry','','[]','鐵牛奔入玉麟隊，自古無雙今一對。',32,'全唐诗/poet.song.72000.json','["鐵牛奔入玉麟隊，自古無雙今一對。", "脫體堂堂呈似伊，有眼無口如何會。"]'),
('d4f5e3d5-2f39-428b-81ed-5ad84867b371','師自作真贊  其六','釋守卓','宋','宋诗','song-poetry','','[]','曾戴花冠入東魯，又携角杖到西乾。',32,'全唐诗/poet.song.72000.json','["曾戴花冠入東魯，又携角杖到西乾。", "惡嫌黄檗無多子，笑許韶陽爛漫禪。"]'),
('76a8f60c-bb72-4e8d-ad4c-29d4c30bb098','牧牛頌示衆','釋守卓','宋','宋诗','song-poetry','','[]','日用須牧牛，鼻索莫離手。',48,'全唐诗/poet.song.72000.json','["日用須牧牛，鼻索莫離手。", "露地非自然，馴良在日久。", "鞭繩既無用，人牛復何有。", "此時唯己知，始覺從前咎。"]'),
('605fb08d-b4a6-4123-8666-5fd9e9c0b1a3','讀傳燈錄','釋守卓','宋','宋诗','song-poetry','','[]','誰謂拈花後，聯芳直至今。',48,'全唐诗/poet.song.72000.json','["誰謂拈花後，聯芳直至今。", "到頭珠有水，未免線因針。", "蝶在花猶在，春深草亦深。", "軒窗倚疏豁，閑聽洞龍吟。"]'),
('0287ebe6-a31e-4725-8515-a14525df0659','和昭默老人寄示拂子頌','釋守卓','宋','宋诗','song-poetry','','[]','即此用，離此用，箭未離弦的先中。',64,'全唐诗/poet.song.72000.json','["即此用，離此用，箭未離弦的先中。", "萬仞崖前撒手歸，一句機玄無用用。", "此時針芥審無差，戴恩奚翅丘山重。", "誓捐軀命壯縣絲，隨波聊與人天共。"]'),
('dded3ef1-8785-4952-a237-edddf78029ed','題廓然居士指菴','釋守卓','宋','宋诗','song-poetry','','[]','全指即亡指，應機何有機。',48,'全唐诗/poet.song.72000.json','["全指即亡指，應機何有機。", "此菴容法界，當處洞真歸。", "寂是用還是，生非佛亦非。", "南方休更問，一笑豁離微。"]'),
('df346dfa-cbdf-4e37-bc00-2c1eb532ff2f','劉公任侍郎比乞法名示之以妙通茲承佳偈因和以答','釋守卓','宋','宋诗','song-poetry','','[]','法法彰全妙，心心祇自通。',48,'全唐诗/poet.song.72000.json','["法法彰全妙，心心祇自通。", "迥然分木迹，廓爾絕邊中。", "諦了名斯立，安行實所從。", "大哉無事事，裴運有孤風。"]'),
('b424000f-9b6c-4191-8ca7-f9d06431f3d8','即來言和答公任侍郎  其一','釋守卓','宋','宋诗','song-poetry','','[]','迥脫根塵始識塵，了無所得才真得。',32,'全唐诗/poet.song.72000.json','["迥脫根塵始識塵，了無所得才真得。", "堂堂獨露本來光，越自南兮胡自北。"]'),
('fe8978f3-d88b-4f67-b240-14701910f750','即來言和答公任侍郎  其二','釋守卓','宋','宋诗','song-poetry','','[]','打破乾坤渠即我，包衾覆載我非渠。',32,'全唐诗/poet.song.72000.json','["打破乾坤渠即我，包衾覆載我非渠。", "渠渠我我教誰識，當體玄玄祇自如。"]'),
('641dc968-da6a-466b-8442-1eec29cc36d5','即來言和答公任侍郎  其三','釋守卓','宋','宋诗','song-poetry','','[]','曠大劫來沒作做，今日非新昨非故。',32,'全唐诗/poet.song.72000.json','["曠大劫來沒作做，今日非新昨非故。", "回光暫借瞥時間，豁見長靈名得度。"]'),
('5fdf02c8-3b1c-4852-9660-980afbdbc942','和答妙靈修撰謝法名','釋守卓','宋','宋诗','song-poetry','','[]','扣己的明無妙妙，參渠始見不靈靈。',32,'全唐诗/poet.song.72000.json','["扣己的明無妙妙，參渠始見不靈靈。", "妙靈靈處誰參扣，瞥轉機輪悟獨醒。"]'),
('ba494420-3f5f-4c1b-985d-292db54b340f','靈然居士施曲木禪床因坐小參以頌示衆','釋守卓','宋','宋诗','song-poetry','','[]','靈然家秘曲木床，願供長靈坐八荒。',64,'全唐诗/poet.song.72000.json','["靈然家秘曲木床，願供長靈坐八荒。", "衲子惺惺爲掀倒，翻然獨露本然光。", "本然光透呵呵笑，無限虛空呈一竅。", "南海波斯弄琵琶，聲聲解作單于調。"]'),
('48f9c9f9-c9dd-434a-9bdb-0285e063ef10','小偈四首寄示心然道人聊資體味以進箇中精淳之趣  其一','釋守卓','宋','宋诗','song-poetry','','[]','心然法法然，法異心心異。',24,'全唐诗/poet.song.72000.json','["心然法法然，法異心心異。", "透過然異來，許你箇巴鼻。"]'),
('c9c8b4a4-c490-4a75-85f9-28b236c08285','小偈四首寄示心然道人聊資體味以進箇中精淳之趣  其二','釋守卓','宋','宋诗','song-poetry','','[]','箇中好巴鼻，言下須瞥地。',24,'全唐诗/poet.song.72000.json','["箇中好巴鼻，言下須瞥地。", "寂寂要惺惺，當機善游戲。"]'),
('f284a7db-daba-4b4a-a4d6-ff531cf36e96','小偈四首寄示心然道人聊資體味以進箇中精淳之趣  其三','釋守卓','宋','宋诗','song-poetry','','[]','心然法法死，大用始全舉。',24,'全唐诗/poet.song.72000.json','["心然法法死，大用始全舉。", "的的徹生生，互非互相許。"]'),
('1dd18ddf-883d-4933-9d27-155a6ce21caa','小偈四首寄示心然道人聊資體味以進箇中精淳之趣  其四','釋守卓','宋','宋诗','song-poetry','','[]','非許復何如，法界一蘧廬。',24,'全唐诗/poet.song.72000.json','["非許復何如，法界一蘧廬。", "於中全諦實，此外盡撩虛。"]'),
('04732b60-ad37-4a2d-b5a1-c16cfd0deafc','寄徐師利  其一','釋守卓','宋','宋诗','song-poetry','','[]','要明得喪非干我，須到身心洞徹時。',32,'全唐诗/poet.song.72000.json','["要明得喪非干我，須到身心洞徹時。", "徹處忘緣緣即徹，從茲出處但隨宜。"]'),
('69cf97fa-c2ac-49fc-94ab-c524514699f4','寄徐師利  其二','釋守卓','宋','宋诗','song-poetry','','[]','迹在世途心了了，兩全方顯丈夫兒。',32,'全唐诗/poet.song.72000.json','["迹在世途心了了，兩全方顯丈夫兒。", "八風盡入遮那境，秘訣何勞問祖師。"]'),
('65d35221-b463-40e3-871d-38f54cb77295','送愿上人歸龍山省侍昭默老人','釋守卓','宋','宋诗','song-poetry','','[]','我省老師未嘗病，汝行親省病老師。',128,'全唐诗/poet.song.72000.json','["我省老師未嘗病，汝行親省病老師。", "汝我同門無異路，彼彼步步不相隨。", "肯謂長行無伴侶，正宜念念念在茲。", "我慚塞責成拘局，心雖默堂身遠離。", "爾能急義重去就，身心俱往更由誰。", "千里龍山不日到，歸心猶恐錫飛遲。", "無病病師力奉侍，不親親者真其資。", "雙溪幕阜不相遠，一往一來皆妙期。"]'),
('df70943b-fa77-45e8-91d4-6d76320ebf96','送諶首座歸永嘉','釋守卓','宋','宋诗','song-poetry','','[]','萬變相應一句通，十二年來已無口。',80,'全唐诗/poet.song.72000.json','["萬變相應一句通，十二年來已無口。", "別余遥指海山歸，雁蕩峰作師子吼。", "此旨明明不覆藏，冥懷自樂有餘光。", "曹源一滴流千古，宿覺徽猷振大唐。", "覿面家風人若問，釣魚須是謝三郎。"]'),
('b16ab023-ef5d-42f7-8885-601e8675b6a4','送慈侍者寧親','釋守卓','宋','宋诗','song-poetry','','[]','生緣斷處參吾道，孝義敦時念倚門。',32,'全唐诗/poet.song.72000.json','["生緣斷處參吾道，孝義敦時念倚門。", "要得一槌收兩當，別余歸去省寒溫。"]'),
('50cbd54b-d7dd-46ba-9c75-49bfc77c9d93','送僧歸永嘉','釋守卓','宋','宋诗','song-poetry','','[]','在在常參一宿覺，的的生緣非永嘉。',32,'全唐诗/poet.song.72000.json','["在在常參一宿覺，的的生緣非永嘉。", "還我今朝却歸去，大千俱屬眼中花。"]'),
('c0bed19d-9f50-43b9-b301-926d55b24850','擬寒山四首  其一','釋守卓','宋','宋诗','song-poetry','','[]','有物是何物，周流泄妙機。',48,'全唐诗/poet.song.72000.json','["有物是何物，周流泄妙機。", "春晴山鳥語，日暮洞雲歸。", "指是馬還是，心非佛亦非。", "誰能同彼此，携手入玄微。"]'),
('3aaf814d-7445-4a6b-b910-eff6b2282589','擬寒山四首  其二','釋守卓','宋','宋诗','song-poetry','','[]','一念通真際，塵塵秘藏開。',48,'全唐诗/poet.song.72000.json','["一念通真際，塵塵秘藏開。", "當頭誰是主，撒手自爲媒。", "大海收毛孔，神珠隠蚌胎。", "此時知佛祖，猶向外邊來。"]'),
('98cf5763-e1f3-4038-a58c-8db7352a4778','擬寒山四首  其三','釋守卓','宋','宋诗','song-poetry','','[]','問訊西來祖，人心爲有無。',48,'全唐诗/poet.song.72000.json','["問訊西來祖，人心爲有無。", "如何垂直指，早晚轉凡夫。", "洛水澄如練，嵩山秀若圖。", "不知端的者，剛道有差殊。"]'),
('3abb6a29-3d07-4e90-82a7-05f96836034b','擬寒山四首  其四','釋守卓','宋','宋诗','song-poetry','','[]','見道即修道，無心誰悟心。',48,'全唐诗/poet.song.72000.json','["見道即修道，無心誰悟心。", "是非凡與聖，成壞古無今。", "碧澗流殘葉，微風入靜林。", "誰來石巖下，教汝夜穿針。"]'),
('b216225f-75d8-47b2-b50e-4faf81fcc033','山居三首  其一','釋守卓','宋','宋诗','song-poetry','','[]','僧家畢竟居山好，石室茆茨養病身。',64,'全唐诗/poet.song.72000.json','["僧家畢竟居山好，石室茆茨養病身。", "開眼不知明屬日，回頭只見影隨人。", "密通蛇虎爲真友，笑與禽魚會本因。", "客間住山今幾久，一番芳草一番春。"]'),
('877008c6-85a7-4c7d-b54b-c5b0b7426992','山居三首  其二','釋守卓','宋','宋诗','song-poetry','','[]','孤猿瘦鶴冷相看，百衲三衣任歲寒。',64,'全唐诗/poet.song.72000.json','["孤猿瘦鶴冷相看，百衲三衣任歲寒。", "未擬將心求別佛，曾因撥草見幽蘭。", "誰爲虛谷呼能應，自許無弦密可彈。", "若謂本來無一物，知公親被祖師謾。"]'),
('6b39aae3-30c9-4ee4-9d19-28d78ce2bc72','山居三首  其三','釋守卓','宋','宋诗','song-poetry','','[]','當軒唯有好溪山，卒歲無人共往還。',64,'全唐诗/poet.song.72000.json','["當軒唯有好溪山，卒歲無人共往還。", "閑看白雲生翠碧，靜聞清磬落潺湲。", "聲將聲入分猶易，空以空藏見即難。", "此箇不能收拾得，任隨流水落人間。"]'),
('a3630f63-ac7d-4c54-afa1-31327167c852','漁父','釋守卓','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','白髮慵梳百不憂，與他鷗鳥日悠悠。',64,'全唐诗/poet.song.72000.json','["白髮慵梳百不憂，與他鷗鳥日悠悠。", "清朝榮辱幾番事，滿眼烟波一葉舟。", "雨過洞庭歌棹月，霜飛雲夢醉眼秋。", "蓑綸晚𣉜蘆花岸，閑扣金針作釣鈎。"]'),
('726e9f16-73a1-4ac2-b3ae-39fce3aadcb1','牧童','釋守卓','宋','宋诗','song-poetry','','[]','相呼相喚又村謳，放却牛來古渡頭。',32,'全唐诗/poet.song.72000.json','["相呼相喚又村謳，放却牛來古渡頭。", "有客問津渾不顧，笑將輕葦汎孤舟。"]'),
('56d8215d-dec0-499c-867d-09d5398e55e6','山中偶作五首  其一','釋守卓','宋','宋诗','song-poetry','','[]','萬化曾無間，真機宛自靈。',24,'全唐诗/poet.song.72000.json','["萬化曾無間，真機宛自靈。", "白雲盤作蓋，青嶂列爲屏。"]'),
('e8d34d1d-033c-4214-8afc-43516994efbb','山中偶作五首  其二','釋守卓','宋','宋诗','song-poetry','','[]','猛虎嘯寒谷，烏鴉噪晚暉。',24,'全唐诗/poet.song.72000.json','["猛虎嘯寒谷，烏鴉噪晚暉。", "圓通門大啟，何事不同歸。"]'),
('bc960a89-aa92-4baa-a2d2-c6123de7ae9a','山中偶作五首  其三','釋守卓','宋','宋诗','song-poetry','','[]','坐石弔孤影，看雲笑此身。',24,'全唐诗/poet.song.72000.json','["坐石弔孤影，看雲笑此身。", "蒲團無限意，分付與何人。"]'),
('e2f1432c-b40c-4b95-8e55-a693f51c74a8','山中偶作五首  其四','釋守卓','宋','宋诗','song-poetry','','[]','漸老便幽僻，西來意亦迷。',24,'全唐诗/poet.song.72000.json','["漸老便幽僻，西來意亦迷。", "不知師子吼，何似野猿啼。"]'),
('92cdc0c1-8d72-4840-8700-b0cda6ff36df','山中偶作五首  其五','釋守卓','宋','宋诗','song-poetry','','[]','爽快憐清景，遲回出草菴。',24,'全唐诗/poet.song.72000.json','["爽快憐清景，遲回出草菴。", "寒山一傾蓋，明月印寒潭。"]'),
('d3afed5c-8620-4ce0-aae2-403711f2005a','巖畔春將老四首  其一','釋守卓','宋','宋诗','song-poetry','','[]','巖畔春將老，香風匝地生。',24,'全唐诗/poet.song.72000.json','["巖畔春將老，香風匝地生。", "囊藏無底鉢，高卧笑毗城。"]'),
('f0d0196e-bdb9-491e-beb4-6f67144daf8c','巖畔春將老四首  其二','釋守卓','宋','宋诗','song-poetry','','[]','巖畔春將老，殘花自點苔。',24,'全唐诗/poet.song.72000.json','["巖畔春將老，殘花自點苔。", "牛頭峰下客，曾見祖師來。"]'),
('fd022b6f-43d4-4843-8d02-da0c66e16edc','巖畔春將老四首  其三','釋守卓','宋','宋诗','song-poetry','','[]','巖畔春將老，階前碧草深。',24,'全唐诗/poet.song.72000.json','["巖畔春將老，階前碧草深。", "瀏陽好風骨，一句有知音。"]'),
('e01a82c1-5f5c-4b46-95f2-e51ad3010d58','巖畔春將老四首  其四','釋守卓','宋','宋诗','song-poetry','','[]','巖畔春將老，憨癡興轉多。',24,'全唐诗/poet.song.72000.json','["巖畔春將老，憨癡興轉多。", "時時逢野老，共唱哩稜囉。"]'),
('f513bc82-b796-4b25-b742-0dc2b714d8e8','除夜','釋守卓','宋','宋诗','song-poetry','','[]','密携光景共因循，誰爲俱忘是要津。',32,'全唐诗/poet.song.72000.json','["密携光景共因循，誰爲俱忘是要津。", "毫髮不移人自老，看看啼鳥報芳春。"]'),
('b828ed14-6d02-4d9a-80bc-7d57e7a4fc1c','僧問六相義因示以偈','釋守卓','宋','宋诗','song-poetry','','[]','天上火星地下走，泥牛踏著燒却口。',32,'全唐诗/poet.song.72000.json','["天上火星地下走，泥牛踏著燒却口。", "馿兒害痛馬人瞋，打落楊梅三五斗。"]'),
('89133c95-8e43-45f6-a3bc-18dc1a92feb6','瞻雙塔','釋守卓','宋','宋诗','song-poetry','','[]','競傳垂手設三關，又說常鋒示一拳。',32,'全唐诗/poet.song.72000.json','["競傳垂手設三關，又說常鋒示一拳。", "誰信雲根涌雙塔，松風歷歷更幽玄。"]'),
('7ffef651-5280-4318-8f4f-fa7a1b614a2f','勉初志','釋守卓','宋','宋诗','song-poetry','','[]','四山相逼勢如奔，三鼠侵藤那久存。',32,'全唐诗/poet.song.72000.json','["四山相逼勢如奔，三鼠侵藤那久存。", "莫倚少年輕白日，急須回首入空門。"]'),
('62b7ea17-86bd-411e-ba55-ede670f3063e','送諸方行化  其一','釋守卓','宋','宋诗','song-poetry','','[]','衲僧無作爲，亦不坐無作。',96,'全唐诗/poet.song.72000.json','["衲僧無作爲，亦不坐無作。", "紅塵本自寂，誰解釋塵紛。", "一機雖妙常，要如千鈞弩。", "弩滿發機全，破的惟等閑。", "持此入紅塵，是謂塵中眼。", "應變猶如如，善導無所事。", "貧富自誰何，知音即所遇。", "得意早歸來，資吾無盡藏。"]'),
('4d2c6681-2955-4bf2-8b11-d4f2d8865f77','送諸方行化  其二','釋守卓','宋','宋诗','song-poetry','','[]','誰管川途凍未開，笑持鐵鉢出山來。',32,'全唐诗/poet.song.72000.json','["誰管川途凍未開，笑持鐵鉢出山來。", "心花不落東君手，待把靈根火裏栽。"]'),
('f0250067-9569-4c9c-a7da-a70107d42030','送諸方行化  其三','釋守卓','宋','宋诗','song-poetry','','[]','火裏生蓮世豈知，入廛須是丈夫兒。',32,'全唐诗/poet.song.72000.json','["火裏生蓮世豈知，入廛須是丈夫兒。", "毗耶老漢如相扣，報道年來眼搭眵。"]'),
('7b5e13a3-118c-4a44-93a8-6a633563e2ce','送諸方行化  其四','釋守卓','宋','宋诗','song-poetry','','[]','甘露無底鉢，禪人要拈撥。',50,'全唐诗/poet.song.72000.json','["甘露無底鉢，禪人要拈撥。", "浩浩塵土中，一佛二菩薩。", "撞著老維摩，輕輕共伊說。", "施者非福田，是誰納敗闕。", "咦。"]'),
('3ad796fb-0d86-4a99-90f1-1610d2ca9f38','送諸方行化  其五','釋守卓','宋','宋诗','song-poetry','','[]','本覺本來明，乘緣須體妙。',48,'全唐诗/poet.song.72000.json','["本覺本來明，乘緣須體妙。", "壁立何匹儔，漚和生談笑。", "萬化了全機，千機全一照。", "波昏月豈亡，水清光自曜。"]'),
('55a41a8e-b3fa-48ea-b92f-11d58ce8788d','送諸方行化  其六','釋守卓','宋','宋诗','song-poetry','','[]','林下既了空，塵中須達事。',48,'全唐诗/poet.song.72000.json','["林下既了空，塵中須達事。", "隨事了真空，自空展化事。", "事空空事中，淘鎔成寶器。", "寶器盛醍醐，是曰甘露味。"]'),
('281f89b4-b5b9-47e2-82d4-7a39525fdb85','送諸方行化  其七','釋守卓','宋','宋诗','song-poetry','','[]','食施何如法施均，綠楊青草幾番春。',32,'全唐诗/poet.song.72000.json','["食施何如法施均，綠楊青草幾番春。", "擎盂好好廛中去，莫惜眉毛指向人。"]'),
('9e7ac566-35dc-426f-8fa7-3412c8c21b48','座右銘','釋守卓','宋','宋诗','song-poetry','','[]','覺變則迷，識澄則悟。',70,'全唐诗/poet.song.72000.json','["覺變則迷，識澄則悟。", "作止因依，生死交互。", "妙矣靈通，混然本素。", "用與性齊，語與默寓。", "三世現前，十方頓赴。", "非知而知，不住而住。", "永言大觀，唯心是務。"]'),
('b104353f-c3d8-4975-8353-585f9e1c66e5','止堂銘','釋守卓','宋','宋诗','song-poetry','','[]','旨哉斯堂，全觀全止。',80,'全唐诗/poet.song.72000.json','["旨哉斯堂，全觀全止。", "是止亦止，應現何已。", "法爾而然，不默則病。", "必爾之歸，淵默生定。", "妙定圓極，心精發光。", "不出戶牖，靈鑒十方。", "既超動靜，無住者存。", "居之而安，左右逢原。"]'),
('aad434b0-7b45-4a8d-acc0-653f37496a92','偈十九首  其一','釋守卓','宋','宋诗','song-poetry','','[]','年來乍住甘露，癡鈍無可作做。',84,'全唐诗/poet.song.72000.json','["年來乍住甘露，癡鈍無可作做。", "剛被王官差排，業緣無能回互。", "祇得逐浪隨波，從教諸方流布。", "門前旋買新鹽，甕裏有些陳醋。", "來者覓茶與茶，大似雖貧而富。", "更問祖師西來，老也得住且住。"]'),
('d6521562-4890-47d5-8432-455fdb660e1e','偈十九首  其二','釋守卓','宋','宋诗','song-poetry','','[]','四維風景寥寥，極目晴空廓落。',64,'全唐诗/poet.song.72000.json','["四維風景寥寥，極目晴空廓落。", "孰爲好醜是非，何用識情卜度。", "石火迸光，清秋一鶚。", "言前得旨已周遮，句後無蹤徒摸索。", "劄著不行，秦時𨍏轢。"]'),
('bdf800d1-f92a-4f77-a5e9-71baa3eb2c11','偈十九首  其三','釋守卓','宋','宋诗','song-poetry','','[]','久雨不晴今日晴，和泥合水要分明。',32,'全唐诗/poet.song.72000.json','["久雨不晴今日晴，和泥合水要分明。", "虛空濕了何妨事，依舊太陽東畔生。"]'),
('9cd4a67a-62ff-4122-a983-d890974d18fb','偈十九首  其四','釋守卓','宋','宋诗','song-poetry','','[]','日出卯，鬧炒炒。',32,'全唐诗/poet.song.72000.json','["日出卯，鬧炒炒。", "於其中，須善巧。", "打麵還他州土麥，唱歌須是帝鄉人。"]'),
('24b79e0a-9afa-48fe-a59f-eeaf199a8da1','偈十九首  其五','釋守卓','宋','宋诗','song-poetry','','[]','的的無來去，明明有舊新。',48,'全唐诗/poet.song.72000.json','["的的無來去，明明有舊新。", "去年今日事，今日去年人。", "脫體全收放，隨流混主賓。", "春光重漏洩，有口不須陳。"]'),
('77dff41f-eaa1-4ed4-ba20-b938a39833d9','偈十九首  其六','釋守卓','宋','宋诗','song-poetry','','[]','步步登高，從空放下。',30,'全唐诗/poet.song.72000.json','["步步登高，從空放下。", "南北東西，曾無縫罅。", "教外別傳，一切話霸。"]'),
('18c974f0-8faa-4a88-b949-5ae05ca08ba1','偈十九首  其七','釋守卓','宋','宋诗','song-poetry','','[]','風非別凉，火是本熱。',20,'全唐诗/poet.song.72000.json','["風非別凉，火是本熱。", "冷坐九年，元來未瞥。"]'),
('bd713225-75fd-4f10-bf3e-6482e9d1a8da','偈十九首  其八','釋守卓','宋','宋诗','song-poetry','','[]','飛金烏，走玉兔，剎那之間成新故。',112,'全唐诗/poet.song.72000.json','["飛金烏，走玉兔，剎那之間成新故。", "一陽復處透全身，露柱開花還峭措。", "炒茅栗，煮山芋，衲僧活計隨時做。", "胡家曲拍自分明，晷運推移何處去。", "堪嗟茫茫塵世人，幾箇暫行休歇路。", "今年不見去年人，多少今人成古墓。", "張三李四醉昏昏，笑殺甘露拄杖子。"]'),
('d2a0e81e-c204-45f2-8749-44bdfbc4f709','偈十九首  其九','釋守卓','宋','宋诗','song-poetry','','[]','勸公一，識取心王萬事畢。',28,'全唐诗/poet.song.72000.json','["勸公一，識取心王萬事畢。", "六塵堆裏拾得來，歷劫元來未曾失。"]'),
('45b98d89-245f-40e8-821c-d545c22d565f','偈十九首  其一○','釋守卓','宋','宋诗','song-poetry','','[]','釋迦掩室，過犯彌天。',30,'全唐诗/poet.song.72000.json','["釋迦掩室，過犯彌天。", "維摩杜詞，自救不了。", "如何如何，口門太小。"]'),
('f79083e2-63f0-4264-b553-a01b28408bd5','偈十九首  其一一','釋守卓','宋','宋诗','song-poetry','','[]','付法傳心，將錯就錯。',40,'全唐诗/poet.song.72000.json','["付法傳心，將錯就錯。", "立雪斷臂，隨邪逐惡。", "本色衲僧，如何評溥。", "達磨大師，露出一膊。"]'),
('02d1a90d-4ed8-44af-a302-662f7b7f5f81','偈十九首  其一二','釋守卓','宋','宋诗','song-poetry','','[]','一雨一晴，巖桂加青。',36,'全唐诗/poet.song.72000.json','["一雨一晴，巖桂加青。", "釋迦骨髓，彌勒眼睛。", "途中無限拕泥者，問渠何日是歸程。"]'),
('edd5f144-5308-4dfb-8f47-2f16e643b27b','偈十九首  其一三','釋守卓','宋','宋诗','song-poetry','','[]','黄河水，出崑崙，要得分明轉見昏。',32,'全唐诗/poet.song.72000.json','["黄河水，出崑崙，要得分明轉見昏。", "若欲迥超無間業，滅却如來正法輪。"]'),
('c0f4ad21-cd68-4975-953b-5c47a9c81adf','偈十九首  其一四','釋守卓','宋','宋诗','song-poetry','','[]','空中呈鳥跡，水上露燈毬。',24,'全唐诗/poet.song.72000.json','["空中呈鳥跡，水上露燈毬。", "要辨渠端的，玉人騎鐵牛。"]'),
('d98fff26-805b-43a2-8298-6993cb35a366','偈十九首  其一五','釋守卓','宋','宋诗','song-poetry','','[]','因行不妨掉臂，求他不妨求己。',44,'全唐诗/poet.song.72000.json','["因行不妨掉臂，求他不妨求己。", "面前山子若存，處處無風浪起。", "一聲鴻雁忽聞時，盡在愁人窠窟裏。"]'),
('0e99cd2d-cf10-4c3d-ba44-8d7cd5d059fe','偈十九首  其一六','釋守卓','宋','宋诗','song-poetry','','[]','孤村黄葉落，深院桂花香。',24,'全唐诗/poet.song.72000.json','["孤村黄葉落，深院桂花香。", "志士惜日短，愁人知夜長。"]'),
('2abb5a22-1d33-4838-b6ad-30e63f10045e','偈十九首  其一七','釋守卓','宋','宋诗','song-poetry','','[]','風從何來，雨從何至。',50,'全唐诗/poet.song.72000.json','["風從何來，雨從何至。", "皮下有血，面上有鼻。", "脫體相呈，全無忌諱。", "明眼衲僧，更須瞥地。", "瞥地如何，且莫瞌睡。"]'),
('337094d9-5b11-4f57-8c32-64d631043607','偈十九首  其一八','釋守卓','宋','宋诗','song-poetry','','[]','落花隨流水，啼鳥在深雲。',48,'全唐诗/poet.song.72000.json','["落花隨流水，啼鳥在深雲。", "莫怪多違背，年高耳目昏。", "豈不見七百甲子老禪翁，對人祇道東門西門南門北門。"]'),
('d360e416-fdf4-4d6f-ab80-9ff1fc1f04c8','偈十九首  其一九','釋守卓','宋','宋诗','song-poetry','','[]','昨朝炒炒鬧，今朝鬧炒炒。',24,'全唐诗/poet.song.72000.json','["昨朝炒炒鬧，今朝鬧炒炒。", "波斯失白㲲，拾得鐵錢鈔。"]'),
('8ede9ef6-70f9-4d34-a5c1-fb9bd15627b9','偈二十四首  其一','釋守卓','宋','宋诗','song-poetry','','[]','心心心，佛佛佛。',50,'全唐诗/poet.song.72000.json','["心心心，佛佛佛。", "心佛佛心，心心佛佛。", "心佛無二，更須知有向上一竅。", "如何是向上一竅，南瞻部州，北鬰單越。"]'),
('eae519be-3b94-4123-b68b-0e60a05c0cf6','偈二十四首  其二','釋守卓','宋','宋诗','song-poetry','','[]','見見須教透頂門，頂門開處寶光分。',44,'全唐诗/poet.song.72000.json','["見見須教透頂門，頂門開處寶光分。", "照徹古今無比況，猶來佛祖是兒孫。", "到頭珠有水，未免線因針。"]'),
('77810ba1-13f1-460a-a27d-0f34e23cc3bd','偈二十四首  其三','釋守卓','宋','宋诗','song-poetry','','[]','真不掩僞，開眼瞌睡。',40,'全唐诗/poet.song.72000.json','["真不掩僞，開眼瞌睡。", "曲不藏直，猶較些子。", "魚目明珠，都盧在汝。", "更擬如何，未敢相許。"]'),
('497c4da1-ebc7-4735-bc53-35d6fe303c26','偈二十四首  其四','釋守卓','宋','宋诗','song-poetry','','[]','人無心合道，困來不覺和衣倒。',76,'全唐诗/poet.song.72000.json','["人無心合道，困來不覺和衣倒。", "一老一不老，法身真箇入荒草。", "了無來，隨分討，糞掃堆頭拾得寶。", "木人石女共歡呼，信手拈來用恰好。", "青山無盡意無窮，何須更覓來時道。"]'),
('2003a18d-662b-4807-a210-fa0f99b8a9d9','偈二十四首  其五','釋守卓','宋','宋诗','song-poetry','','[]','二月桃花紅，三月李花白。',24,'全唐诗/poet.song.72000.json','["二月桃花紅，三月李花白。", "要調滿庭芳，須會十八拍。"]'),
('cbf53656-d136-4449-88d0-55260255c994','偈二十四首  其六','釋守卓','宋','宋诗','song-poetry','','[]','開眼即迷，閉眼即錯。',20,'全唐诗/poet.song.72000.json','["開眼即迷，閉眼即錯。", "古佛巴鼻，何處摸索。"]'),
('5cc2ec67-be96-420f-b979-c5658a1e932f','偈二十四首  其七','釋守卓','宋','宋诗','song-poetry','','[]','會與不會，拈却一對。',25,'全唐诗/poet.song.72000.json','["會與不會，拈却一對。", "直截如何，風不鳴條，雨不破塊。"]'),
('1b4d5cde-90ed-4991-8ae1-45798e7695aa','偈二十四首  其八','釋守卓','宋','宋诗','song-poetry','','[]','欲明生死須窮道，一葉落時天下秋。',32,'全唐诗/poet.song.72000.json','["欲明生死須窮道，一葉落時天下秋。", "不涉去來常變化，歸根得旨但隨流。"]'),
('5d73690c-1e78-44ff-9bf0-633f4820a790','偈二十四首  其九','釋守卓','宋','宋诗','song-poetry','','[]','晴來又雨，雨了又晴。',29,'全唐诗/poet.song.72000.json','["晴來又雨，雨了又晴。", "輝天電閃，震地雷鳴。", "爭奈室中人不聞何。"]'),
('231687c0-f9de-479f-95bf-ccd4d12f3b84','偈二十四首  其一○','釋守卓','宋','宋诗','song-poetry','','[]','古佛真宗，彌滿成現。',27,'全唐诗/poet.song.72000.json','["古佛真宗，彌滿成現。", "明眼衲僧，作麽生辨。", "切忌撞頭磕腦。"]'),
('a2cc1951-8044-448e-b35c-70514428c559','偈二十四首  其一一','釋守卓','宋','宋诗','song-poetry','','[]','糞掃堆頭丈六身，入泥入水出家人。',32,'全唐诗/poet.song.72000.json','["糞掃堆頭丈六身，入泥入水出家人。", "丈夫自有通方眼，認著珍時不是珍。"]'),
('2438e02d-0ff7-4322-b234-70f147fa5537','偈二十四首  其一二','釋守卓','宋','宋诗','song-poetry','','[]','歲時駒過隙，倏忽十月初。',52,'全唐诗/poet.song.72000.json','["歲時駒過隙，倏忽十月初。", "今年寒較早，前日已開爐。", "爐邊向去者，各各護眉鬚。", "分明一路無寒暑，不知何日是歸歟。"]'),
('5cbd002b-2667-43a0-b781-0ba147f1a10e','偈二十四首  其一三','釋守卓','宋','宋诗','song-poetry','','[]','日出心光耀，堂堂更孤峭。',64,'全唐诗/poet.song.72000.json','["日出心光耀，堂堂更孤峭。", "天陰性地昏，風寒早閉門。", "不知天地者，剛道有乾坤。", "欲明還得暗，打破却渾侖。", "爭如回首家鄉路，寒食依前是暮春。"]'),
('f7096412-24b1-4331-8d12-55a34e452037','偈二十四首  其一四','釋守卓','宋','宋诗','song-poetry','','[]','心同虛空界，箇中有買賣。',60,'全唐诗/poet.song.72000.json','["心同虛空界，箇中有買賣。", "示等虛空法，處處皆周匝。", "證得虛空時，全收復是誰。", "無是無非法，一離還一合。", "不因霜雪苦，那辨歲寒心。"]'),
('2e08fefc-69ca-4a1b-84ed-ac635ee899f0','偈二十四首  其一五','釋守卓','宋','宋诗','song-poetry','','[]','雲從龍，風從虎，大地誰言無寸土。',96,'全唐诗/poet.song.72000.json','["雲從龍，風從虎，大地誰言無寸土。", "三陽肇處布新春，明明獨露乾坤祖。", "誰知毗耶老病翁，默爾忘言善談吐。", "不落四句徹三玄，還他一二三四五。", "報爾栴檀林下人，應時納祐還知否。", "收來橫骨暗中抽，放去隨群作水牯。"]'),
('c43cbbac-e4b3-471e-b012-cd1b7e06a13d','偈二十四首  其一六','釋守卓','宋','宋诗','song-poetry','','[]','諸佛不出世，四十九年說。',80,'全唐诗/poet.song.72000.json','["諸佛不出世，四十九年說。", "千江有水千江月，萬里無雲萬里天。", "祖師不西來，少林有妙訣。", "西天此土俱拈却，一種平懷當處親。", "若人識祖佛，當處便超越。", "大盡三十日，小盡二十九。"]'),
('ed75272c-c29e-4b23-b0c9-24081fec2dd2','偈二十四首  其一七','釋守卓','宋','宋诗','song-poetry','','[]','生死即涅槃，涅槃即生死。',132,'全唐诗/poet.song.72000.json','["生死即涅槃，涅槃即生死。", "全迷即全悟，全死即全生。", "魔佛齊平，孰爲非道。", "又須知生死非涅槃，涅槃非生死。", "無生死而不顯涅槃，無涅槃而不度生死。", "法法顯然，塵塵自離。", "到者裏，更須有轉身一路。", "若也轉得，枯木枝頭，別迎春色。", "踢倒鐵圍山，踏翻生死海。", "從教月色和雲白，管取春來草又青。"]'),
('c1e83bf1-8e02-4d2c-a127-1429aae6a320','偈二十四首  其一八','釋守卓','宋','宋诗','song-poetry','','[]','一月普現一切水，一燈能傳百千燈。',32,'全唐诗/poet.song.72000.json','["一月普現一切水，一燈能傳百千燈。", "此時不徹全身句，眨起眉毛已葛藤。"]'),
('153107a2-388d-4d28-8d78-3b316211c6bf','偈二十四首  其一九','釋守卓','宋','宋诗','song-poetry','','[]','大圓鑑中同結社，一微塵裏共安居。',113,'全唐诗/poet.song.72000.json','["大圓鑑中同結社，一微塵裏共安居。", "釋迦彌勒無門入，不到到者真丈夫。", "大丈夫漢，撩著便知來由，不爲分外。", "若更擬議躊躇，何啻雲泥萬里。", "所以道十五日已前點即不到，十五日已後到即不點。", "且道點即是，不點即是。", "長因虎嘯風生處，記得龍吟霧起時。"]'),
('5d2ce7c3-33d7-40ae-aad4-0280c9dc9c84','偈二十四首  其二○','釋守卓','宋','宋诗','song-poetry','','[]','五五二十五，人人超佛祖。',64,'全唐诗/poet.song.72000.json','["五五二十五，人人超佛祖。", "撩著未知機，黄金成糞土。", "諸禪德，莫莽鹵，夷門山朝朝走入。", "新羅占波國裏，賣吉州針。", "相逢醉老婆，尋牛撞著虎。"]'),
('ef49db58-3b3a-4ff2-b8e6-2ea794b3a3f0','偈二十四首  其二一','釋守卓','宋','宋诗','song-poetry','','[]','逢庚則伏，貍奴昨外暍死。',56,'全唐诗/poet.song.72000.json','["逢庚則伏，貍奴昨外暍死。", "遇明則蘇，白牯今朝律活。", "全活全死，全死全活。", "死活兩忘，是箇什麽。", "到這裏，也須是箇漢始得。"]'),
('e4c3bd27-86be-44c6-862f-611368cfb21c','偈二十四首  其二二','釋守卓','宋','宋诗','song-poetry','','[]','長期告畢，法歲云周。',72,'全唐诗/poet.song.72000.json','["長期告畢，法歲云周。", "木人施草，石女行籌。", "衲僧了無交涉，那更頭上安頭。", "橫擔楖栗，笑傲清秋。", "要去即去，得留且留。", "逢人若問長靈老，向道浩浩塵中鬭鐵牛。"]'),
('e45221bb-609d-410f-aba1-419a521f042e','偈二十四首  其二三','釋守卓','宋','宋诗','song-poetry','','[]','過現無三世，星霜有四明。',48,'全唐诗/poet.song.72000.json','["過現無三世，星霜有四明。", "秋殘心似口，冬至眼如眉。", "了了何依住，新新孰變移。", "歲寒同飲啄，冷暖自家知。"]'),
('9eff13bc-a7eb-4571-b8a4-374b9e978198','偈二十四首  其二四','釋守卓','宋','宋诗','song-poetry','','[]','心心心，莫謾尋。',44,'全唐诗/poet.song.72000.json','["心心心，莫謾尋。", "道道道，已蹉過。", "不蹉過，是什麽。", "一機全，步步到。", "木馬已追風，瞎馿倒推磨。"]'),
('b7c4f49c-1ad9-40ac-b899-a3c376f39f53','臨終前一日和雲門曲','釋守卓','宋','宋诗','song-poetry','','[]','衲僧要唱雲門曲，六六從來三十六。',74,'全唐诗/poet.song.72000.json','["衲僧要唱雲門曲，六六從來三十六。", "曹源有箇癡禪人，解道一生數不足。", "數不足，不屬金石與絲竹。", "等閑一拍五音全，直道如弦已曲錄。", "從教歲去年來，依舊山青水綠。"]'),
('e587d50f-6421-4abd-8a33-4ef45ed1e66d','李太白畫歌','饒節','宋','宋诗','song-poetry','','[]','先生之氣蓋天下，當時流輩退百舍。',272,'全唐诗/poet.song.72000.json','["先生之氣蓋天下，當時流輩退百舍。", "醉中咳唾落珠璣，身後聲名滿夷夏。", "青山木拱三百年，今晨乃拜先生畫。", "烏紗之巾白紵袍，岸巾攘臂方出遨。", "神遊八極氣自穩，冰壺玉斗霜風高。", "嗚呼先生泰絕倫，仙風道骨語甚真。", "肅然可望不可親，懸知野鶴非雞羣。", "天寶之初天子逸，先生醉去不肯屈。", "采石江頭明月出，鼓枻酣歌志願畢。", "只今遺像粉墨間，尚有英風爽毛骨。", "宣州長史粉黛工，誰令寫此人中龍。", "細看筆意有俯仰，妙處果在阿堵中。", "人云此畫世莫比，吳侯得之喜不寐。", "意侯所愛豈徒爾，亦惜真才死泥滓。", "先生朽骨如可起，誰爲獵之奉天子。", "作爲文章文聖世，千秋萬古誦盛美。", "再拜先生泪如洗，振衣濯足吾往矣。"]'),
('8634b98d-b475-4c19-b630-7716099e605b','送故人','饒節','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','秋風夜作萬馬聲，草木自有離別情。',240,'全唐诗/poet.song.72000.json','["秋風夜作萬馬聲，草木自有離別情。", "君行胡不卜春夏，况我抱病方竛竮。", "我生不祥憂患并，行李四方影隨形。", "少年之氣追琢盡，胸中獨抱渭與涇。", "世人紛紛水火爭，我欲從之憊不能。", "騎馬時尋故人舍，掀髯抵掌意自傾。", "圖書萬卷相將迎，座無凡兒眼更明。", "惟酒無量與興會，我醉未去君經營。", "不用賜金爲解酲，一月何必一日醒。", "此中萬事氣自寧，勿語世人人不聽。", "君今胡爲忽戒行，使我此計墮杳冥。", "君行瀟湘絕洞庭，沙頭水落鼉夜鳴。", "想君抱恨寐輒驚，起弔湘纍涕泪橫。", "顧我胡爲世網嬰，前行霜露後榛荆。", "誰爲傳之鳳凰翎，與君方駕尋此盟。"]'),
('0b7c791e-c80f-47b0-966c-596cbc5df9c8','送傅仲默登第歸麻姑','饒節','宋','宋诗','song-poetry','','[]','謝安中年不堪別，况我與子本末同。',160,'全唐诗/poet.song.72000.json','["謝安中年不堪別，况我與子本末同。", "臨川古郡著名數，麻姑且在邦域中。", "與君同方復同術，十年共度虀鹽日。", "一身爛漫天地中，萬里風霜今白髮。", "南山之封木拱矣，此身萬事相終始。", "何知遲暮猶羈旅，夜語對床輒三起。", "君今先著祖生鞭，我窮未辦買山錢。", "君行啟我方寸亂，抱琴長歌聲徹天。", "西風蕭蕭木脫葉，表裏家山落眉睫。", "爲語淮南大小山，雖在侯門不彈鋏。"]'),
('34e121bb-f27e-4c6d-ac10-9247d962a410','送善權歸豫章','饒節','宋','宋诗','song-poetry','','[]','北斗以南好風土，西山爽氣吞吳楚。',160,'全唐诗/poet.song.72000.json','["北斗以南好風土，西山爽氣吞吳楚。", "前輩風流固超絕，後生法像仍奇古。", "道人久學祖師禪，敗裙破衲今幾年。", "胸中秀氣磨未盡，時出新詩皆可傳。", "都城鼎鼎冠劍偉，井掃權門日中市。", "道人香火辦寂莫，有脚不踏公侯地。", "古來賢俊能幾何，只今零落亦已多。", "一見道人氣象是，蒲團棐几生春和。", "我思伸眉向林莽，未暇優游取卿相。", "扁舟今日與君別，明朝夢落江湖上。"]'),
('d3b050eb-5c72-40f7-8d4e-6d5f4ed10982','石魚行贈靈壁張氏','饒節','宋','宋诗','song-poetry','','[]','磬石山中石無主，百里厚坤不承土。',144,'全唐诗/poet.song.72000.json','["磬石山中石無主，百里厚坤不承土。", "土人出石如出金，闕地及泉隧而取。", "重重徹之如徹席，凡材頑狠邱山積。", "中藏一板金王精，定是陶鎔鬼神力。", "黄鍾之律生於黍，近代縱橫不如古。", "天生此材豈苟然，伐而用之百獸舞。", "師襄入海工不精，且製嘉魚大小鳴。", "大爲王鮪施僧飯，小爲魴鰥依石屏。", "君家二尾儻遺我，要喚兒曹坐睡醒。"]'),
('288118a6-0a43-4114-a833-d25abb8e4cfe','向居卿所藏靈壁石歌','饒節','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','靈壁之石妙天下，奇姿異質窮變化。',195,'全唐诗/poet.song.72000.json','["靈壁之石妙天下，奇姿異質窮變化。", "時時好事獲寸尺，谷量牛馬未當價。", "耐官丞相三代孫，風流似是典刑存。", "心胸本無紈袴氣，詩書漸洗膏粱昏。", "邇來得石不盈尺，依稀尚带莓苔迹。", "氣象中含萬仞懸，秀潤仍分千里碧。", "大江之南千萬山，終日思歸行路難。", "坐中一見此真骨，心折當年雨後天。", "君不見黄金白璧驕侈本，大官厚祿方安穩。", "少年趣駕迅如電，我欲追之墮車蹇。", "年來老大計轉拙，一丘一壑興不淺。", "儻君他日棄前魚，南窗坐對廬山遠。"]'),
('85c54974-61c9-4ab0-b896-fbb1c3dedd36','阿智歌','饒節','宋','宋诗','song-poetry','','[]','呂卿諸子森如蝟，不作世間兒女氣。',146,'全唐诗/poet.song.72000.json','["呂卿諸子森如蝟，不作世間兒女氣。", "封胡羯末自行列，麟鳳龜龍各異致。", "小兒阿智甫七齡，衮衮似欲無諸兄。", "疏眉秀目澹玉雪，覆肝立壁開天庭。", "自從諸兄授孝經，淋漓筆墨有典刑。", "客來推席儼在庭，舉頭揖客客爲驚。", "吾知呂卿大源委，黄河崑崙千萬里。", "政令凡兒出其中，不扶而直麻生蓬。", "况如此雛落落自奇偉，出門汗血當追風。"]'),
('2020725c-beeb-479f-9f9a-04dcf4f9f3cb','寄夏思道惠示縑帛','饒節','宋','宋诗','song-poetry','','[]','憶昔南方木葉下，祝融逗留不退舍。',144,'全唐诗/poet.song.72000.json','["憶昔南方木葉下，祝融逗留不退舍。", "閭閻未簡卒歲材，明月滿門自宜夜。", "而今身在天中央，日月寒暑遵故常。", "西風今日我爲政，冥冥塵沙何可當。", "浮雲倚勢不解事，濃陰數日釀秋思。", "卧病但作仲卿泣，載酒誰問子雲字。", "故人千里知我寒，書來遺我帛數端。", "揀絲織作經緯稱，長細廣幅尺度寬。", "染人暴練勿設色，衣被皎皎識君德。"]'),
('0349112c-9c08-4960-87d1-134acf722288','送梅郎一首','饒節','宋','宋诗','song-poetry','','[]','梅郎可愛如蜀柳，風流似是子真後。',160,'全唐诗/poet.song.72000.json','["梅郎可愛如蜀柳，風流似是子真後。", "抱器來賓太學窮，五年自袖采蘭手。", "來時落雁摇虛弓，汗血長鳴西北風。", "自誓壞韓復蠹魏，可憐一無咫尺功。", "我亦數奇困竿累，玉山冰川失眼底。", "永嘉堂上聞阿連，墮食正冠爲君起。", "君今製衣作行具，何以贈之白鷺羽。", "殷勤持□重似人，漠漠深藏飽魚蠹。", "船頭逢逢奏曉鼓，卷簾卧看春江雨。", "到家春溫雁且北，寄聲布帆無恙不。"]'),
('e622b4b7-bffb-475b-9d50-4b26624905df','鄰居遺湯沐浴','饒節','宋','宋诗','song-poetry','','[]','都城甘水嗇於酒，擔頭取飽得滿缶。',112,'全唐诗/poet.song.72000.json','["都城甘水嗇於酒，擔頭取飽得滿缶。", "每憶江湖萬松底，夜半酒醒挽石斗。", "如今長卿不滿喉，豈有溫泉濯汗流。", "岑岑背若負芒刺，每向一飯懷千憂。", "君家有井金作欄，轆轤可取不可殫。", "大奴分遺足一斛，洗我塵垢生羽翰。", "人生生理易與耳，輟洗爲君起長歎。"]'),
('ace883b3-4bad-4519-bd61-f3f622377188','趙元達婦孕不育後數日其猶子生一女子二子皆有戚戚之色戲作此詩開之','饒節','宋','宋诗','song-poetry','','[]','十年不見陳驚座，二子相逢心亦可。',176,'全唐诗/poet.song.72000.json','["十年不見陳驚座，二子相逢心亦可。", "高帝子孫果隆準，杜陵先生豈欺我。", "甘陵夫子孕不育，世無元化操五毒。", "乳醫袖手輒寤生，不藥而喜神所福。", "君家阿濟頤未髯，頗恨生子不生男。", "人間久乏古烈女，世上多歎吾兒凡。", "應當有子問賢否，弄璋弄瓦詩人口。", "木蘭買馬替爺征，班昭嗣兄成漢表。", "人生得此二子者，安用癡兒鬧昏曉。", "况君各自富春秋，有女如玉方好逑。", "必欲商瞿有男子，殷勤更問東家丘。"]'),
('2b9bf42f-81e4-4767-b45f-58d935b8249d','贈陳侯一首','饒節','宋','宋诗','song-poetry','','[]','古人已朽不可作，長安年少多嶽嶽。',200,'全唐诗/poet.song.72000.json','["古人已朽不可作，長安年少多嶽嶽。", "太官五斗僅代耕，舒緩養高簡然諾。", "陳侯氣穩天機精，心胸開霽脫檢繩。", "只今冠佩奉朝請，折節重士身自輕。", "主人斗酒相逢迎，金尊玉槃紅燭明。", "黄花開徹秋未了，殘月挂簷霜氣清。", "氣吞百吏不足數，滑稽巧中一座傾。", "座客未用喜且愕，陳侯吏事復不惡。", "簿書獄訟談笑了，盜賊骨驚吏膽落。", "至今魯山駕車處，會使齊兒畏朱博。", "方今天子坐明堂，指麾夷狄如驅羊。", "安得吏師如侯者，上應列宿布四方，政治豈但幾成康。"]'),
('b6f39392-1e56-403e-b70b-d62bb4b24503','立之作詩譏僕沉浮於酒次韵答之','饒節','宋','宋诗','song-poetry','','[]','頹俗不可挽，我思陳孟公。',144,'全唐诗/poet.song.72000.json','["頹俗不可挽，我思陳孟公。", "胸中一噫氣，浩蕩滄海東。", "初余亦拙謀，墮身尺度中。", "昔爲吾家駒，今爲客子蓬。", "人生百年耳，過鳥欻無蹤。", "何至自矛盾，身與衆敵逢。", "仲尼固玄聖，道大自不容。", "落落少年場，誰復識呂蒙。", "古今一丘貉，同赴三尺封。", "乃知常滿尊，慰藉吾人窮。", "君詩苦相厄，欲抗輒喪雄。", "但恐百錢債，負我葛陂龍。"]'),
('4087782d-dcf5-40f9-b7fc-f9142cc53b7f','送彭淵才如北都','饒節','宋','宋诗','song-poetry','','[]','我學如水馬，盡日忙不進。',180,'全唐诗/poet.song.72000.json','["我學如水馬，盡日忙不進。", "結交有神奇，所得盡豪俊。", "十年困三舍，萬事到兩鬢。", "風流半零落，吾道或拘窘。", "彭侯南方來，超妙有遠韵。", "落落澗壑姿，倒屣解吾慍。", "胸中幾年讀，正朔謹堯舜。", "盤盂百家伎，鉤致得幽藴。", "夜半一商略，氣與山嶽峻。", "方洋及衛霍，似是老行陣。", "崢嶸濟時術，百未一見信。", "自言窮達機，默與寒暑運。", "功名蓋偶然，未暇以身殉。", "偉哉君子勇，一語破幽憤。", "何時燈火底，懷抱爲吾盡。"]'),
('acc84a1e-1a73-4ebe-b514-faf44af1d944','賦王立之家四梅','饒節','宋','宋诗','song-poetry','','[]','化工轡六龍，風雷共推軌。',216,'全唐诗/poet.song.72000.json','["化工轡六龍，風雷共推軌。", "談笑却冰雪，咄嗟辦桃李。", "紛紛西園英，轉眄即填委。", "獨餘四種梅，冰玉自標致。", "豈爭滕薛長，未與管晏比。", "微風挽寒條，草木競披靡。", "蠟梅異天質，芳香輩蘭芷。", "多葉美無度，勝韵洗貪鄙。", "紅梅拂曉粧，深淺自有體。", "單白亦閑淡，冷艷照流水。", "初如王謝郎，雍容各簪履。", "出處豈皆同，一一竟可喜。", "此花固不凡，俗眼自多瞇。", "栽培或一遇，得此輒遺彼。", "君家獨兼有，班壓萬紅紫。", "况當頓有前，朝暾媚窗几。", "我無筆五色，爲此了衆美。", "安得九轉丹，暫起來陽史。"]'),
('e8852495-d061-4e44-be2c-e00be9d6fb55','春日飲王立之家同賦三頭牡丹依次定十韵節得牡字','饒節','宋','宋诗','song-poetry','','[]','異時王公門，使車駕四牡。',120,'全唐诗/poet.song.72000.json','["異時王公門，使車駕四牡。", "殊方仰吾父，天子尊伯舅。", "舒遲入樞府，易若屈伸肘。", "風流未疏缺，日月競奔走。", "諸孫以文嗣，文字宗科斗。", "英華被草木，美成豈不久。", "宜哉此花瑞，鼎立世無有。", "綿力爲君賦，半夜饑腸吼。", "尺寸窘吾步，豈復到淵藪。", "翻然欲投筆，大恐惠文糾。"]'),
('861f07f3-06f7-422e-8d13-afcc718a42f8','士大夫湛於不義雖窮極富貴君子過之弗顧而况女子失身於委巷容笑之賤亦豈能自拔哉吾友人賦歎息行有謂而作諸人既屬和僕亦擬古樂府爲辭傷之於其末開之以正是亦詩人之志也','饒節','宋','宋诗','song-poetry','','[]','歎息復歎息，丹砂爲土玉爲石。',150,'全唐诗/poet.song.72000.json','["歎息復歎息，丹砂爲土玉爲石。", "誰家女兒妙無敵，日日當窗泪霑舄。", "問之何思復何憶，深顰欲語語不得。", "回身抱琴不回面，清商自寫昭君怨。", "朔風蕭蕭霜月懸，萬里胡沙鳴一雁。", "此聲此意太分明，猶恐君侯未會情。", "從頭却欲爲君說，恐君斷腸君勿聽。", "黄鶴一去已千里，雉子高飛亦能幾。", "人生長短要自裁，嗟爾此身今已矣，刺刺促促徒爲爾。"]'),
('fa26ae3e-162d-47b3-b2fa-7447f5d12eb9','次韵劉無言遊法雲寺','饒節','宋','宋诗','song-poetry','','[]','磨蟻迭左右，鐵炭互俯仰。',180,'全唐诗/poet.song.72000.json','["磨蟻迭左右，鐵炭互俯仰。", "歲月如牧馬，快驟脫羈鞅。", "方希草玄雄，未羨畫眉敞。", "劉侯啟予者，險韵寫勝賞。", "讀之令人醒，居然見圖像。", "我昔曾此遊，僧梵薦肸蠁。", "撞鐘鳴木鯉，破我顛倒想。", "百年能幾許，萬事苦鞅掌。", "喪身聲利場，齒角伐犀象。", "前輩曉雲散，後生春水長。", "君看門外轍，盛氣日來往。", "道人初不省，禪寂異到壤。", "乃知雨花地，可以透迷網。", "君侯此嘉集，塵跡已相盪。", "援琴寫我歎，中夜發哀響。"]'),
('2b8c8456-f706-42e4-ab32-99c961e099f9','爲謝無逸賦陳氏貫時軒','饒節','宋','宋诗','song-poetry','','[]','西園拱羣木，嚴霜損天和。',132,'全唐诗/poet.song.72000.json','["西園拱羣木，嚴霜損天和。", "豈不惜嘉陰，奈此風雨何。", "青青繄此君，凡材不同科。", "君知不同科，何必葉與柯。", "試看一尺根，節已倍身多。", "故令卷籜中，高韵不可摩。", "陳侯定可人，厚禮爲君羅。", "視此種竹心，知君減悲歌。", "吾徒涉世疏，投足得詆訶。", "何如雪月際，對君自婆娑。", "但無我履聲，與子相經過。"]'),
('37a0fe87-f3a2-4e1d-bc6f-68da94240154','次韵李二','饒節','宋','宋诗','song-poetry','','[]','道散士不守，君子利爲上。',144,'全唐诗/poet.song.72000.json','["道散士不守，君子利爲上。", "交遊固竇灌，父子亦歆向。", "繄我二三友，日月共照臨。", "殊鄉不殊習，異族豈異心。", "吾徒拙身謀，要是滄海客。", "大材費伐剪，古樂難考擊。", "相逢聊解顔，把酒聽軟語。", "斷水洗垢病，戛玉開未寤。", "男兒生墮地，脚跡付九州。", "不知誰主盟，會此車與舟。", "願畢已醉杯，竟比難得歡。", "明朝黄子別，離恨已闌干。"]'),
('e3292503-3e62-40ba-896f-dd52e586020d','次韵呂由義見贈之什兼簡若谷居仁','饒節','宋','宋诗','song-poetry','','[]','行年本數奇，閱世復癡絕。',144,'全唐诗/poet.song.72000.json','["行年本數奇，閱世復癡絕。", "巉然寒餓表，但未朋友缺。", "晚得二三子，楚楚著行列。", "家學有師法，保身盡明哲。", "堂皇建鐘磬，戶牖照玉雪。", "白晳采蘭手，未負如意鐵。", "由來石中璞，不在苦分別。", "當時偶一見，頓使我心悅。", "道喪古人遠，君子或降節。", "狐裘儻羔袖，豈待跖與桀。", "若人苟相久，可以輔衰拙。", "歡喜奏微吟，聊嗣登歌闋。"]'),
('9004c420-1701-43d3-adc3-65b39f321e45','次韵劉時可劉將赴宣州幕','饒節','宋','宋诗','song-poetry','','[]','我客汴之濱，夢寐大刀頭。',120,'全唐诗/poet.song.72000.json','["我客汴之濱，夢寐大刀頭。", "幸逢劉伯倫，衣冠少其流。", "胡床白羽扇，語穩氣不浮。", "異時果下馬，彷彿遍九州。", "每思張翰鱸，爲登王粲樓。", "食貧節益苦，異哉居拙謀。", "宣州雖多賢，祿仕恐未優。", "長女嫁及時，大兒婚可求。", "長才不自獻，澹與衆人儔。", "君其吏隠歟，吾亦滄海遊。"]'),
('c285edda-034c-4f61-97e5-f02280c7ca80','次韵謝公定時夏均父招諸客泛舟遊百花洲','饒節','宋','宋诗','song-poetry','','[]','好事屢載酒，扁舟每乘興。',156,'全唐诗/poet.song.72000.json','["好事屢載酒，扁舟每乘興。", "况當秋氣清，開我心若鏡。", "風漪蹙寒綠，日幹下脩影。", "却從蒼翠中，羨彼各飛泳。", "翱翔數仞翼，白小一寸命。", "微物有至樂，此理須自領。", "君侯靜無譁，敢以一言請。", "人生百年爾，飛電作光景。", "試看楹間懸，俯仰歲月永。", "堂堂寇萊公，祀事薦時餠。", "吾徒豈不老，啖蔗入佳境。", "况茲詩酒習，已自破清凈。", "聊須明月來，褰裳踏歸艇。"]'),
('1b7d78fc-0b9c-4ade-817e-5bdb4e345b33','灌蘭一首','饒節','宋','宋诗','song-poetry','','[]','往作蘭溪游，步屧出林麓。',168,'全唐诗/poet.song.72000.json','["往作蘭溪游，步屧出林麓。", "溪頭小雨竟，溪水澹文縠。", "嬋嫣幾叢秀，臨流自結束。", "曲折訪叢底，初不露芬馥。", "歸休行結佩，薄采未盈匊。", "時遵微徑間，幽然感清淑。", "年來蠶自縛，投迹先擬足。", "不意淟涊中，見此二孤竹。", "威威耐寒苦，繹繹輩杞菊。", "似是溪頭裔，相逢慰煩促。", "一日不見之，鄙吝生眉目。", "故將應書手，抱甕助長毓。", "孤根著土深，稍稍樹支族。", "看渠吐胸中，一洗桃李俗。"]'),
('daccb7a7-145e-4dc6-a030-484c716aba11','約方時敏楊信祖二子同過王立之觀立之所集前輩詩文各以姓賦詩','饒節','宋','宋诗','song-poetry','','[]','秋容散古原，秋聲滿寒條。',168,'全唐诗/poet.song.72000.json','["秋容散古原，秋聲滿寒條。", "幽人開曉夢，喔喔雞戒朝。", "騎馬西南隅，不知道里遥。", "我行將何之，我友昔見邀。", "斯人非世人，與世不相聊。", "幾年賦歸歟，塞耳樹上瓢。", "誰知翰墨功，百倍巴蜀饒。", "方楊妙天質，兩玉不易招。", "粟馬來會盟，此義久寂寥。", "主人喜開尊，盃殽初刻彫。", "及乎啟丹臺，座上皆聞韶。", "委積山海奇，浩蕩江漢朝。", "此囿無郊封，爛漫各蒭蕘。", "歸來蒲深望，老大猶虛驕。"]'),
('adf78f08-638e-4b82-9e95-7108139b8849','蓘室詩王立之爲宗子求','饒節','宋','宋诗','song-poetry','','[]','布穀作五更，鷦鷯亦司辰。',216,'全唐诗/poet.song.72000.json','["布穀作五更，鷦鷯亦司辰。", "田師遽束縕，請火起近鄰。", "耕耘豈辭勞，常虞秋計貧。", "匽薄壟畝間，努力不自珍。", "秋風落高原，罷亞千頃雲。", "公子豈知田，得師自農人。", "歸來坐虛室，却掃富貴昏。", "架插河間書，門引霍三賓。", "耡耰翰墨場，寒窗澹爐熏。", "六籍聖人師，百家素王臣。", "骫骳離騷經，妙語泣鬼神。", "靈文陋詛楚，高論追過秦。", "泛覽四庫餘，瓦礫半珠蠙。", "遊心領其要，開卷得其人。", "門前風作埃，肥馬走搢紳。", "豈知歌鐘地，辛苦事斯文。", "懶夫江海士，履聲遠王門。", "未暇到此室，歸歟老斲輪。"]'),
('ebc9e132-47ac-4b6e-8863-c4b7112149f0','秋蚊行','饒節','宋','宋诗','song-poetry','','[]','秋蚊撲撲啄作花，秋江噴薄卷舊沙。',64,'全唐诗/poet.song.72000.json','["秋蚊撲撲啄作花，秋江噴薄卷舊沙。", "魚肥兔賤年穀熟，田家八月生有涯。", "羣翁坐社兒擊鼓，酒一載行翁起舞。", "但得催科了眼前，兒郎各自能辛苦。"]'),
('2791be4c-89f0-49c6-a679-b084a23fff64','戲汪信民教授','饒節','宋','宋诗','song-poetry','','[]','汪侯思家每不寐，顛倒裳衣中夜起。',64,'全唐诗/poet.song.72000.json','["汪侯思家每不寐，顛倒裳衣中夜起。", "豈惟蓐食窘僮奴，頗復打門攪鄰里。", "凉風蕭蕭月在庭，老夫醉著呼不醒。", "山僮奔走奉嘉客，銅瓶汲井天未明。"]'),
('b82f8038-ef71-4601-8b49-b96932141b5b','歸來怨','饒節','宋','宋诗','song-poetry','','[]','瓊株玉樹非凡根，幽蘭紫芝種不繁。',64,'全唐诗/poet.song.72000.json','["瓊株玉樹非凡根，幽蘭紫芝種不繁。", "誰家妙質傾春色，失身逋蕩依荆棘。", "流蘇暗繞雲母屏，棲魂不穩夜魘驚。", "歸來泣下繡時室，漫漫此生身事畢。"]'),
('f7fb47d9-dbca-4863-a102-4db506fceead','得交行贈王立之','饒節','宋','宋诗','song-poetry','','[]','世上紛紛走車轍，交情回互作冷熱。',64,'全唐诗/poet.song.72000.json','["世上紛紛走車轍，交情回互作冷熱。", "搢紳豈無酈寄賣，山林謾有嵇康絕。", "我窮四方但餬口，一丘一壑志未了。", "得交天下能幾人，直道如君可偕老。"]'),
('97a65cc6-9ec6-4246-be72-65fd491b3103','雨小霽登南寺閣','饒節','宋','宋诗','song-poetry','','[]','登樓望四垂，縮縮雨小休。',48,'全唐诗/poet.song.72000.json','["登樓望四垂，縮縮雨小休。", "老木藤蔓活，古殿金碧流。", "浮雲捲豈盡，落日不可留。", "無人相與語，鸜鵒謾啾啾。"]'),
('aeb4ef17-b6ab-4914-90b2-c4656fa9b452','上范謙叔左丞求退','饒節','宋','宋诗','song-poetry','','[]','老驥伏櫪志千里，烈士暮年心不已。',112,'全唐诗/poet.song.72000.json','["老驥伏櫪志千里，烈士暮年心不已。", "不用悲歌擊唾壺，尚挾平戎獻天子。", "書成未上忽自悟，便逐道人林莽去。", "年來著脚古道場，疾病魔人無屏處。", "不遇我公如古人，零落離披作風絮。", "我公德量大如海，太平天子待真宰。", "乞身莫待我公行，早向千峰萬峰外。"]'),
('9b79e9e2-5885-41e1-a7c4-155acf43e2c8','賦劉仲高高齋詩','饒節','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','先生言語妙天下，向來太學傳芬芳。',232,'全唐诗/poet.song.72000.json','["先生言語妙天下，向來太學傳芬芳。", "當時品目入前輩，後生籍籍窺餘光。", "立談一見便相可，交無新舊合則章。", "別來幾何歲月忙，我已三變變滄浪。", "子才如許猶綠裳，宜參公卿升廟堂，何爲高齋尚翱翔。", "懸知公意非自高，自高自聖渠作狂。", "泰山北斗不自贊，瓊株玉樹絕否臧。", "用則伊周冠百王，直道而行氣益昌。", "不用兩龔或退藏，直道而去括智囊。", "用與不用俱徜徉，使婦無褌非吉祥。", "世人言高不著本，但欲困苦鄰饑尪。", "不知舒卷重在我，尊爲帝師初未妨。", "先生年來力學道，等觀窮達如炎凉。", "屈伸有命不足論，要保胸中百鍊剛。"]'),
('e5aa6ffe-16c1-47bd-9d44-408377caeb87','永處庵詩爲蔡仲志刑曹作','饒節','宋','宋诗','song-poetry','','[]','刑曹仕宦如客寄，朱墨如山無况味。',96,'全唐诗/poet.song.72000.json','["刑曹仕宦如客寄，朱墨如山無况味。", "平生燈火讀書心，便與衲僧同器類。", "自從供職江上郡，一月常勤五七問。", "向來書至乞庵名，永處那伽表嘉遁。", "世間萬事不挂眼，蒲團不動跏趺穩。", "客至清談真老禪，數枝霜竹伴幽韵。"]'),
('93404295-e7af-4ddd-b555-0b5f8dd929ff','送莊季裕宣教','饒節','宋','宋诗','song-poetry','','[]','莊侯目如巖下電，墮泪碑傍始相見。',64,'全唐诗/poet.song.72000.json','["莊侯目如巖下電，墮泪碑傍始相見。", "松間經行倚松語，袖有普賢真行願。", "春風昨夜忽言別，楚兒恰恰耕殘雪。", "野人無以贈君行，山杏溪桃爲君說。"]'),
('3fbfa8d2-d997-419e-9ddc-d6bf12cd068a','送趙廉訪','饒節','宋','宋诗','song-poetry','','[]','飛來之峰可圖寫，畫工摇筆不敢下。',192,'全唐诗/poet.song.72000.json','["飛來之峰可圖寫，畫工摇筆不敢下。", "玲瓏八面尚能摩，萬古冷泉那可畫。", "趙公胸中有涇渭，愛山自得山水意。", "向來與客到峰前，亭上酌泉賞泉味。", "我客峰邊一蔀室，關門無事輒終日。", "公來剝啄自敲門，蹔解跏趺爲公出。", "池上烟光初過雨，巖花膠轕開無數。", "曳杖惟愁猿狖驚，笑談復恐蛟龍怒。", "聞道公歸朝玉京，王事不敢寬作程。", "想公拜舞升天廷，雍容奏議詳而明。", "知公不獨稱安寧，疏民利害通民情。", "吾君憂民精且誠，願公中和輔太平。"]'),
('d530deae-9b6f-44d7-8625-dc7e130a339f','韓升之主簿惠示襄陽雜咏詩淳深高古吟諷不置輒用最後書懷贈彥履韵以釋其意','饒節','宋','宋诗','song-poetry','','[]','刮磨習氣如洗爵，惟餘好古情未薄。',96,'全唐诗/poet.song.72000.json','["刮磨習氣如洗爵，惟餘好古情未薄。", "向來詩軸入松門，便對屠門先大嚼。", "吾儕事業如石田，筆墨魔人妨夜眠。", "如公萬卷瘖不吐，使者旁午誰見憐。", "方今神武拓疆土，超擢賢才固其所。", "莫歎簿書官祿微，黄鐘大呂生一黍。"]'),
('9b66fd8e-5030-461b-ae9a-bce2a3d7d420','張執權主簿同二知縣大夫入山作詩併以見贈亦次其韵','饒節','宋','宋诗','song-poetry','','[]','我不學支公畜馬作戲劇，道人不韵亦成癖。',134,'全唐诗/poet.song.72000.json','["我不學支公畜馬作戲劇，道人不韵亦成癖。", "又不學雲巖常說老婆禪，苦道熾然說牆壁。", "歸來挈杖訪飲虹，携詩過我三士同。", "我喜坐之鶻壁峰，下視凜凜十八公。", "諸人胸中何所有，文字萬卷皆科斗。", "平生筆端自有口，簿書透處時一吼。", "白面王孫金作鞭，憐渠政遭富貴纏。", "今朝此樂戒勿傳，一笑蚊蝱空過前。"]'),
('dc0b1966-880c-41eb-9501-d1ee55bda080','青原臺詩','饒節','宋','宋诗','song-poetry','','["\u6ed5\u738b\u9601"]','五馬胸中足丘壑，駐車决遣有餘樂。',128,'全唐诗/poet.song.72000.json','["五馬胸中足丘壑，駐車决遣有餘樂。", "似言新廣青原臺，不減滕王舊江閣。", "滕王閣下當年路，靜中懷抱時來去。", "聞說青原比像間，表裏江山便知處。", "使車時此携佳賓，與人同樂不同羣。", "倚欄自得新詩句，矯首長懷古道人。", "青原親見曹溪祖，渠有兒孫住山斧。", "問公何處見青原，杳杳飛鴻掠雲去。"]'),
('d98b95d8-1bff-426c-8eb1-550ffec6af1e','贈道士張謙中','饒節','宋','宋诗','song-poetry','','[]','道人髭鬚似民部，平生篆隸心獨苦。',128,'全唐诗/poet.song.72000.json','["道人髭鬚似民部，平生篆隸心獨苦。", "世間筆墨一點無，駸駸氣象追千古。", "道人得師在何許，秦漢鼎彝周石鼓。", "若嶧山碑若詛楚，二李而下初不數。", "異時心醉不窺園，依繩作直規作圓。", "一朝妙解古人意，脫落尺度誠其天。", "嗟君絕藝世無敵，勿示時流渠未識。", "我亦當年好古人，推席爲君三歎息。"]'),
('04c38131-4e21-4d73-bbf0-efeba7e8db26','英遊閣詩','饒節','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖氣欲吞吳楚，山作重圍如捍虜。',195,'全唐诗/poet.song.72000.json','["西湖氣欲吞吳楚，山作重圍如捍虜。", "回環樓閣駭魚龍，挺拔浮圖逼雲雨。", "西湖英遊天下傳，湖光山色當圭田。", "何須西土方爲浄，不待吳門自是仙。", "雪花飛時妙無價，梅影橫斜端可畫。", "荷氣薰人六月風，月華徹底三秋夜。", "陰容霽色風且雨，曉光暮碧寒代暑。", "閣中氣象頃刻移，詩人不是無心賦。", "竹閣使君遺跡空，草堂居士但聞風。", "百年光景電劃水，湖山無限生有窮。", "愛君長才猶袖手，豈宜苦爲湖山久。", "君不見向來閣上舊遊人，富貴功名古無有。"]'),
('6b56f8e0-5716-4b42-9e06-78cb37df33a5','爲卿曇輔作一枝庵詩','饒節','宋','宋诗','song-poetry','','[]','百年七萬二千飯，檢校勞生豈無限。',128,'全唐诗/poet.song.72000.json','["百年七萬二千飯，檢校勞生豈無限。", "巍巍孰是真丈夫，應作已作所作辦。", "不信窮通手翻覆，自窮自通均不足。", "窮思大厦千萬間，通或胡椒八百斛。", "道人不與世俗俱，一枝自占巢有餘。", "有時放杖據高梧，睥睨三界如蘧廬。", "春風數日到梅萼，吟遶寒香雪欲作。", "歸來趺坐尼師壇，柏子烟消泉一勺。"]'),
('f4ff6106-2981-4594-8acc-0c2ddd84aa4a','止止堂詩送仁禪者徧參','饒節','宋','宋诗','song-poetry','','[]','止止堂中一禪客，五尺枯藤藏未得。',83,'全唐诗/poet.song.72000.json','["止止堂中一禪客，五尺枯藤藏未得。", "平生心膽闖古人，今復江南又江北。", "昨夜霜風號古木，玄猿啼寒星斗黑。", "傍家行脚有底難，獨師大去吳王國。", "君不見季子敝盡黑貂裘，歸來印佩六國侯。"]'),
('b0abe625-26b5-471a-a5c9-ed84df37a918','送慧林化士','饒節','宋','宋诗','song-poetry','','[]','王舍城中車馬塵，霏霏似我澗底雲。',128,'全唐诗/poet.song.72000.json','["王舍城中車馬塵，霏霏似我澗底雲。", "此塵可貴不可賤，中著功名富貴人。", "上人衣带雲霞色，隨例塵中歸未得。", "祇園爲有老作家，鬧市叢中自禪寂。", "向來禪律相錯居，空庭月作五日墟。", "市聲浩浩如灘瀨，誰信禪房靜有餘。", "道人要是白雲侶，紅塵不是安身處。", "未能隨我便那伽，早入千峰萬峰去。"]'),
('990fc9ce-2aa0-4c5b-8556-77a93eb91913','送不愚兄香嚴行','饒節','宋','宋诗','song-poetry','','[]','君不見香嚴之山天下望，何必楞伽稱海上。',195,'全唐诗/poet.song.72000.json','["君不見香嚴之山天下望，何必楞伽稱海上。", "龍湫直下一萬尺，鶻崖突起三千丈。", "借問何人出其中，前有國師後閑公。", "中間有人騎乳虎，大雄敬樹真卧龍。", "山中壯氣今重振，堂上老人提舊印。", "晶明如住廣寒深，淵泉自吸滄溟盡。", "兄今三十未爲老，名利波濤拔身早。", "向來自裂子夏冠，翻然便剗天然草。", "如兄勇銳世莫比，誰與同生亦同死。", "只今文采尚未章，人道香嚴有真子。", "隋河渾渾日夜流，兄今倚柁到南州。", "南州水潔草如染，自在溈山水牯牛。"]'),
('30e02a25-4192-484e-b784-81064f7e5fff','鈍庵詩爲印長老作','饒節','宋','宋诗','song-poetry','','[]','姑蘇昔是吳王國，表裏湖山本充塞。',128,'全唐诗/poet.song.72000.json','["姑蘇昔是吳王國，表裏湖山本充塞。", "吳王亡後臺觀空，只有湖山亡不得。", "齋錢吳越又富足，前身端受靈山囑。", "平生佛事滿東南，上下君民總純熟。", "阿師累世同此會，外家更是東南最。", "晚年彷彿傳雙林，鄉里推高無與對。", "阿師四海老行脚，偶向南陽露頭角。", "他年欲識癡鈍人，髮長衲敝人誰覺。"]'),
('6629e2d2-3525-41bd-bd59-5e3ca4140f48','寄趙季成鈐轄','饒節','宋','宋诗','song-poetry','','[]','器之高誼已下世，安當我友埋金沙。',288,'全唐诗/poet.song.72000.json','["器之高誼已下世，安當我友埋金沙。", "倚松卧病無一錢，俗醫如山闖利多。", "天寒歲暮山谷裏，二老不作如我何。", "謂天蓋高不無意，間生賢者爲帝裔。", "不容聲色眩耳目，但許詩書養梗柢。", "少年所學無不有，精研往往窮淵藪。", "不知用心能幾何，妙悟自然絕師友。", "德成而上藝爲下，此言端爲中流者。", "須知豪傑蓋不然，以德養藝斯又全。", "若分上下爲優劣，千金安得稱神仙。", "德爲本質藝其飾，表裏相資乃我德。", "欲知公子志甚深，已著千金追舊跡。", "世人有藝初無德，爲驕爲傲爲殘賊。", "殺人取財不知懼，猶誇庸妄肆誕惑。", "須知公子本無我，一切有求無不可。", "平生高見隘古人，焚棄經方見何左。", "老僧年來學禹步，跰𨇤鑒井不能去。", "還丹一粒能幾何，從此游山不知處。"]'),
('1eeda2f4-f484-4515-9090-99ab79dc011d','送宋秀才','饒節','宋','宋诗','song-poetry','','[]','東風欲歸不可挽，門前芳草青青遠。',178,'全唐诗/poet.song.72000.json','["東風欲歸不可挽，門前芳草青青遠。", "倚松卧病不能行，肩輿出門還復懶。", "先生家住岷峨下，當年神授神仙卦。", "死生禍福如眼前，從來卿相爭稱借。", "倚松卧病正無脚，袖出神方色閒暇。", "我知公意事仁義，不學世人事財利。", "無盡先生如古人，一見先生愛其真。", "幾年門下真子弟，付之萬事未嘗計。", "或云公可爲身謀，先生一笑公何醉。", "倚松老矣世共憐，公獨何心德如天。", "從今藜杖儻能扶，山長水遠公能從我無。"]'),
('7a392b9f-1401-4471-8262-e6426278261c','送江南景喜上人','饒節','宋','宋诗','song-poetry','','[]','我有平生雪色塵，廉者不求貪不與。',64,'全唐诗/poet.song.72000.json','["我有平生雪色塵，廉者不求貪不與。", "明朝聊以贈君行，一炷沉烟夜深語。", "丁寧佛法苦無多，文房四物來作魔。", "丈夫所作若未辦，奈此崢嶸歲月何。"]'),
('da1cfed5-b83b-4ae2-9c93-f774d20d97bd','次韵卿山主解嘲','饒節','宋','宋诗','song-poetry','','[]','道人竹瘦松柏剛，飽更風雨慣雪霜。',67,'全唐诗/poet.song.72000.json','["道人竹瘦松柏剛，飽更風雨慣雪霜。", "堂堂自住一法界，豈與蕭艾相短長。", "利刀割水風吹光，以空壞空竟誰傷。", "君不見湖邊飛來兩白鷺，終朝容與水雲鄉。"]'),
('32f7398b-b92c-4b95-8904-ff6b8878bd98','豫章寶智上人持高子詩求和','饒節','宋','宋诗','song-poetry','','[]','我客飛來峰，一室聊自適。',120,'全唐诗/poet.song.72000.json','["我客飛來峰，一室聊自適。", "關門不敢開，怒風退六鷁。", "敲門者爲誰，起我正禪寂。", "稻麻竹葦中，見此一英特。", "手携高子句，按譜恣遊歷。", "高子我舊遊，伉俠不易得。", "憶昔京城隅，王郎古遺直。", "當時會合地，爛漫存轍蹟。", "繄君入社晚，感事一嗟惜。", "安得賦歸堂，尋盟合琮璧。"]'),
('e70a03d4-562c-473b-8e0f-2c8363d50e5f','贈卿書記','饒節','宋','宋诗','song-poetry','','[]','我室如逆旅，塵坌被几席。',288,'全唐诗/poet.song.72000.json','["我室如逆旅，塵坌被几席。", "自是懶掃除，初非護鼠跡。", "比室有道人，高潔如玉璧。", "時來相勞苦，倚席笑啞啞。", "道人居若何，純素勝金碧。", "槃盂及几杖，奠置有疆埸。", "青絲貫湘竹，秩秩間儒釋。", "短長各部伍，行列共繩尺。", "試看缶中蘭，修葉浄如拭。", "我亦捧心顰，觸缾汙履舄。", "乃知效子敗，古語不可易。", "時當過師語，輸寫盡胸臆。", "師言吐如屑，永語嗟嘖嘖。", "問師何所嗟，吾道苦荆棘。", "堂堂大道場，兒輩恣陵轢。", "苞苴幸引援，側媚乞朝夕。", "爭傳外道語，盜履祖師閾。", "狂瀾不可回，妖氛一何逼。", "柏直尚乳臭，唐儉安足惜。", "世無磊落人，口語謾籍籍。", "豈無直道師，衆寡久不敵。", "常恐碧眼胡，西來苦無益。", "道人僧之傑，老驥猶伏櫪。", "安得大寶坊，降魔掃妖癖。"]'),
('8b6c09f9-af14-4965-8d14-86eb68ee440b','潤屋軒詩','饒節','宋','宋诗','song-poetry','','[]','層崖如立壁，秀潤初欲溜。',276,'全唐诗/poet.song.72000.json','["層崖如立壁，秀潤初欲溜。", "下有癯道人，異時妙基構。", "爲山不爲屋，豈待吉日戊。", "軒成玉滿家，不減朱門富。", "松篁既崔錯，雲霧亦臻湊。", "霜威入松骨，古滑咽泉竇。", "谷風卷簷回，浩蕩金石奏。", "騷騷烏夜啼，鼎鼎雉朝雊。", "時於藤蘿中，便捷一猿透。", "客來坐胡床，紙帳卷輕皺。", "兒童敬杖屨，文史當俎豆。", "微薰出小鼎，長缾上虛甃。", "此樂師有餘，何爲尚奔走。", "記我識師初，昂昂野鶴瘦。", "風姿入清古，氣象脫凡陋。", "我遊山海間，未獲一角獸。", "如師能幾何，不落餘子後。", "師如佳少年，氣出萬夫右。", "平生千鈞弩，要以一手彀。", "雖未須眉蒼，典刑已可候。", "汲深非短綆，善舞屬長袖。", "願君浚其源，故道或可復。", "功成歸此軒，趺坐了昏晝。"]'),
('df8af5ae-08d6-42d2-adad-236393bfb1c7','錢塘清照律師芝草出其父墓上爲作此詩','饒節','宋','宋诗','song-poetry','','[]','槃槃千丈松，磅礴犯雲漢。',240,'全唐诗/poet.song.72000.json','["槃槃千丈松，磅礴犯雲漢。", "要爲根所持，龍蛇走斷岸。", "英英西洛花，妙爲天下冠。", "根移枝可易，人爲過其半。", "君看此靈芝，不與彼共貫。", "超然自挺立，初不頼根榦。", "儻可種而植，朱門當爛漫。", "胡爲不可致，圖畫空傳翫。", "芝生在何許，可卜不待彖。", "忠臣孝子家，義夫烈士館。", "吉事定有祥，豈是供好玩。", "道人律之師，父蠱雖不幹。", "平生沙門行，報德已無算。", "向來郭氏阡，盛事傳里閈。", "青青十畝陰，手植幾脫腕。", "召和不吹律，脩德自幽贊。", "至今超山下，百本益璀璨。", "亭亭卷雲濤，濯濯立鵝鸛。", "乃知天人間，决定可覆按。", "野人爲作詩，誦實不敢贊。"]'),
('db2ce4a6-b190-4898-959e-e8786442a311','次韵呂無求同泛汴水','饒節','宋','宋诗','song-poetry','','[]','瑣瑣榆下錢，貼貼水上鏡。',108,'全唐诗/poet.song.72000.json','["瑣瑣榆下錢，貼貼水上鏡。", "蝸牛共飲吸，水馬競馳騁。", "靜中觀至妙，度此春日永。", "舟師挽且譁，俚語相譏病。", "勞逸各有役，不必盡乘興。", "公緣升斗窮，我訪山水勝。", "雖云異出處，同是縛垢凈。", "何當俱一掃，歇此風中艇。", "携持少室去，從渠謂捷徑。"]'),
('7aa61ed6-ec3e-4988-a90f-4bc9dde893d7','次韵呂居仁送李商老兼簡李去言兄弟諸同參五首  其一','饒節','宋','宋诗','song-poetry','','[]','歲月如翻江，學道若農務。',60,'全唐诗/poet.song.72000.json','["歲月如翻江，學道若農務。", "道人競寸晷，政以生死故。", "耽耽鷺闖池，落落鶴警露。", "瞥然忽中的，優曇濯泥汙。", "何當一鼓作，姑置管城兔。"]'),
('ef952007-f571-4164-bf31-272d2b2067a8','次韵呂居仁送李商老兼簡李去言兄弟諸同參五首  其二','饒節','宋','宋诗','song-poetry','','[]','開門對南山，萬物盡昭告。',60,'全唐诗/poet.song.72000.json','["開門對南山，萬物盡昭告。", "自是君不領，豈是君不好。", "諸人如驥子，矯首萬里道。", "援琴欲寫之，促軫不能操。", "請子亦停手，趺坐西南奧。"]'),
('0d004b15-f86f-4bb7-a141-2a9c3da9b680','次韵呂居仁送李商老兼簡李去言兄弟諸同參五首  其三','饒節','宋','宋诗','song-poetry','','[]','同參如用兵，各出不會期。',60,'全唐诗/poet.song.72000.json','["同參如用兵，各出不會期。", "一將夜破敵，諸將或未知。", "如何衛霍材，局趣窺短籬。", "軍儲有量數，歲月未易支。", "惟兵不可宿，早寄入塞詩。"]'),
('1b9ec75e-11d5-4a40-bcac-00753a00f0a2','次韵呂居仁送李商老兼簡李去言兄弟諸同參五首  其四','饒節','宋','宋诗','song-poetry','','[]','角巾拂彈棋，運斤斲蠅翼。',60,'全唐诗/poet.song.72000.json','["角巾拂彈棋，運斤斲蠅翼。", "當時未得妙，豈暇日入息。", "譬如河漫流，難以一簣塞。", "飲食男女間，嬉笑中盜賊。", "要須了其原，及此未曛黑。"]'),
('52c8f0fb-8fc0-4a5d-931a-3e4aab19f0cb','次韵呂居仁送李商老兼簡李去言兄弟諸同參五首  其五','饒節','宋','宋诗','song-poetry','','[]','李氏澤如海，富此明月珠。',60,'全唐诗/poet.song.72000.json','["李氏澤如海，富此明月珠。", "諸郎皆可人，共出堯舜途。", "之子見我時，抱負勤髯奴。", "江頭一再見，凜凜氣百夫。", "贈子伊字門，不類城旦書。"]'),
('6dc94d95-7d7d-4af3-bf9a-623318c18da8','次韵答曾仲成二首  其一','饒節','宋','宋诗','song-poetry','','[]','曾侯果勝流，折節事膏火。',96,'全唐诗/poet.song.72000.json','["曾侯果勝流，折節事膏火。", "年來何轉窮，正以工詩坐。", "可憐哭鬼句，不救采薇餓。", "平生九品祿，團團螘旋磨。", "歸來卜我鄰，步屧得相過。", "劇談到理窟，我義危欲墮。", "世人富貴忙，此樂渠不那。", "春山正可尋，我行公亦可。"]'),
('8d61e093-47dd-40a0-8477-85a3a1dc8a6c','次韵答曾仲成二首  其二','饒節','宋','宋诗','song-poetry','','[]','我老不能世，百念久灰冷。',84,'全唐诗/poet.song.72000.json','["我老不能世，百念久灰冷。", "偶隨出山雲，託跡蹔人境。", "借問交遊人，出處各形影。", "某或李廣奇，某或衛青幸。", "如公不世才，跬步可臺省。", "何爲賦歸來，欲近沃洲嶺。", "夜半哦公詩，月寒心怲怲。"]'),
('dbcff45f-53ba-40a8-b888-e3f5ac4b8940','養志堂詩爲襄陽吳傳朋通判作','饒節','宋','宋诗','song-poetry','','[]','我思古丈夫，出處各有意。',288,'全唐诗/poet.song.72000.json','["我思古丈夫，出處各有意。", "上焉不作名，下亦豈爲利。", "周旋進退間，萬世作凡例。", "吁嗟古人遠，中夜輒三起。", "老來得賢侯，氣象無乃是。", "少年自挺立，學問造嚴祕。", "筆端挾風雨，麈尾揠根柢。", "問之爲誰歟，盛德有苗裔。", "廣陵之外孫，右司公之子。", "內師孟母賢，外交天下士。", "漸磨薰蒸到，成此不凡器。", "年來貳襄陽，豈爲山水計。", "政以承母心，欲覲淮源隧。", "淮源日夜流，墓木已拱矣。", "母來拜墓門，滿下平生淚。", "回頭語兒孫，更酹墳前地。", "我懷三十年，一飯不忘此。", "惟誠通鬼神，志願今乃遂。", "兒身勉直道，無貽墓中愧。", "寧爲潁封人，勿作魚梁吏。", "到官闢高堂，涓潔亦明麗。", "夜月進古几，春盤供早薺。", "爐薰事禪寂，簡物薄滋味。", "起居飲食安，其樂固洩洩。"]'),
('bc497793-be8f-4b48-9cbb-66f9797f89f2','呂無求以詩堅同舟爲嵩山之約次韵報之','饒節','宋','宋诗','song-poetry','','[]','我窮走四方，瑣瑣知交態。',96,'全唐诗/poet.song.72000.json','["我窮走四方，瑣瑣知交態。", "呂卿晚定交，槁質頼沾溉。", "筆端有神奇，胸次無疆界。", "平生書畫船，往往出光怪。", "我非張孝廉，招呼許同載。", "顧我念嵩洛，如痞思一憶。", "况飛西北帆，一枕千里快。", "便當謀吉日，恐負遊山債。"]'),
('461be47e-1161-4264-b92d-64ab3a067394','閱舊詩軸見夏均父和晁之道詩次其韵寄伯容仲成均父諸友','饒節','宋','宋诗','song-poetry','','[]','往者少年日，所慕韓伯休。',216,'全唐诗/poet.song.72000.json','["往者少年日，所慕韓伯休。", "涉世更百難，得交多勝流。", "當時回俗駕，喘汗困萬牛。", "晚看故曹耦，半逝半乃侯。", "侯者朱其輪，逝者卧荒丘。", "荒丘不足悲，朱輪或可羞。", "翻然乃自悟，庶幾桑榆收。", "朋儕競挽止，一往只掉頭。", "我豈築室愚，喋喋于道謀。", "向來漢上行，懸知計未優。", "重念佛祖心，獨往恐不酬。", "細看叢林敝，百孔如破裘。", "出有造請惡，入懷薪米憂。", "雖云學道輩，坦途多不由。", "我欲獨挽之，難哉推陸舟。", "歸來擁白雲，草茅有前修。", "誓不出山去，三更林莽秋。", "寄聲二三友，興來過我不。"]'),
('04c3784f-5954-497d-8256-5cde5443b1a4','虛舟齋詩爲王深叔作','饒節','宋','宋诗','song-poetry','','[]','人生一涉世，波瀾渺無窮。',168,'全唐诗/poet.song.72000.json','["人生一涉世，波瀾渺無窮。", "凡兒似得計，兀兀自窮能。", "惟有盛名下，頗招衆嫉攻。", "開關或延敵，政使臧亦凶。", "古人故不爾，山泉養正蒙。", "我非阮嗣宗，何時見阿戎。", "濯濯春月柳，謖謖松下風。", "似聞未著冠，筆力百夫雄。", "餘子窘不足，渠乃忌太豐。", "比從道人遊，警悟世諦中。", "試觀名齋意，已見應世工。", "聖賢在方策，制行固不同。", "惟有虛己遊，萬川同一東。", "此名可書紳，願言謹厥終。"]'),
('6a2aae0a-a6e6-4c26-a224-6c453577d079','和周提刑樂歲詩','饒節','宋','宋诗','song-poetry','','[]','老農終歲忙，濯足不及骭。',144,'全唐诗/poet.song.72000.json','["老農終歲忙，濯足不及骭。", "豈無相勞苦，穡事苦縈絆。", "邇來鄰酒熟，隔戶聞呼喚。", "客至便爲約，此飲期達旦。", "乃翁起行酌，瓦缶恣瀰漫。", "一引未置之，捋肘發屢歎。", "嘗記秋來雨，似稱春餘旱。", "旱憂牟麥焦，雨懼禾黍爛。", "而今雨旱解，萬事皆畢幹。", "儻非值時和，未易了炊爨。", "似聞使者賢，云似周十亂。", "語竟復滿引，抵掌笑秦漢。"]'),
('e075a1a0-65e8-4a0f-9627-c9f4fb292456','次韵酬潘庭立儀曹見贈之作','饒節','宋','宋诗','song-poetry','','[]','安仁可獨來，連璧豈易得。',120,'全唐诗/poet.song.72000.json','["安仁可獨來，連璧豈易得。", "我老閱士久，此士秀江國。", "不窺董生園，頗割子魚席。", "向來决勝地，辟水湛寒碧。", "幾年富問學，一道貫儒釋。", "捉麈初不譁，論正語明白。", "哦詩咄嗟辦，妙韵出金石。", "吾家妙喜師，賞歎節屢擊。", "夜堂明月冷，鼎足坐禪寂。", "他年山中人，盛事話疇昔。"]'),
('7e3d9865-9c9d-4fd0-abfb-1d4d9c8724fc','杲道人屢聘不起用庭立韵作詩開之','饒節','宋','宋诗','song-poetry','','[]','百年過雷雹，誰喪復誰得。',120,'全唐诗/poet.song.72000.json','["百年過雷雹，誰喪復誰得。", "邯鄲一枕夢，蝸角兩戰國。", "道人脫世網，便卷百丈席。", "分明老胡裔，彷彿眸子碧。", "向來數道場，衆挽不容釋。", "金言無自晦，如反衣狐白。", "道人笑不答，我心固匪石。", "邇來燕雀豪，頗須鷹隼擊。", "達人有舒卷，大士等喧寂。", "何當爲衆起，孰謂今非昔。"]'),
('0c92206f-6e24-4b3d-bb2d-6cc19cf07bbf','元輝上人喜賦詩作東坡字蕭然有出塵之姿渠亦用韵有作且乞詩爲別因再次韵贈之','饒節','宋','宋诗','song-poetry','','[]','禪流筆墨戲，好句亦時得。',120,'全唐诗/poet.song.72000.json','["禪流筆墨戲，好句亦時得。", "譬如世佳人，不必須傾國。", "我行百城時，所至不暖席。", "默求支許流，常歎暮雲碧。", "阿師有典刑，一見我心釋。", "根源師璨可，餘事窺元白。", "叢林半良窳，初若泗濱石。", "欲出金玉音，不妨聊考擊。", "致遠或恐泥，落華反枯寂。", "口邊白醭去，願子師古昔。"]'),
('3456c722-fb9f-41b6-a62f-5c8805924a4d','修上人出覺範送行詩言別因次韵餞之','饒節','宋','宋诗','song-poetry','','[]','上人邱壑姿，韵出餘子右。',96,'全唐诗/poet.song.72000.json','["上人邱壑姿，韵出餘子右。", "已經老洪目，云是江南秀。", "訪我白崖巔，喘汗經層岫。", "初無一日雅，恍若十年舊。", "胡床氣未穩，牙籤出深袖。", "我居人跡絕，特坐歲時久。", "子來亦遽去，既別重回首。", "招提送客還，松戶閉春晝。"]'),
('a1cd7b16-7d9d-4b0d-826d-4930bd1ed9d8','望雞園詩','饒節','宋','宋诗','song-poetry','','[]','望雞天人供，韵出芝菌表。',108,'全唐诗/poet.song.72000.json','["望雞天人供，韵出芝菌表。", "炎蒸夜過雨，裂地出清曉。", "根株樹玉雪，頂𩕳翬青縹。", "羽衣散皋原，鴻雁集蘋蓼。", "邂逅遽擷取，已盡首猶矯。", "麻昉助芳烈，薑芼戒煩擾。", "取味俄頃間，薇蕨蓋其小。", "吾生易與耳，升合自可了。", "聊爲道人劇，五鼎端可少。"]'),
('a9708eaa-b8bf-406d-ba0f-5c40be90fed9','用蔡伯世韵作詩寄之兼簡呂居仁兄弟十首  其一','饒節','宋','宋诗','song-poetry','','[]','蔡侯材棟梁，向來飽霜露。',24,'全唐诗/poet.song.72000.json','["蔡侯材棟梁，向來飽霜露。", "十年林下思，常恐庾塵汙。"]'),
('7a9fb01c-5561-495b-a543-0d317181a73c','用蔡伯世韵作詩寄之兼簡呂居仁兄弟十首  其二','饒節','宋','宋诗','song-poetry','','[]','人生落世故，至寶墮深井。',24,'全唐诗/poet.song.72000.json','["人生落世故，至寶墮深井。", "儻無自拔計，金玉謾棄屏。"]'),
('cce20948-2f83-434a-87f4-605b5f2f9d56','用蔡伯世韵作詩寄之兼簡呂居仁兄弟十首  其三','饒節','宋','宋诗','song-poetry','','[]','至理本曠夷，小道皆左僻。',24,'全唐诗/poet.song.72000.json','["至理本曠夷，小道皆左僻。", "信能彈指了，可死不待夕。"]'),
('921a0e25-72ed-4f4d-8dc6-37062bff0324','用蔡伯世韵作詩寄之兼簡呂居仁兄弟十首  其四','饒節','宋','宋诗','song-poetry','','[]','松毛巧婦禽，螺殻寄居蟲。',24,'全唐诗/poet.song.72000.json','["松毛巧婦禽，螺殻寄居蟲。", "二物自廣大，那知十方空。"]'),
('fb353e2c-8e51-43b3-9d75-129c5e5e59f6','用蔡伯世韵作詩寄之兼簡呂居仁兄弟十首  其五','饒節','宋','宋诗','song-poetry','','[]','百年固多變，深谷或高岸。',24,'全唐诗/poet.song.72000.json','["百年固多變，深谷或高岸。", "要知悟破迷，大似理易亂。"]'),
('2dff06c4-d21c-4421-9b85-08f1edf2abad','用蔡伯世韵作詩寄之兼簡呂居仁兄弟十首  其六','饒節','宋','宋诗','song-poetry','','[]','見彈已求炙，亡羊猶補牢。',24,'全唐诗/poet.song.72000.json','["見彈已求炙，亡羊猶補牢。", "功成無早暮，事竟等卑高。"]'),
('424588d2-94b0-42a5-89de-241de0b8af33','用蔡伯世韵作詩寄之兼簡呂居仁兄弟十首  其七','饒節','宋','宋诗','song-poetry','','[]','君豈蔡子叔，我非支道林。',24,'全唐诗/poet.song.72000.json','["君豈蔡子叔，我非支道林。", "何當速相就，爲子細徵心。"]'),
('a8429237-2f07-462a-8361-9544266fb81a','用蔡伯世韵作詩寄之兼簡呂居仁兄弟十首  其八','饒節','宋','宋诗','song-poetry','','[]','沉水博山爐，積灰如雪霜。',24,'全唐诗/poet.song.72000.json','["沉水博山爐，積灰如雪霜。", "何如坐三昧，自薰成定香。"]'),
('c4650b69-64b9-4573-8520-c27976db0a27','用蔡伯世韵作詩寄之兼簡呂居仁兄弟十首  其九','饒節','宋','宋诗','song-poetry','','[]','三世如旦暮，四大轉風火。',24,'全唐诗/poet.song.72000.json','["三世如旦暮，四大轉風火。", "儻能了無生，如觀掌中果。"]'),
('e4a3ee69-0d16-40cf-b7f1-ef2aeb050ffc','用蔡伯世韵作詩寄之兼簡呂居仁兄弟十首  其一○','饒節','宋','宋诗','song-poetry','','[]','學道十萬衆，得者一二稀。',24,'全唐诗/poet.song.72000.json','["學道十萬衆，得者一二稀。", "寄聲故曹耦，捨此將安歸。"]'),
('675448db-9453-42a9-b4e6-cbc6ddb8d08b','示故人','饒節','宋','宋诗','song-poetry','','[]','變化密移何太急，剎那念念一呼吸。',60,'全唐诗/poet.song.72000.json','["變化密移何太急，剎那念念一呼吸。", "八萬四千方便門，且道何門不可入。", "入不入，曉來微雨芭蕉濕。", "殷勤更問箇中人，門外堂堂相對立。"]'),
('82574d57-7517-4fdf-a135-2a192d1a895a','次韵應銓詩','饒節','宋','宋诗','song-poetry','','[]','誰養山中雲，館我雲中寺。',36,'全唐诗/poet.song.72000.json','["誰養山中雲，館我雲中寺。", "山深雲常潤，出戶須芒屨。", "可憐雲外人，過我一飯去。"]'),
('de6aa96c-e818-488f-b80b-144204ddf180','客舟','饒節','宋','宋诗','song-poetry','','[]','三界衆生俱是客，就中君是客中客。',32,'全唐诗/poet.song.72000.json','["三界衆生俱是客，就中君是客中客。", "眼前何處非君家，莫道君家歸未得。"]'),
('3f5e2c02-f57b-4fe0-86aa-4e336ebae99a','王信玉生日','饒節','宋','宋诗','song-poetry','','[]','簪笏誰非嗣，才能恐未難。',240,'全唐诗/poet.song.72000.json','["簪笏誰非嗣，才能恐未難。", "傳家推有守，樹德莫如寬。", "賤子敢爲佞，明公信可觀。", "四維開雉堞，千頃漲波瀾。", "逮下亡圭角，逢人倒肺肝。", "月評終許劭，愛客自袁安。", "不僞心常逸，忘機體更胖。", "所臨惟簡易，有道息彫殘。", "使節軺車穩，兵符玉具乾。", "百城同鏁靜，萬井益歌歡。", "退食公無事，揮毫妙可刊。", "笙歌珠履醉，風月井梧寒。", "諸子仍聞道，羣雛半著冠。", "居然謝紈綺，沃若秀芝蘭。", "表裏初無憾，行藏晚竟完。", "向來三徑志，欲了五車看。", "異日人爭誦，來徵印已刓。", "恐須煩柱石，從此接鴛鸞。", "直道惟天相，亨衢豈自干。", "祝公千歲壽，終始立朝端。"]'),
('7169e7cf-0346-475b-bc8e-0e542ecd42cc','九月六日駕幸蔡王府','饒節','宋','宋诗','song-poetry','','[]','詔可觀光夾路民，雍容禁衛見寬仁。',64,'全唐诗/poet.song.72000.json','["詔可觀光夾路民，雍容禁衛見寬仁。", "天光湛湛乾坤凈，玉色溫溫草木春。", "虛駕老臣人望重，降輿新第聖恩親。", "屬車未御鈞天奏，只有歡聲滿後塵。"]'),
('65e0e50e-51c2-4c4e-9365-06a13b683584','過關山用同行韵','饒節','宋','宋诗','song-poetry','','[]','風來幡動作真觀，耳倒聲邊亦妄聞。',64,'全唐诗/poet.song.72000.json','["風來幡動作真觀，耳倒聲邊亦妄聞。", "自笑敝貂蘇季子，苦求知畫宋元君。", "關山行李今三反，燈火工夫費幾分。", "安得一廛留我老，抱琴矯首送浮雲。"]'),
('5d5fef0c-1fc2-4af1-86b4-f9c7b69e8a6f','遇里人道及鄉閭事作詩寄謝無逸','饒節','宋','宋诗','song-poetry','','[]','敝貂去國漫西東，聞說鄉閭夢寐中。',64,'全唐诗/poet.song.72000.json','["敝貂去國漫西東，聞說鄉閭夢寐中。", "賈豎裹頭仍納婦，驪駒將子又追風。", "雲山何處非投老，文史他年不療窮。", "富貴可求吾亦懶，眼看餘子化王公。"]'),
('760c5c44-f0fc-405b-93a9-fec0670736d4','謁漢高帝廟','饒節','宋','宋诗','song-poetry','','[]','鳳凰山下綠茫茫，殺氣猶纏古戰場。',64,'全唐诗/poet.song.72000.json','["鳳凰山下綠茫茫，殺氣猶纏古戰場。", "他日英雄矜勝敗，今時田野話興亡。", "狗烹兔死已千載，雷動風行尚一方。", "過客若餘秦父老，拜祠應有泪浪浪。"]'),
('c36f3de4-10e3-4d96-8a04-74bce14cb207','贈霍明府偉','饒節','宋','宋诗','song-poetry','','[]','南海先生不諱窮，鬢髯如戟氣如虹。',64,'全唐诗/poet.song.72000.json','["南海先生不諱窮，鬢髯如戟氣如虹。", "異時磅礴風塵外，今日低回文課中。", "政事有誰咨蹇老，功名未合愧終童。", "何人爲草陽城薦，臺閣差差振古風。"]'),
('bc7dab65-37c9-47c4-84c7-90cdd019c696','次韵張符離民師適堂即事','饒節','宋','宋诗','song-poetry','','[]','三考符離課獨優，政成囹圄自無囚。',64,'全唐诗/poet.song.72000.json','["三考符離課獨優，政成囹圄自無囚。", "滿堂文史閑□令，一榻薰風對奕秋。", "刑措似聞閭巷語，年登仍解廟堂憂。", "從今尊酒留佳句，折獄何勞比仲由。"]'),
('4425c71c-4b28-4cf0-baa9-2a17998ffab3','汪信民約諸人遊城南陳氏園不果','饒節','宋','宋诗','song-poetry','','[]','先生休沐不譚經，準擬行槃到野亭。',64,'全唐诗/poet.song.72000.json','["先生休沐不譚經，準擬行槃到野亭。", "興盡回船散童騎，客來呼吏出盆缾。", "奩中白黑誰成敗，醆底聖賢同醉醒。", "却笑伯倫尚多事，苦憐江漢載浮萍。"]'),
('bc2e5273-71d0-4718-b0f5-f093cb88509a','贈隠居','饒節','宋','宋诗','song-poetry','','[]','竟體芳蘭君可人，一軒風月澹無鄰。',64,'全唐诗/poet.song.72000.json','["竟體芳蘭君可人，一軒風月澹無鄰。", "絲麻十畝他年老，文史三冬上世貧。", "渾渾淄澠空自辨，眈眈狼虎謾相親。", "了然道眼都無許，祇有鶑花滿意春。"]'),
('42aabaf8-da6b-4311-846c-e38698d4518c','次韵彭聖從秋興','饒節','宋','宋诗','song-poetry','','[]','淡雲疏雨承秋早，白露清風引夜長。',64,'全唐诗/poet.song.72000.json','["淡雲疏雨承秋早，白露清風引夜長。", "已見畢星朝北極，似聞驍騎卷西凉。", "隻雞還我田家味，小胯須君官焙香。", "千古步兵今遠矣，屬誰長嘯作鸞凰。"]'),
('408c7e01-6b47-4ee7-8e46-491ba666adc9','題滄浪亭','饒節','宋','宋诗','song-poetry','','[]','君構虛亭古岸頭，我來登覽判千憂。',64,'全唐诗/poet.song.72000.json','["君構虛亭古岸頭，我來登覽判千憂。", "丈人釣艇波瀾闊，孺子歌聲草樹秋。", "山似畫屏隨屈曲，人如楊柳擅風流。", "他年若有江湖具，乘興因君棹小舟。"]'),
('5c0f6365-6380-475c-840f-d1824b19a9de','次韵米元章壯觀','饒節','宋','宋诗','song-poetry','','[]','曉色村村澹，春風樹樹穠。',48,'全唐诗/poet.song.72000.json','["曉色村村澹，春風樹樹穠。", "八窗中夜月，千里隔江峰。", "酒道窮通樂，詩原左右逢。", "客來應下榻，石銚煮長松。"]'),
('7d748024-6b89-4f10-99d8-4edd03a0446e','端午日二首  其一','饒節','宋','宋诗','song-poetry','','[]','艾葉斜枝短，菖蒲瘦節長。',48,'全唐诗/poet.song.72000.json','["艾葉斜枝短，菖蒲瘦節長。", "綠雲依鬢亂，紅雪落杯香。", "風物江淮似，功名歲月忙。", "澤間人弔屈，應有泪浪浪。"]'),
('1860f321-2440-40d8-8d5d-6d510c65034e','端午日二首  其二','饒節','宋','宋诗','song-poetry','','[]','異代多同俗，千秋餉楚魂。',48,'全唐诗/poet.song.72000.json','["異代多同俗，千秋餉楚魂。", "人才終可惜，祀事故常存。", "赤鹵豐禾黍，閑民長子孫。", "憐渠身世拙，滿眼暮雲屯。"]'),
('a199f98a-60ba-41d4-961a-f7e004a0c944','山居二首  其一','饒節','宋','宋诗','song-poetry','','[]','小徑深通竹，疏籬巧過藤。',48,'全唐诗/poet.song.72000.json','["小徑深通竹，疏籬巧過藤。", "冷猿嘯古木，饑鷺啄寒冰。", "貴客終難屈，蓬門不用應。", "此中有佳處，黄卷短檠燈。"]'),
('b5791434-7ed4-43db-843c-179b0a3845ad','山居二首  其二','饒節','宋','宋诗','song-poetry','','[]','門擁深深草，溪明衮衮沙。',48,'全唐诗/poet.song.72000.json','["門擁深深草，溪明衮衮沙。", "冷烟浮菜甲，小雨薦茅牙。", "老興元無繫，春工竟自華。", "鄰翁却相可，步屧過渠家。"]'),
('ed702386-c487-467a-8bc1-9068a4d9d935','送王長元同弟次元赴官','饒節','宋','宋诗','song-poetry','','[]','梁苑春未競，隋河凍尚肥。',48,'全唐诗/poet.song.72000.json','["梁苑春未競，隋河凍尚肥。", "鬢毛開老境，甲子運天機。", "華鄂君方仕，樵蘇我未歸。", "憑將汝南麈，慎對可人揮。"]'),
('161f2936-57bb-4622-86d2-f18f14f87005','蒲適正挽歌','饒節','宋','宋诗','song-poetry','','[]','吾道何多蹇，蒼天呼不聞。',48,'全唐诗/poet.song.72000.json','["吾道何多蹇，蒼天呼不聞。", "楩楠初有待，涇渭竟難分。", "閱世中庸行，隨時俗下文。", "想君九原恨，著草露紛紛。"]'),
('6e4121cb-0043-434b-879a-ccdbbb2d4b97','息慮軒詩','饒節','宋','宋诗','song-poetry','','[]','雨暗藤經屋，春深草到門。',48,'全唐诗/poet.song.72000.json','["雨暗藤經屋，春深草到門。", "客來非問字，鶴老不乘軒。", "花氣翻詩思，松聲撼醉魂。", "呼兒換香鼎，趺坐竟黄昏。"]'),
('17db71ad-434d-49f4-aa43-6ea231899ce7','歲暮','饒節','宋','宋诗','song-poetry','','[]','浩蕩生涯計，凄凉客子心。',48,'全唐诗/poet.song.72000.json','["浩蕩生涯計，凄凉客子心。", "歲從官歷盡，憂入鬢毛深。", "月氣含窗戶，湯聲轉釜鬵。", "餘生無所慕，持此卧山林。"]'),
('0cd2eff6-fe49-4e6b-9182-c50852cc446f','送宿州晁祖禹簽判','饒節','宋','宋诗','song-poetry','','[]','一見晁公子，雍容前輩風。',48,'全唐诗/poet.song.72000.json','["一見晁公子，雍容前輩風。", "規橅俗吏外，步作古人中。", "環佩千官合，梯航九驛通。", "空虛循吏傳，誰爲薦諸公。"]'),
('40f981b5-07f9-402a-bec6-6ed456156e10','九日發淮康','饒節','宋','宋诗','song-poetry','','[]','九日非吾事，黄花亦謾生。',48,'全唐诗/poet.song.72000.json','["九日非吾事，黄花亦謾生。", "未傾彭澤酒，還背汝陽城。", "細雨秋天近，西風白葛輕。", "山村遠城市，可有笑歌聲。"]'),
('7f720b3e-388c-4785-8f11-87a849958027','秋日遊城南展氏園登閣','饒節','宋','宋诗','song-poetry','','[]','金燈奮髯階砌寬，楊柳緩带樓閣閑。',32,'全唐诗/poet.song.72000.json','["金燈奮髯階砌寬，楊柳緩带樓閣閑。", "我來不爲春事促，西風斜日面前山。"]'),
('fc7c057e-f3ae-4981-b1b6-3b1d2783e2c8','製藥','饒節','宋','宋诗','song-poetry','','[]','身如逆旅無非我，豈謂昌陽信引年。',64,'全唐诗/poet.song.72000.json','["身如逆旅無非我，豈謂昌陽信引年。", "南北未能忘世故，藥囊隨處却安禪。", "萬金良藥吾何用，九轉丹砂世謾傳。", "草木精華如可貰，未妨巾屨地行仙。"]'),
('d9c6f073-597a-47ec-9c9d-c8e97911ecc7','麻城道中','饒節','宋','宋诗','song-poetry','','[]','拱道新松無數青，晚風十里撼江聲。',32,'全唐诗/poet.song.72000.json','["拱道新松無數青，晚風十里撼江聲。", "棟梁不是尋常度，宜有長材待老成。"]'),
('482ad89d-d502-4c58-909d-a8303642c871','過淮','饒節','宋','宋诗','song-poetry','','[]','淮山漠漠水潭潭，落日孤雲自不堪。',32,'全唐诗/poet.song.72000.json','["淮山漠漠水潭潭，落日孤雲自不堪。", "今夜月明風更急，憑吹魂夢到江南。"]'),
('01d79985-4f65-43d3-8c35-5f1b8b0ebc47','從人覓山水扇二首  其一','饒節','宋','宋诗','song-poetry','','[]','少壯崎嶇山水間，短衣楚製略勝寒。',32,'全唐诗/poet.song.72000.json','["少壯崎嶇山水間，短衣楚製略勝寒。", "年來疲病歸期墮，只乞君家便面看。"]'),
('9e0a112a-7c9c-42c3-a6c4-5b6467714f64','從人覓山水扇二首  其二','饒節','宋','宋诗','song-poetry','','[]','愛君才氣耻言兵，欲倚詩書繼老成。',32,'全唐诗/poet.song.72000.json','["愛君才氣耻言兵，欲倚詩書繼老成。", "手裏林泉當付我，恐妨抽板揖公卿。"]'),
('00caba9c-0419-405b-a91b-8061bf125d8b','偶書','饒節','宋','宋诗','song-poetry','','[]','廣離騷罷獨支頤，萬里江山座上歸。',32,'全唐诗/poet.song.72000.json','["廣離騷罷獨支頤，萬里江山座上歸。", "門外不知蠻戰觸，滿窗蚊子刺明飛。"]'),
('e4eb435c-7176-444c-8922-51ae25b7ad91','自簡','饒節','宋','宋诗','song-poetry','','[]','錯龜數策願分疑，筮短龜長一是非。',32,'全唐诗/poet.song.72000.json','["錯龜數策願分疑，筮短龜長一是非。", "但把故吾重簡練，不須分畫見郊圻。"]'),
('f02b40ea-6fd7-4302-abba-0dde3b551098','以太學燈籠遺陳松老','饒節','宋','宋诗','song-poetry','','[]','君有傳家三尺檠，巨編長軸稱經營。',32,'全唐诗/poet.song.72000.json','["君有傳家三尺檠，巨編長軸稱經營。", "時文今是蠅頭字，遺子終南捷徑行。"]'),
('f421f2a5-a8bf-4b7b-96da-7346ee17e17d','聞說','饒節','宋','宋诗','song-poetry','','[]','聞說南方仍歲旱，十家生事九家空。',32,'全唐诗/poet.song.72000.json','["聞說南方仍歲旱，十家生事九家空。", "君王分寄二千石，避寢何人舍蓋公。"]'),
('d718ccf0-43d9-41cd-a9b4-239c26c4d7a4','鄰雞','饒節','宋','宋诗','song-poetry','','[]','鄰雞振羽非惡聲，北斗倒挂玉繩橫。',32,'全唐诗/poet.song.72000.json','["鄰雞振羽非惡聲，北斗倒挂玉繩橫。", "朋來勞苦饑寒解，客去悠颺羽翼成。"]'),
('a28cdd52-7d22-46de-9d6d-ecb4224ff989','久雨偶晴見日','饒節','宋','宋诗','song-poetry','','[]','濃陰百日漫西東，洶洶隋河夜欲洪。',32,'全唐诗/poet.song.72000.json','["濃陰百日漫西東，洶洶隋河夜欲洪。", "但得望堯常拜手，誰能畏盾輒逃空。"]'),
('6b50028e-f9ad-4a2f-80d9-452bef28ccef','趙元達久不至池上作詩戲之','饒節','宋','宋诗','song-poetry','','[]','雨後新荷擁岸青，菰蒲相向立蜻蜓。',32,'全唐诗/poet.song.72000.json','["雨後新荷擁岸青，菰蒲相向立蜻蜓。", "此中佳處君知否，應對文君賦小星。"]'),
('bfb57ce7-a520-4ac4-bea6-34112cef9815','再用韵','饒節','宋','宋诗','song-poetry','','[]','楊柳池塘表裏青，魚兒偷眼畏蜻蜓。',32,'全唐诗/poet.song.72000.json','["楊柳池塘表裏青，魚兒偷眼畏蜻蜓。", "夜來雨過菖蒲靜，倒浸中天四五星。"]'),
('5dcd8c6b-56fe-4d81-8498-d85aac900e02','書天源河上友人壁','饒節','宋','宋诗','song-poetry','','[]','春色撩人不奈渠，紅塵無處可飛鳬。',32,'全唐诗/poet.song.72000.json','["春色撩人不奈渠，紅塵無處可飛鳬。", "懸知桃李付流水，來看垂楊十萬株。"]'),
('98384c71-b16d-499c-9782-f76eb922425e','次韵答陳考城','饒節','宋','宋诗','song-poetry','','[]','袖裏楞伽非世書，了知乾沒未殊途。',32,'全唐诗/poet.song.72000.json','["袖裏楞伽非世書，了知乾沒未殊途。", "會携他日已漫刺，歸謁南山五大夫。"]'),
('c8968f40-4ef2-436f-bdd9-00044d29a7fc','爲謝無逸賦梅花二首  其一','饒節','宋','宋诗','song-poetry','','[]','頓有亭前春耐寒，年年扶杖雪中看。',32,'全唐诗/poet.song.72000.json','["頓有亭前春耐寒，年年扶杖雪中看。", "不知謝子題詩處，比得王家第幾般。"]'),
('79fcee0a-2806-4046-a7b4-1868cdbfedf1','爲謝無逸賦梅花二首  其二','饒節','宋','宋诗','song-poetry','','[]','聞道香寒卧雪枝，瓊樓玉戶巧相依。',32,'全唐诗/poet.song.72000.json','["聞道香寒卧雪枝，瓊樓玉戶巧相依。", "可憐今日移根處，王謝堂前燕子飛。"]'),
('3aba99bc-3cb7-475f-a57c-1e746e2461b7','戲趙元達','饒節','宋','宋诗','song-poetry','','[]','竹木王孫不嗣音，老夫多病轉侵尋。',32,'全唐诗/poet.song.72000.json','["竹木王孫不嗣音，老夫多病轉侵尋。", "可憐一息絕纓會，破壞經年設醴心。"]'),
('6084b984-ef7c-4de0-b0fa-de2ba2d4308e','冬日書謝氏園壁','饒節','宋','宋诗','song-poetry','','[]','瓦缶藏春土脈乾，嫣香已謝菊花團。',32,'全唐诗/poet.song.72000.json','["瓦缶藏春土脈乾，嫣香已謝菊花團。", "履聲遶盡欄干曲，肅肅松風作暮寒。"]'),
('0cade4cc-8955-4c1f-ab5e-c385678e3c4f','卧雲堂','饒節','宋','宋诗','song-poetry','','[]','補牢初未益亡羊，聊伴閑雲卧草堂。',32,'全唐诗/poet.song.72000.json','["補牢初未益亡羊，聊伴閑雲卧草堂。", "君解入官雲作雨，未應舒卷却相妨。"]'),
('defc0556-b387-4f37-859f-cba220ea1dc7','聽松軒','饒節','宋','宋诗','song-poetry','','[]','老龍偃蹇據巖壑，匠石營材城市中。',32,'全唐诗/poet.song.72000.json','["老龍偃蹇據巖壑，匠石營材城市中。", "自有幽人不相負，解凭曲几聽秋風。"]'),
('a12cd641-8c53-4d9c-8ecf-dde7b3cfeaa6','觀魚閣','饒節','宋','宋诗','song-poetry','','[]','紛紛乾沒可憐渠，小閣詩書自有餘。',32,'全唐诗/poet.song.72000.json','["紛紛乾沒可憐渠，小閣詩書自有餘。", "日背竹林風過柳，試扶松檻看浮魚。"]'),
('cd373250-650d-4eef-9f16-5aa610e7b93e','快目亭','饒節','宋','宋诗','song-poetry','','[]','文字遮人窗閉蠅，無人傳與衛生經。',32,'全唐诗/poet.song.72000.json','["文字遮人窗閉蠅，無人傳與衛生經。", "我愁爛漫不可寫，須上君家快目亭。"]'),
('44ed23b4-28e5-432a-adac-48efcefbbdfa','病中兩絕句  其一','饒節','宋','宋诗','song-poetry','','[]','芒鞋藜杖世緣輕，無妄誰令水火爭。',32,'全唐诗/poet.song.72000.json','["芒鞋藜杖世緣輕，無妄誰令水火爭。", "造物小兒莫相苦，此中無物可虧成。"]'),
('89d7cf4c-1fbe-4dc2-a9e5-a54f072c6225','病中兩絕句  其二','饒節','宋','宋诗','song-poetry','','[]','暑濕相乘勢益昌，呼童煮藥不知方。',32,'全唐诗/poet.song.72000.json','["暑濕相乘勢益昌，呼童煮藥不知方。", "懸知草木皆憑藉，聊爲形骸作主張。"]'),
('a4f470de-944f-47c7-8d6b-10a5924ea067','春日即事二首  其一','饒節','宋','宋诗','song-poetry','','[]','人言春事經桃李，我欲要之病未任。',32,'全唐诗/poet.song.72000.json','["人言春事經桃李，我欲要之病未任。", "昨日强隨年少去，看花那復故時心。"]'),
('dbe29a67-7576-4efa-9b6b-0d0c7d594f69','春日即事二首  其二','饒節','宋','宋诗','song-poetry','','[]','風光竟歲宜人少，樂事惟春取數多。',32,'全唐诗/poet.song.72000.json','["風光竟歲宜人少，樂事惟春取數多。", "果下小騮君借我，一鞭隨意掠烟莎。"]'),
('92414b53-6649-4d74-b2a9-0886e95c8058','送同舍葛茂達還浙東二首  其一','饒節','宋','宋诗','song-poetry','','[]','豈無强醉陽司業，固有無錢鄭廣文。',32,'全唐诗/poet.song.72000.json','["豈無强醉陽司業，固有無錢鄭廣文。", "三請未能勤問道，一歸今日願從君。"]'),
('daa154fe-dfde-40f8-b307-01e0e1593f17','送同舍葛茂達還浙東二首  其二','饒節','宋','宋诗','song-poetry','','[]','隋河東下一千里，僮僕未知行李勞。',32,'全唐诗/poet.song.72000.json','["隋河東下一千里，僮僕未知行李勞。", "聞道杞苗今結子，憑君飽食賦離騷。"]'),
('6df39c31-14d1-41de-819f-e94d6c206410','次韵呂原明侍講歡喜四絕句 麥熟','饒節','宋','宋诗','song-poetry','','[]','黄雲千頃起邱山，缾缶村村自往還。',32,'全唐诗/poet.song.72000.json','["黄雲千頃起邱山，缾缶村村自往還。", "懸知大作今年社，我欲從渠季孟間。"]'),
('3b682718-9242-4ef8-9da4-18d0130e59b4','次韵呂原明侍講歡喜四絕句 拾麥','饒節','宋','宋诗','song-poetry','','[]','撝鐮霍霍穟紛紛，多謝遺餘畀後人。',32,'全唐诗/poet.song.72000.json','["撝鐮霍霍穟紛紛，多謝遺餘畀後人。", "負載歸來對妻子，始知身是太平民。"]'),
('cf735c91-67f9-4674-a025-873aa021f197','次韵呂原明侍講歡喜四絕句 蠶熟','饒節','宋','宋诗','song-poetry','','[]','絲在機頭角未乾，兒孫衣褐眼中完。',32,'全唐诗/poet.song.72000.json','["絲在機頭角未乾，兒孫衣褐眼中完。", "茅簷翁嫗自相壽，飽暖渾家感縣官。"]'),
('a1c8d6cc-8352-482a-b11f-a83df1d53c20','次韵呂原明侍講歡喜四絕句 盜獲','饒節','宋','宋诗','song-poetry','','[]','似聞有盜起空舍，聞說驅除唾手間。',32,'全唐诗/poet.song.72000.json','["似聞有盜起空舍，聞說驅除唾手間。", "枹鼓不驚雞自午，先生閉戶養三關。"]'),
('e349cf7f-1f84-4bc3-96f5-6a8f2d72ad3a','尋梅二首  其一','饒節','宋','宋诗','song-poetry','','[]','聞道香寒犯雪開，駝裘絮帽探春來。',32,'全唐诗/poet.song.72000.json','["聞道香寒犯雪開，駝裘絮帽探春來。", "立春恰在王正朔，次第羣芳不待催。"]'),
('4d4195fd-70b2-434f-bd56-bdf2df0b0f7d','尋梅二首  其二','饒節','宋','宋诗','song-poetry','','[]','樂事何如憂患多，尋梅不厭數經過。',32,'全唐诗/poet.song.72000.json','["樂事何如憂患多，尋梅不厭數經過。", "從今直到楊花盡，終始春風亦幾何。"]'),
('69f7ba3b-448b-4b00-83f2-817e437e78b5','寄曾伯容','饒節','宋','宋诗','song-poetry','','[]','豈是從前蹤跡疏，三年不送一行書。',32,'全唐诗/poet.song.72000.json','["豈是從前蹤跡疏，三年不送一行書。", "襄山儻有陪鄰地，爲問洲中種木奴。"]'),
('000e6573-3535-4317-a3b9-bab567ec9edd','次韵呂居仁共二首 望山','饒節','宋','宋诗','song-poetry','','[]','文章二子東西漢，人物諸何大小山。',32,'全唐诗/poet.song.72000.json','["文章二子東西漢，人物諸何大小山。", "四海有家歸未得，眼看寸碧便怡顔。"]'),
('385b6209-dd59-4ab2-bce6-68eeb885f08c','次韵呂居仁共二首 榴花','饒節','宋','宋诗','song-poetry','','[]','安石榴花作意開，杖藜聊復爲渠來。',32,'全唐诗/poet.song.72000.json','["安石榴花作意開，杖藜聊復爲渠來。", "何人風味更不淺，屐齒崢嶸付綠苔。"]'),
('8568281e-c481-4b8f-8404-3958ea835063','虞姬墓','饒節','宋','宋诗','song-poetry','','[]','風悲月黑楚歌聞，泣下虞兮夜未分。',32,'全唐诗/poet.song.72000.json','["風悲月黑楚歌聞，泣下虞兮夜未分。", "千騎星飛向前死，不知誰爲閉荒墳。"]'),
('1e160e64-39b9-477c-a43c-2ccdfbffe388','霸王城','饒節','宋','宋诗','song-poetry','','[]','百年父老不知兵，楚漢相持尚有營。',32,'全唐诗/poet.song.72000.json','["百年父老不知兵，楚漢相持尚有營。", "日暮牛羊歸虎落，野雞飛過霸王城。"]'),
('79c1ba9f-b929-43b7-a9f4-03776efda72d','病起觀垂絲海棠感慨作二絕句  其一','饒節','宋','宋诗','song-poetry','','[]','遲日暖風逼春事，海棠垂絲轉嬌羞。',32,'全唐诗/poet.song.72000.json','["遲日暖風逼春事，海棠垂絲轉嬌羞。", "分明綽約若處子，桃杏塵凡非此流。"]'),
('1ef2f883-8873-45c5-8f09-5e53765232de','病起觀垂絲海棠感慨作二絕句  其二','饒節','宋','宋诗','song-poetry','','[]','賣花擔上誇桃李，頓使春工不值錢。',32,'全唐诗/poet.song.72000.json','["賣花擔上誇桃李，頓使春工不值錢。", "莫怪海棠不受折，要令笄珥絕凡緣。"]'),
('632ee9c4-9b88-4d98-aff6-843ed2733cc2','用海印和尚韵和吳提刑遊山頌','饒節','宋','宋诗','song-poetry','','[]','白崖老將卧遥岑，苗裔分明祖少林。',64,'全唐诗/poet.song.72000.json','["白崖老將卧遥岑，苗裔分明祖少林。", "遂有樂天來問道，不妨黄蘗爲傳心。", "繩床斜月坐秋晚，石銚寒泉語夜深。", "一枕竹風清未曉，堂堂魚鼓現觀音。"]'),
('404df5ff-eae6-480d-b306-4513a7df89dc','用前韵示謝公定學士','饒節','宋','宋诗','song-poetry','','[]','買金須是識真金，學道先防邪見林。',64,'全唐诗/poet.song.72000.json','["買金須是識真金，學道先防邪見林。", "切忌隨言因作解，直須見色便明心。", "大圓覺海波瀾闊，優鉢羅花根蒂深。", "只者若還親薦得，十方俱現海潮音。"]'),
('1f316870-2311-4ef7-8deb-c0e8a3a326d4','用前韵示官人','饒節','宋','宋诗','song-poetry','','[]','古路玄微難謾尋，古人須要飽叢林。',64,'全唐诗/poet.song.72000.json','["古路玄微難謾尋，古人須要飽叢林。", "待聞牆壁熾然說，方見風幡便是心。", "鼻孔易隨人事去，鬢毛空覺歲華深。", "兒啼女喚君知否，盡是頻伽美妙音。"]'),
('a9d55992-7052-433f-846f-b209c8791ad4','用前韵示同參','饒節','宋','宋诗','song-poetry','','[]','談玄說妙隔千岑，過取諸方荆棘林。',64,'全唐诗/poet.song.72000.json','["談玄說妙隔千岑，過取諸方荆棘林。", "三界有誰教學道，十方無法謾求心。", "老胡生下家先破，達磨西來病轉深。", "却問誰知第一句，恒沙諸佛未知音。"]'),
('6a026eea-eaa9-4dc5-a355-5fa1bf60c42d','答惠海首座五首海乃圓照禪師小師  其一','饒節','宋','宋诗','song-poetry','','[]','鬧市叢邊荆棘侵，旃檀獨秀舊園林。',64,'全唐诗/poet.song.72000.json','["鬧市叢邊荆棘侵，旃檀獨秀舊園林。", "俊駒昔是吾家瑞，老鶴今猶萬里心。", "短笛凄清秋水闊，亂山高下白雲深。", "當年得力分明處，竚聽爐香演一音。"]'),
('f0fc01ba-99b8-47b2-8083-4f64ca9898cb','答惠海首座五首海乃圓照禪師小師  其二','饒節','宋','宋诗','song-poetry','','[]','龍生龍子氣駸駸，拄杖橫擔徧寶林。',64,'全唐诗/poet.song.72000.json','["龍生龍子氣駸駸，拄杖橫擔徧寶林。", "果得雲門函蓋句，肯忘黄蘗老婆心。", "扶疏綠樹西風薄，零落黄花秋意深。", "若問宗風竟誰嗣，請將消息問威音。"]'),
('456527f0-6eaa-41bf-b4a7-b170b0a697b2','答惠海首座五首海乃圓照禪師小師  其三','饒節','宋','宋诗','song-poetry','','[]','莫歎宗師久屈沉，趙州八十尚叢林。',64,'全唐诗/poet.song.72000.json','["莫歎宗師久屈沉，趙州八十尚叢林。", "脚跟點地便無事，鼻孔撩天非有心。", "落筆滿堂嗟敏妙，談玄終日見精深。", "丁寧佛法無多子，三角泥牛演梵音。"]'),
('f80fa8e3-0518-4b0f-a671-2469d82eb529','答惠海首座五首海乃圓照禪師小師  其四','饒節','宋','宋诗','song-poetry','','[]','缾鉢隨緣訪古今，皎如玉樹倚寒林。',64,'全唐诗/poet.song.72000.json','["缾鉢隨緣訪古今，皎如玉樹倚寒林。", "投機不礙多玄辯，寄宿何曾有執心。", "禪板蒲團人已靜，博山沈水觀方深。", "從來大器宜成晚，王國公卿多賞音。"]'),
('274694f1-9410-4bfb-91c2-298625a63ba4','答惠海首座五首海乃圓照禪師小師  其五','饒節','宋','宋诗','song-poetry','','[]','流輩推高不獨今，當年成筍便平林。',64,'全唐诗/poet.song.72000.json','["流輩推高不獨今，當年成筍便平林。", "白雲縱有爲霖意，流水曾無戀影心。", "問道故人歸雨後，供香童子立更深。", "青山不免露頭角，短幅斜封更嗣音。"]'),
('b3e31e9b-47e5-4df0-b00e-e7e5e63ca701','喜官人悟道','饒節','宋','宋诗','song-poetry','','[]','白崖峰頂絕躋攀，到者方知到者難。',64,'全唐诗/poet.song.72000.json','["白崖峰頂絕躋攀，到者方知到者難。", "聞道裴公纔一喏，便從偃老破三關。", "人生有限隨流去，佛法無多掣電間。", "喜見伽陀辨端的，倒騎馿子上幡竿。"]'),
('e821500f-b379-4324-91b4-0417c2f1b32b','閬人蒲君錫提舉參老師悟道唱和四首  其一','饒節','宋','宋诗','song-poetry','','[]','一喏推翻十二峰，三乘四庫當時通。',64,'全唐诗/poet.song.72000.json','["一喏推翻十二峰，三乘四庫當時通。", "自聞百丈下堂句，已破提婆外道宗。", "畫角曉吹深徑雪，寒梅晴放小塘風。", "孤峰頂上他年事，又是籌盈石室中。"]'),
('1e32e7a8-56af-4c46-88fe-f6be2c9fed86','閬人蒲君錫提舉參老師悟道唱和四首  其二','饒節','宋','宋诗','song-poetry','','[]','魔法年來逞獨雄，不令人說悟圓通。',64,'全唐诗/poet.song.72000.json','["魔法年來逞獨雄，不令人說悟圓通。", "儻無上士已親證，爭識吾家是正宗。", "飽腹豈因餐畫餠，開花須是得春風。", "從今同道方相委，九尾烏龜嘯月中。"]'),
('5729e06a-c412-4d8f-9308-387c56d943bd','閬人蒲君錫提舉參老師悟道唱和四首  其三','饒節','宋','宋诗','song-poetry','','[]','東西南北本來同，自有時人礙不通。',64,'全唐诗/poet.song.72000.json','["東西南北本來同，自有時人礙不通。", "了後何妨三藏教，悟來那有五家宗。", "學飛鵰鶚雄吞野，出腹麒麟要弄風。", "到底輸他真鼻孔，癡人空坐黑山中。"]'),
('eb07bf53-88e6-41a3-876a-be85162a54bb','閬人蒲君錫提舉參老師悟道唱和四首  其四','饒節','宋','宋诗','song-poetry','','[]','老胡入草太無窮，直指仙人那一通。',64,'全唐诗/poet.song.72000.json','["老胡入草太無窮，直指仙人那一通。", "今日大顛回吏部，他年李勃嗣歸宗。", "華夷元共一輪月，今古曾無兩樣風。", "從此牧牛真石鞏，肯令信脚犯苗中。"]'),
('a2f18326-33cc-4bd4-a39d-32b1f17e3814','別用韵寄諸同參','饒節','宋','宋诗','song-poetry','','[]','好笑多知一老翁，須言妙用及神通。',64,'全唐诗/poet.song.72000.json','["好笑多知一老翁，須言妙用及神通。", "我無佛說并魔說，誰問南宗與北宗。", "麤飯有時聊飽腹，破衣隨分且遮風。", "他年同道如相過，沙銚煨茶竹葉中。"]'),
('f99ed10b-c8b8-4569-b7fc-b29289efbff7','寄夏均父二首  其一','饒節','宋','宋诗','song-poetry','','[]','好雪春來番更番，思君未說幾時還。',64,'全唐诗/poet.song.72000.json','["好雪春來番更番，思君未說幾時還。", "有心便欲辭彭澤，更懶聊須到魯山。", "酒肉異時相煦濕，功名他日已斕斑。", "故人若問別來事，舉似雲門第二關。"]'),
('f990d182-f2b8-4a65-9fef-7995af8286bb','寄夏均父二首  其二','饒節','宋','宋诗','song-poetry','','[]','四海交情未有君，解衣推食見情真。',64,'全唐诗/poet.song.72000.json','["四海交情未有君，解衣推食見情真。", "平生爛漫如一日，萬里周旋覺更親。", "我已山林新祝髮，君猶州縣故隨人。", "而今官意知何似，早晚歸來洗世塵。"]'),
('77998ffc-3826-4f1b-9877-ece34b3c32d5','海印生日','饒節','宋','宋诗','song-poetry','','[]','優鉢羅花此日開，法王真子異凡材。',64,'全唐诗/poet.song.72000.json','["優鉢羅花此日開，法王真子異凡材。", "平生極力參耆舊，晚歲傾心接後來。", "得意篇章渾簡易，忘情風境自徘徊。", "兒孫只麽酬恩德，倒挽滄溟作壽杯。"]'),
('2453547f-3195-49e4-96a4-2ec46250cdd0','同廣德和尚及諸禪伯遊山有作次其韵','饒節','宋','宋诗','song-poetry','','[]','捫蘿挽石復穿雲，却歎公侯走世塵。',64,'全唐诗/poet.song.72000.json','["捫蘿挽石復穿雲，却歎公侯走世塵。", "碧嶂回眸三界小，紅崖移步百花春。", "長沙只解隨芳草，王老猶難避鬼神。", "不道遊山末後句，瘦藤遥指牧牛人。"]'),
('3b858f82-5027-4f69-9b2b-935c2e2b7092','再次前韵','饒節','宋','宋诗','song-poetry','','[]','芒鞋短杖訪松筠，未許癡禪繼後塵。',64,'全唐诗/poet.song.72000.json','["芒鞋短杖訪松筠，未許癡禪繼後塵。", "碧嶂烟嵐千頃潤，紅崖花草四時春。", "林中儻遇狻猊獸，日下休看舜若神。", "却笑子湖窮鬼子，猶將消息問時人。"]'),
('8d628c35-5c45-494c-b0fb-9d5396b1c9df','次韵答呂居仁','饒節','宋','宋诗','song-poetry','','[]','向來相許濟時功，大似頻婆餉遠空。',64,'全唐诗/poet.song.72000.json','["向來相許濟時功，大似頻婆餉遠空。", "我已定交木上座，君猶求舊管城公。", "文章不療百年老，世事能磨雙頰紅。", "好貸夜窗三十刻，胡床趺坐究幡風。"]'),
('f90d37b1-fdcd-4d80-8dbd-95b43c87e325','再次前韵','饒節','宋','宋诗','song-poetry','','[]','曾將千古較窮通，芥孔能容幾許空。',64,'全唐诗/poet.song.72000.json','["曾將千古較窮通，芥孔能容幾許空。", "借問折腰辭五斗，何如折臂取三公。", "四時但覺風雨過，一飯奚須刀匕紅。", "要識壞魔三昧力，更培根墢待春風。"]'),
('86b98e6b-598f-4f85-b26d-d2a190f5a5e6','吾友汪信民博士近聞參道甚力昨日得書云喪其偶其言耿耿有不釋然者因寄此頌開之且挽其進','饒節','宋','宋诗','song-poetry','','[]','悼亡應作斷腸聲，此恨從來不易平。',64,'全唐诗/poet.song.72000.json','["悼亡應作斷腸聲，此恨從來不易平。", "墮淚要知非轉物，鼓盆政恐未忘情。", "疏親憎愛無非妄，生死存亡但有名。", "著力早須無底鉢，優曇在火更晶明。"]'),
('dcbe6fab-f75f-4bd7-a592-981842b2f511','龜山戲贈諧文章','饒節','宋','宋诗','song-poetry','','[]','水母潭邊窣堵波，下頭有箇老禪和。',64,'全唐诗/poet.song.72000.json','["水母潭邊窣堵波，下頭有箇老禪和。", "蒲鞋舊日曾供母，寶壽平生不渡河。", "衣鉢三千舊風景，形模十二古頭陀。", "是凡是聖人休問，門外寒松卷薜蘿。"]'),
('c2cef846-58b4-4ffe-85c2-6b8e950a7c4b','次韵呂無求入山會宿北窗','饒節','宋','宋诗','song-poetry','','["\u897f\u6e56"]','駐車决遣底匆匆，求宿西湖北面峰。',64,'全唐诗/poet.song.72000.json','["駐車决遣底匆匆，求宿西湖北面峰。", "旋掩竹窗移短榻，徐敲冰甕瀹長松。", "名高政恐爲深累，道大由來自不容。", "顧我與公無二患，孤燈相對兩疏慵。"]'),
('92421bcd-d6f5-431e-8d66-9684a34c3e0a','無求用前韵作雪詩見寄亦次其韵','饒節','宋','宋诗','song-poetry','','[]','一夜花飛殿暮冬，曉驚銀色現前峰。',64,'全唐诗/poet.song.72000.json','["一夜花飛殿暮冬，曉驚銀色現前峰。", "增肥幻質饒冰柱，埋沒虛名歎瓦松。", "素紙不書思雪老，白圭無玷憶南容。", "知君豈乏扁舟興，哦罷新詩興已慵。"]'),
('f8e3e06b-04fb-4930-a034-f1cd00971395','贈靈巖德雲庵主','饒節','宋','宋诗','song-poetry','','[]','道人徧歷五家宗，歸隠林間事事慵。',64,'全唐诗/poet.song.72000.json','["道人徧歷五家宗，歸隠林間事事慵。", "棐几有時吟夜雨，杖藜隨意倚寒松。", "插天戶牖險更險，拔地樓臺重復重。", "借問師庵在何處，巍巍坐斷妙高峰。"]'),
('be8aa122-738e-4626-bda3-a1ed78a74165','德雲庵詩','饒節','宋','宋诗','song-poetry','','[]','巖下虛通上入雲，衆山圍繞一山尊。',64,'全唐诗/poet.song.72000.json','["巖下虛通上入雲，衆山圍繞一山尊。", "德雲只在此峰頂，童子何妨問法門。", "已種穉松三百本，待移蒼竹一千根。", "不須更學藥山老，月下嘯聲驚遠村。"]'),
('e67d90c1-6581-486c-b524-7a4478121330','次韵鑑碧軒','饒節','宋','宋诗','song-poetry','','[]','當軒方鑑碧溶溶，無事道人居此中。',64,'全唐诗/poet.song.72000.json','["當軒方鑑碧溶溶，無事道人居此中。", "弟子來參洗鉢話，朋遊舊識釣魚翁。", "一奩深淥桃花雨，數尺寒漪竹葉風。", "箇處好懷誰共委，俯青飛鳥過晴空。"]'),
('ba0ee516-82d6-419a-911b-c894fbc2b9df','再次前韵','饒節','宋','宋诗','song-poetry','','[]','不待山腰轉籜龍，一函寒碧自深中。',64,'全唐诗/poet.song.72000.json','["不待山腰轉籜龍，一函寒碧自深中。", "未容濠上觀魚客，聊許雙林照影翁。", "雨後蝸牛羣飲月，春餘水馬競追風。", "井蛙海鼈難棲泊，會看長虹下晚空。"]'),
('4db6ac1b-7a9c-442a-9eb6-31e6ed0f2d94','楊梅','饒節','宋','宋诗','song-poetry','','[]','五月楊梅正滿林，初疑一核價千金。',64,'全唐诗/poet.song.72000.json','["五月楊梅正滿林，初疑一核價千金。", "味方河朔蒲桃重，色比瀘南荔子深。", "飛椗似聞新入貢，登盤不見舊供吟。", "詩成欲寄山中舊，恐起頭陀愛渴心。"]'),
('7c14df2f-14b6-4ac7-942d-2ccac9fa3737','次韵','饒節','宋','宋诗','song-poetry','','[]','南山北嶺總成林，野嫗名園獨擅金。',64,'全唐诗/poet.song.72000.json','["南山北嶺總成林，野嫗名園獨擅金。", "實熟每憂風雨橫，根蟠誰念歲華深。", "品題可配荔枝譜，風味能忘莊舄吟。", "食罷蜜脾聊殿後，半鈎新月在房心。"]'),
('14d24d03-2e1f-432d-8069-e019f9887d30','戲乞石菖蒲','饒節','宋','宋诗','song-poetry','','[]','古澗靈苗不易遭，寸根拳石著身牢。',64,'全唐诗/poet.song.72000.json','["古澗靈苗不易遭，寸根拳石著身牢。", "齊如秧稻刺春水，小似神龜負綠毛。", "未與幽人供壽考，曾隨遷客賦離騷。", "阿師垂手入廛去，應許珍奇付我曹。"]'),
('12d07456-6f3a-46c0-a952-4f974d09298e','次韵卿山主梅花','饒節','宋','宋诗','song-poetry','','[]','歲事功成雪洗塵，化工著意製清新。',64,'全唐诗/poet.song.72000.json','["歲事功成雪洗塵，化工著意製清新。", "遂教天下無雙色，來作人間第一春。", "未許調羹傅巖老，聊從牽興杜陵人。", "遥知月下遶千匝，桃李成蹊未是頻。"]'),
('6384c94c-aaae-4505-b772-8c139133ccbd','送廣上人','饒節','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','師住匡廬南面山，飛來峰下略開單。',64,'全唐诗/poet.song.72000.json','["師住匡廬南面山，飛來峰下略開單。", "時情淡薄知音少，吾道彫零行路難。", "何必善書須學衛，未應解義必師安。", "丈夫不用尋塵跡，自向虛空著羽翰。"]'),
('2bed6109-c8f8-4fc9-9993-8678133c4797','再次韵關子開','饒節','宋','宋诗','song-poetry','','[]','我初詿誤輩簪纓，君亦前生失念僧。',64,'全唐诗/poet.song.72000.json','["我初詿誤輩簪纓，君亦前生失念僧。", "得意那知蟻旋磨，反身方悟鼠侵藤。", "高才自合參廊廟，朽質聊須活斗升。", "已破小團盟異日，速來相就鑿春冰。"]'),
('afa564fd-7a49-40b2-9aae-d82ff54ca958','用前韵答呂無求','饒節','宋','宋诗','song-poetry','','[]','聰明强健不聾丞，時出高言欲作僧。',64,'全唐诗/poet.song.72000.json','["聰明强健不聾丞，時出高言欲作僧。", "客至解衣揮玉麈，詩成落筆掃溪藤。", "園如靖節不難去，座比維摩豈易升。", "退食略無聲色累，自磨煤麝寫陽冰。"]'),
('84af1424-95b0-48ec-ae0c-6fb30924ac51','用前韵答湛長老','饒節','宋','宋诗','song-poetry','','[]','阿師歌詠過騰騰，豈是尋常粥飯僧。',64,'全唐诗/poet.song.72000.json','["阿師歌詠過騰騰，豈是尋常粥飯僧。", "自了木平三擔土，何須寂子四揮藤。", "新詩似錦誰能濯，高論如天不可升。", "飯罷關門香一豆，浄琉璃鉢泛輕冰。"]'),
('ef3d1f4f-b449-4cd2-9573-c236d2f5227d','次韵孫嚮仲自靈隠歸餘杭二首  其一','饒節','宋','宋诗','song-poetry','','[]','淡月晴風奏曉凉，春回草木被餘香。',64,'全唐诗/poet.song.72000.json','["淡月晴風奏曉凉，春回草木被餘香。", "溪橋村落牛羊散，竹塢人家桑柘忙。", "大樹稍疑經櫪社，羣雞端恐過尸鄉。", "年來課最何須問，翁媼茅簷話短長。"]'),
('00a3c3e7-541c-43e0-8152-6b66221b7b48','次韵孫嚮仲自靈隠歸餘杭二首  其二','饒節','宋','宋诗','song-poetry','','[]','冷泉亭下漱甘凉，十里猶餘齒頰香。',64,'全唐诗/poet.song.72000.json','["冷泉亭下漱甘凉，十里猶餘齒頰香。", "入境自知風俗厚，到家應覺簿書忙。", "好依名教窮真樂，莫指溫柔是舊鄉。", "此理不疑何用卜，誰論筮短與龜長。"]'),
('6617f80d-526c-4c4c-be31-e367ebca33d2','送以照上人','饒節','宋','宋诗','song-poetry','','[]','三年坐夏飽湖山，夢遶江南身未還。',64,'全唐诗/poet.song.72000.json','["三年坐夏飽湖山，夢遶江南身未還。", "一見道人知妙質，蹔聞鄉語破衰顔。", "朱輪華轂何曾乏，白拂長藤自不閑。", "特立如師世無幾，爲君出戶立潺湲。"]'),
('ca2d5605-f8c6-485c-a535-ee08acb1c9bc','次韵靈隠小軒','饒節','宋','宋诗','song-poetry','','[]','小軒容膝趣清深，只有溪風夜月侵。',64,'全唐诗/poet.song.72000.json','["小軒容膝趣清深，只有溪風夜月侵。", "絡石靜移春後蔓，凌霄危露雨中心。", "松窗舊草秋蛇帖，棐几誰賡雪子吟。", "他日幽人問佳致，茂林修竹似山陰。"]'),
('fd52dbab-0f28-4445-8d8b-3fc34ac305ba','次韵答劉通判二首  其一','饒節','宋','宋诗','song-poetry','','[]','補牢初未益亡羊，始悔出山謀不臧。',64,'全唐诗/poet.song.72000.json','["補牢初未益亡羊，始悔出山謀不臧。", "求志已甘長貿貿，應緣何苦自皇皇。", "曾更世上風濤闊，方悟閑中氣味長。", "富貴如公非我比，春蘭秋菊各馨香。"]'),
('54e9dd1f-c0ad-4776-8800-cd8449438533','次韵答劉通判二首  其二','饒節','宋','宋诗','song-poetry','','[]','何事先生倦世榮，非貪水碧與山青。',64,'全唐诗/poet.song.72000.json','["何事先生倦世榮，非貪水碧與山青。", "乞身高節恐難遂，捷徑浮言固不經。", "聞道金丹能化鶴，豈同腐草止爲螢。", "宰官本是隨緣現，不礙他年叩玉扃。"]'),
('dd7e5fcb-96e5-44bf-b95e-06d8b3291980','晁以道贈楊中立詩有談禪詆毀之語蓋以諷予因用其韵解嘲且開之云','饒節','宋','宋诗','song-poetry','','[]','西來碧眼困津梁，只要教渠識舊鄉。',64,'全唐诗/poet.song.72000.json','["西來碧眼困津梁，只要教渠識舊鄉。", "常恐佛魔相蹂躪，故提邪正爲平章。", "好隨魚化禹門去，莫學蠅鑽窗紙忙。", "誦箒忘苕解成道，可憐楚些漫沉湘。"]'),
('06e8d4ce-0871-407e-bf72-bbb21ac88126','用曾伯容韵贈不愚兄','饒節','宋','宋诗','song-poetry','','[]','叢林隨處便安身，龍象何曾輩六羣。',64,'全唐诗/poet.song.72000.json','["叢林隨處便安身，龍象何曾輩六羣。", "盛德若愚常宴默，佳言如屑間繽紛。", "蒲團石上坐明月，茗椀松間打亂雲。", "無限青山元屬我，而今不免爲中分。"]'),
('5e6c758b-61e5-4661-9f0e-c602edfeade1','贈伯容','饒節','宋','宋诗','song-poetry','','[]','放牛歸馬老將軍，直道從來不黨羣。',64,'全唐诗/poet.song.72000.json','["放牛歸馬老將軍，直道從來不黨羣。", "妙唱揮毫飛衮衮，高談奮麈墮紛紛。", "文章千古陶元亮，筆札平生谷子雲。", "惟有丁寧一大事，頗遭魔罥每瓜分。"]'),
('fae58244-d3b2-4da3-874a-1ad80f82eaba','和不愚兄庵頌三首  其一','饒節','宋','宋诗','song-poetry','','[]','此庵俄壞復俄成，步屧相從了此生。',64,'全唐诗/poet.song.72000.json','["此庵俄壞復俄成，步屧相從了此生。", "鶴不乘軒方自舞，鶑非求友爲誰鳴。", "冬葅弄色應分甕，春薺聞香莫戛鐺。", "月下相尋記低語，松間烏鵲恐飛驚。"]'),
('7681a439-9f33-4c7c-bb50-84b6ca16828a','和不愚兄庵頌三首  其二','饒節','宋','宋诗','song-poetry','','[]','四海歸來坐太平，莫令華雨惱空生。',64,'全唐诗/poet.song.72000.json','["四海歸來坐太平，莫令華雨惱空生。", "歸雲無事朝猶卷，老馬休心夜不鳴。", "勝處林泉九節杖，閑中日月二升鐺。", "曉來乞火打庵戶，想見春風一夢驚。"]'),
('f3466ae0-d893-4cd2-82de-49d16bef2c82','和不愚兄庵頌三首  其三','饒節','宋','宋诗','song-poetry','','[]','常恨山居寡弟兄，阿師庵就可憐生。',64,'全唐诗/poet.song.72000.json','["常恨山居寡弟兄，阿師庵就可憐生。", "輔車豈但圖相倚，獨掌從來不浪鳴。", "野老獻謀脩水磑，山童相喚借茶鐺。", "年來活計渾成就，猿鶴安棲定不驚。"]'),
('0121b968-a181-4fbf-9438-ca92d250edcd','用朱元方韵寄深明郎中二首  其一','饒節','宋','宋诗','song-poetry','','[]','當時冠蓋集祇園，大似農夫值有年。',64,'全唐诗/poet.song.72000.json','["當時冠蓋集祇園，大似農夫值有年。", "龐老一言投馬祖，陸侯徹底見南泉。", "古今已自融三際，語默何曾落二邊。", "父子並爲同社客，團欒應話老婆禪。"]'),
('acd520ed-3e50-42dd-b1ad-eee63220a016','用朱元方韵寄深明郎中二首  其二','饒節','宋','宋诗','song-poetry','','[]','剎那念念轉光陰，已過方來不住今。',64,'全唐诗/poet.song.72000.json','["剎那念念轉光陰，已過方來不住今。", "身似虛舟從不繫，魔如敵國謾相侵。", "未能以幻還脩幻，豈暇將心更用心。", "以說爲宗遍天下，思公一笑白雲深。"]'),
('4ea418eb-b26c-4730-8a81-ea5a921f8d9b','送曾伯容還漢上','饒節','宋','宋诗','song-poetry','','[]','軋軋籃輿來者誰，朝廷遺此一男兒。',64,'全唐诗/poet.song.72000.json','["軋軋籃輿來者誰，朝廷遺此一男兒。", "襟懷朗朗百間屋，局量汪汪萬頃陂。", "異日小生端欲吏，邇來至德益堪師。", "贈行一句西來意，雨後春江淥渺瀰。"]'),
('fd270ede-7377-4637-b22f-f70bb2fdd27d','次韵鏡上人三首  其一','饒節','宋','宋诗','song-poetry','','[]','妙處從來自不傳，少時喜樂似初禪。',64,'全唐诗/poet.song.72000.json','["妙處從來自不傳，少時喜樂似初禪。", "爲山何止不成簣，掘井于今未及泉。", "自了一生同作夢，頻麾萬事付蒼烟。", "因師聊作逢場戲，老馬爲駒不受鞭。"]'),
('05adb831-1c18-4905-8ec5-d5e0a14a6a75','次韵鏡上人三首  其二','饒節','宋','宋诗','song-poetry','','[]','色聲香味心緣觸，忍進戶檀般若禪。',64,'全唐诗/poet.song.72000.json','["色聲香味心緣觸，忍進戶檀般若禪。", "但識曹溪一滴味，始知天下別無泉。", "乳衣百澣猶聞氣，城郭非遥早見烟。", "到底輸他真定力，暮途快馬亦須鞭。"]'),
('e88b44a9-c498-49fa-83e1-6f5065bf8b3e','次韵鏡上人三首  其三','饒節','宋','宋诗','song-poetry','','[]','相見無言意已傳，不談名利不談禪。',64,'全唐诗/poet.song.72000.json','["相見無言意已傳，不談名利不談禪。", "靜如秋浦翹雙鶴，清似寒巖落瀑泉。", "隠逸妄人居妙室，功名渠輩畫凌烟。", "二流淼淼追難及，老大難揮馬腹鞭。"]'),
('ea2d5b0f-8ad3-43da-a0bb-666553a2a090','改德士頌五首  其一','饒節','宋','宋诗','song-poetry','','[]','自知祝髮非華我，故欲毀形從道人。',32,'全唐诗/poet.song.72000.json','["自知祝髮非華我，故欲毀形從道人。", "聖主如天苦憐憫，復令加我舊冠巾。"]'),
('94e969fb-8764-4a13-9789-f27d25ef4791','改德士頌五首  其二','饒節','宋','宋诗','song-poetry','','[]','舊說螟蛉逢蜾蠃，異時胡蝶夢莊周。',32,'全唐诗/poet.song.72000.json','["舊說螟蛉逢蜾蠃，異時胡蝶夢莊周。", "世間物化渾如夢，夢裏惺惺却自由。"]'),
('cc8998a7-c68b-4fe9-9e66-57c04ba8ac20','改德士頌五首  其三','饒節','宋','宋诗','song-poetry','','[]','德士舊嘗稱進士，黄冠初不異儒冠。',32,'全唐诗/poet.song.72000.json','["德士舊嘗稱進士，黄冠初不異儒冠。", "種種是名名是假，世人誰不被名謾。"]'),
('039403a5-40d1-4d25-9809-7d88d6fef9fa','改德士頌五首  其四','饒節','宋','宋诗','song-poetry','','[]','衲子紛紛惱不禁，倚松傳與法安心。',32,'全唐诗/poet.song.72000.json','["衲子紛紛惱不禁，倚松傳與法安心。", "缾盤釵釧形雖異，還我從來一色金。"]'),
('49419f1f-68cb-4635-9948-1e7bc33d73be','改德士頌五首  其五','饒節','宋','宋诗','song-poetry','','[]','少年曾著書生帽，老大當簪德士冠。',32,'全唐诗/poet.song.72000.json','["少年曾著書生帽，老大當簪德士冠。", "此身無我亦無物，三教空名何處安。"]'),
('b08013c7-cb03-4232-b316-de3b3c27cdde','法門復故聖恩深厚矣自此恐雲巢不能久栖當爲衆一起承示佳句因用韵備載之','饒節','宋','宋诗','song-poetry','','[]','佛日光芒忽再懸，歡呼萬國戴堯天。',64,'全唐诗/poet.song.72000.json','["佛日光芒忽再懸，歡呼萬國戴堯天。", "不須菩薩行求鉢，自是如來許覆肩。", "雲漢飛騰新放鶴，江湖遊泳不烹鮮。", "雲巢從此棲難穩，珪玉今逢豐富年。"]'),
('044fd68e-8faf-406f-9174-a9d3051d4751','不愚兄再示佳句如璧亦重用來韵','饒節','宋','宋诗','song-poetry','','[]','聖慈何事輒翻然，日月從來本麗天。',64,'全唐诗/poet.song.72000.json','["聖慈何事輒翻然，日月從來本麗天。", "食座千冠□掃跡，禪堂百衲便差肩。", "朝三暮四渾堪笑，秋菊春蘭豈鬭鮮。", "但得時和湯餠足，不材從此盡天年。"]'),
('cce24b11-ee39-497b-9f33-a3b9aae906e2','比復僧相不愚戲作三頌恐傍觀以謂吾徒實有喜慍故復次來韵不免道破兼寄祖禹同參道人','饒節','宋','宋诗','song-poetry','','[]','聖主生知本解禪，故教勘破普周天。',64,'全唐诗/poet.song.72000.json','["聖主生知本解禪，故教勘破普周天。", "一原大似東西水，同體何殊左右肩。", "把定絲毫渾沮喪，放開頃刻便芳鮮。", "衲僧敗闕知多少，且笑髯舒三十年。"]'),
('9a1302ed-0def-4a90-93b5-583d8e24a9c8','再次韵且召遊山','饒節','宋','宋诗','song-poetry','','[]','勞生擾擾苦推遷，擬疏行藏細問天。',64,'全唐诗/poet.song.72000.json','["勞生擾擾苦推遷，擬疏行藏細問天。", "壯歲同尊曲阜履，老來幾拍洪崖肩。", "自聞新澤春雷動，喜見清詩蜀錦鮮。", "莫怪招呼玩花草，要回皓首作丁年。"]'),
('6885ebae-6caa-4e8b-8568-63eca6489858','適承再示佳句亦强勉再成一首','饒節','宋','宋诗','song-poetry','','[]','擺落紅塵罷作緣，從渠早晚離西天。',64,'全唐诗/poet.song.72000.json','["擺落紅塵罷作緣，從渠早晚離西天。", "何妨展軸卧翹足，未暇隨人笑脅肩。", "但許南泉到癡鈍，莫依投子覓新鮮。", "佛魔一掃雙無用，陋矣莊生大小年。"]'),
('b9c9765b-2094-47ad-a7bc-2d44d7c1a4e9','昨日一詩乃是見贈亦復次韵爲報','饒節','宋','宋诗','song-poetry','','[]','阿師卧處白雲連，几外千峰秀接天。',64,'全唐诗/poet.song.72000.json','["阿師卧處白雲連，几外千峰秀接天。", "漸畏聲名收虎視，何嘗骨相露鳶肩。", "雄風高論鷁飛退，皓雪新詩鶴奪鮮。", "老眼熨摩今有待，徵書同到起延年。"]'),
('70b505a6-d190-4ebe-940b-4548448f75e8','復用韵成一首特作狡猾爾勿誚吾作夢也想當一笑','饒節','宋','宋诗','song-poetry','','[]','憶昔兒曹氣尚全，逢人箕踞輒談天。',64,'全唐诗/poet.song.72000.json','["憶昔兒曹氣尚全，逢人箕踞輒談天。", "攝衣便欲探龍頷，唾手何辭舉彘肩。", "自免敝冠歸落寞，便磨餘墨壞華鮮。", "如今事事皆慵退，大似黄楊厄閏年。"]'),
('83409701-0594-4595-bde4-129e1de5a147','復用韵自詠倚松一首','饒節','宋','宋诗','song-poetry','','[]','庵外無人誰過前，老松千丈獨參天。',64,'全唐诗/poet.song.72000.json','["庵外無人誰過前，老松千丈獨參天。", "煮茶春水漸過膝，却虎短牆纔及肩。", "已退晚雲歸浩浩，未分芽菊競鮮鮮。", "客來問我何時住，笑指松枝數歲年。"]'),
('344730ac-b931-4787-b94b-35b01bda6194','昨日承佳贈浮實甚矣謹再用韵酬贈','饒節','宋','宋诗','song-poetry','','[]','嘗徧諸方五味禪，不須鼻孔便撩天。',64,'全唐诗/poet.song.72000.json','["嘗徧諸方五味禪，不須鼻孔便撩天。", "自應猊座長垂手，只許巢雲暫息肩。", "世外豈無羊氏鶴，人間多滯禹門鮮。", "便當勉爲衆生起，趁取靈芝三秀年。"]'),
('ae071030-c43f-476e-aa36-90d217ad8cb0','復用前韵寄伯容兼其三子','饒節','宋','宋诗','song-poetry','','[]','高閣巍臨漢水邊，從來談舌自摩天。',64,'全唐诗/poet.song.72000.json','["高閣巍臨漢水邊，從來談舌自摩天。", "華公不用徒辭位，噲等何堪復比肩。", "他日屢藏閭里骨，而今時縱校人鮮。", "龐公父子皆知道，試問王家三少年。"]'),
('197719b9-ec01-44bc-860f-23d2bd637c43','再用韵戲作二庵圖','饒節','宋','宋诗','song-poetry','','[]','人說雙庵鶻壁巔，妙高峰頂四禪天。',64,'全唐诗/poet.song.72000.json','["人說雙庵鶻壁巔，妙高峰頂四禪天。", "夢魂似亦曾招手，千里猶堪論比肩。", "淥水白雲同一妙，蒼松翠竹自相鮮。", "誰能爲作虎頭畫，傳與人間五百年。"]'),
('9edd45e1-647d-4af4-b6fc-b3d43fbf32c5','不愚兄示上元佳句謹次韵爲笑','饒節','宋','宋诗','song-poetry','','[]','溪雲釀雪展還收，數日春嚴罷出遊。',64,'全唐诗/poet.song.72000.json','["溪雲釀雪展還收，數日春嚴罷出遊。", "月竹蕭蕭香轉座，缾湯隠隠被蒙頭。", "一燈聊破上元夢，半夜稍增塗足油。", "說妙談玄吾不會，從教高挂雪峰毬。"]'),
('e3c3bf82-8b58-4b28-be1a-3ed236936490','再次前韵','饒節','宋','宋诗','song-poetry','','[]','佳節山家事事休，一菴容膝自優游。',64,'全唐诗/poet.song.72000.json','["佳節山家事事休，一菴容膝自優游。", "殘梅韵勝窺籬落，滿月光寒上隴頭。", "不待玄沙行乞火，何須投子更携油。", "夜深自倚蒲團困，誰問渠儂馬打毬。"]'),
('31b1c111-914a-4630-97c4-d3b79c19b5f9','再用韵戲紀山中之勝','饒節','宋','宋诗','song-poetry','','[]','人既無心境自幽，問渠何事世間遊。',64,'全唐诗/poet.song.72000.json','["人既無心境自幽，問渠何事世間遊。", "連雲自種蘭千本，带雪新栽橘數頭。", "已架酴醾連外戶，便留薝蔔壓香油。", "明年不怕春寒重，收拾東風柳絮毬。"]'),
('d71b1f75-092d-4e3f-bf04-9b6e800d3862','用韵奉贈巢雲兄','饒節','宋','宋诗','song-poetry','','[]','南有雪峰北趙州，橫擔拄杖徧曾遊。',64,'全唐诗/poet.song.72000.json','["南有雪峰北趙州，橫擔拄杖徧曾遊。", "四方叢席鬧如市，幾箇衲僧真到頭。", "萬里山川困行李，三冬文史費膏油。", "何如了事巢雲老，解打湍流水上毬。"]'),
('c8d9a0ee-c05c-4c5e-9dd3-3d3daec07bf4','老懶一首亦次元韵','饒節','宋','宋诗','song-poetry','','[]','枕石眠雲漱碧流，胸中元自有天游。',64,'全唐诗/poet.song.72000.json','["枕石眠雲漱碧流，胸中元自有天游。", "莊生達士方疑夢，演若狂夫正怖頭。", "未了色空魚畏絖，不忘念慧鉢持油。", "老夫無此閑家具，一任年華若轉毬。"]'),
('41507a16-ddff-4ece-8c5c-1d0ef75158fd','均父約去年十月還襄陽今已二月矣尚未聞漢上消息因誦舊寄渠詩二首用其韵寄之  其一','饒節','宋','宋诗','song-poetry','','[]','聞道祁陽已賜環，春來何事未言還。',64,'全唐诗/poet.song.72000.json','["聞道祁陽已賜環，春來何事未言還。", "移書漢上二三友，寄夢湖南千萬山。", "顧我幸緣樗散老，知儂真坐虎文斑。", "歸來此度心應死，不待丸泥封漢關。"]'),
('f9f243f9-e740-4d9b-b2ac-0075ea6f7b06','均父約去年十月還襄陽今已二月矣尚未聞漢上消息因誦舊寄渠詩二首用其韵寄之  其二','饒節','宋','宋诗','song-poetry','','[]','歸期小雪已中春，常恐傳言遠未真。',64,'全唐诗/poet.song.72000.json','["歸期小雪已中春，常恐傳言遠未真。", "慎莫錙銖論得喪，政須平等視冤親。", "懸知江海山林士，不中功名富貴人。", "聞道扁舟期訪我，來時莫带庾公塵。"]'),
('0fb82146-2404-48b6-a135-1b417313b21f','次韵趙承之殿撰二首  其一','饒節','宋','宋诗','song-poetry','','[]','第一流中能幾人，瑶林瓊樹恐無鄰。',64,'全唐诗/poet.song.72000.json','["第一流中能幾人，瑶林瓊樹恐無鄰。", "恬遊事外緣聞道，憂到眉端止爲民。", "出處不譁渾入妙，文章無意自通神。", "頭青面雪關渠事，要作菖蒲几研春。"]'),
('25d72894-3383-440d-80e4-76f9b354eaf8','次韵趙承之殿撰二首  其二','饒節','宋','宋诗','song-poetry','','[]','晚辭富貴功名士，竟作東西南北人。',64,'全唐诗/poet.song.72000.json','["晚辭富貴功名士，竟作東西南北人。", "早歲衣冠如昨夢，平生筆墨累閑身。", "時情尺水翻千丈，世故秋毫寓一塵。", "自有使君天上士，新詩揮掃喚人頻。"]'),
('c0e3fcab-b1cd-4cb0-8b2d-b848591cd2e0','田熙載比失解留詩別承之殿撰承之用其韵以寵其行如璧亦次其韵','饒節','宋','宋诗','song-poetry','','[]','田侯藴藉絕凡塵，常苦冥冥天勝人。',64,'全唐诗/poet.song.72000.json','["田侯藴藉絕凡塵，常苦冥冥天勝人。", "可但淵源深孔孟，更無學術略儀秦。", "且尋耒耨聊餬口，未置文章便穩身。", "幸有使君敦眷舊，轉令名字落簪紳。"]'),
('3bfdcd3c-6c01-40ca-813f-c22ed3829459','捫蝨新籬','饒節','宋','宋诗','song-poetry','','[]','甕牖近山巔，人言闕短垣。',48,'全唐诗/poet.song.72000.json','["甕牖近山巔，人言闕短垣。", "聊須安虎落，未免伐龍孫。", "留路依松罅，埋椿避石根。", "從今有來客，道得始開門。"]'),
('3d9c5d3f-663c-4bb0-80f4-8ad867f106da','次韵湛老菖蒲二首  其一','饒節','宋','宋诗','song-poetry','','[]','溪淥渠無數，窗奩此獨幽。',48,'全唐诗/poet.song.72000.json','["溪淥渠無數，窗奩此獨幽。", "蘋繁惟祭祀，楊柳謾風流。", "根抱千年老，苗舒一寸柔。", "內剛還外順，不對道人羞。"]'),
('a52c4b5a-7495-4171-9970-de76bdbe2778','次韵湛老菖蒲二首  其二','饒節','宋','宋诗','song-poetry','','[]','永辭寒澗密，來作寶坊幽。',48,'全唐诗/poet.song.72000.json','["永辭寒澗密，來作寶坊幽。", "著脚非危石，退身曾急流。", "江蘆强剛愎，野蔓太優柔。", "會有仙人食，王公未敢羞。"]'),
('e996cf2f-fc28-45f1-bdf0-5fee32cc1add','劉仲高儀曹左顧林下重話十年之別作詩見贈次韵','饒節','宋','宋诗','song-poetry','','[]','下馬疑高韵，披襟記舊游。',48,'全唐诗/poet.song.72000.json','["下馬疑高韵，披襟記舊游。", "從頭推故跡，屈指盡名流。", "安否何勞問，行藏不用籌。", "夜闌重換燭，羣吏且前休。"]'),
('021529e0-e08a-4f97-957e-3ddaf3fd9af4','再次韵','饒節','宋','宋诗','song-poetry','','[]','四海班揚譽，平生支許游。',48,'全唐诗/poet.song.72000.json','["四海班揚譽，平生支許游。", "芝蘭端秀潤，楊柳未風流。", "異日玉堂草，何年石室籌。", "願公隨處用，擇地豈真休。"]'),
('2fd4f625-db22-45f7-9e3f-629db6f9f329','山居雜頌七首  其一','饒節','宋','宋诗','song-poetry','','[]','幾被儒冠誤此身，偶然隨分作閑人。',32,'全唐诗/poet.song.72000.json','["幾被儒冠誤此身，偶然隨分作閑人。", "二時粥飯隨堂飽，長短高低一任君。"]'),
('ce13a433-b336-4e9f-a6b0-30cb071af9f3','山居雜頌七首  其二','饒節','宋','宋诗','song-poetry','','[]','石楠子熟雪微乾，曾向人家畫裏看。',32,'全唐诗/poet.song.72000.json','["石楠子熟雪微乾，曾向人家畫裏看。", "覿面似君君未領，問君何處有遮欄。"]'),
('bff15bb4-6b7f-41c4-b475-82caeddf6b1f','山居雜頌七首  其三','饒節','宋','宋诗','song-poetry','','[]','禪堂茶退卷殘經，竹杖芒鞋信脚行。',32,'全唐诗/poet.song.72000.json','["禪堂茶退卷殘經，竹杖芒鞋信脚行。", "山盡路回人跡絕，竹雞時作兩三聲。"]'),
('87b94385-a50f-4d91-b792-67a876b99d49','山居雜頌七首  其四','饒節','宋','宋诗','song-poetry','','[]','溪邊小立聽溪聲，日到溪心衮衮明。',32,'全唐诗/poet.song.72000.json','["溪邊小立聽溪聲，日到溪心衮衮明。", "獨木自橫人不渡，隔溪黄犢轉頭鳴。"]'),
