('579f03e9-d543-4fcf-82ce-607d3fd1ed91','寄呂善叔主簿','饒節','宋','宋诗','song-poetry','','[]','倚松卧病山林下，每荷明公特見憐。',32,'全唐诗/poet.song.73000.json','["倚松卧病山林下，每荷明公特見憐。", "但得此身常受供，不妨明月在秋天。"]'),
('fbb53716-d8f9-40b6-9270-36b69275d7b8','贈善公華嚴法師','饒節','宋','宋诗','song-poetry','','[]','京國馳名四十年，華嚴說罷復談禪。',32,'全唐诗/poet.song.73000.json','["京國馳名四十年，華嚴說罷復談禪。", "夜來一昔真懺悔，果然明月在秋天。"]'),
('0e116c97-37af-4333-a5f3-e192f7236267','贈呂無求縣丞約遊嵩少','饒節','宋','宋诗','song-poetry','','[]','白葛烏紗松徑遥，溪聲激激雨蕭蕭。',64,'全唐诗/poet.song.73000.json','["白葛烏紗松徑遥，溪聲激激雨蕭蕭。", "樂山樂水自仁智，爭利爭名渠市朝。", "今日不須沽酒引，他年豈待作詩招。", "懸知三十六峰下，祗麽相尋共寂寥。"]'),
('55d0df73-0e64-402c-bda5-6cc1f3c4e737','贈毛雍玉縣丞謝到山中','饒節','宋','宋诗','song-poetry','','[]','何事凌寒带曉暾，高才不肯簿書昏。',64,'全唐诗/poet.song.73000.json','["何事凌寒带曉暾，高才不肯簿書昏。", "別峰小寺已鳴磬，夾道短籬猶閉門。", "雨後松枝渾黛綠，凍餘泉竇尚春溫。", "聊將二物方君德，富貴功名不足論。"]'),
('47638a8b-1e02-4abe-a8a9-a47d6c302ece','答呂居士寄詩','饒節','宋','宋诗','song-poetry','','[]','長憶吟詩對短檠，詩成重改又雞鳴。',32,'全唐诗/poet.song.73000.json','["長憶吟詩對短檠，詩成重改又雞鳴。", "如今老矣無心力，口誦君詩繞竹行。"]'),
('313914e9-0877-480c-aee0-45fb396faef0','題骨觀畫','饒節','宋','宋诗','song-poetry','','[]','白骨纖纖巧畫眉，髑髏楚楚被羅衣。',32,'全唐诗/poet.song.73000.json','["白骨纖纖巧畫眉，髑髏楚楚被羅衣。", "手持紈扇空相對，笑殺傍觀自不知。"]'),
('389a85e4-d38b-4130-8605-e582fbc9d6f6','春','饒節','宋','宋诗','song-poetry','','[]','盡道春多雨，傷摧花鳥空。',24,'全唐诗/poet.song.73000.json','["盡道春多雨，傷摧花鳥空。", "不知春態度，尤在綠蔭中。"]'),
('f0a5739e-a99a-4ac7-bae5-8561c579d8b0','紅梅','饒節','宋','宋诗','song-poetry','','[]','嬌朱淺淺透冰光，瘦倚疏篁半出牆。',64,'全唐诗/poet.song.73000.json','["嬌朱淺淺透冰光，瘦倚疏篁半出牆。", "雅有風情勝桃杏，巧含春思避冰霜。", "融明醉臉籠輕暈，斂掩仙裙蹙嫩黄。", "日暮風英墮行袂，依稀如著領巾香。"]'),
('1562c3db-18de-4af9-8f5a-0509bf73a0ac','偈','饒節','宋','宋诗','song-poetry','','[]','剝剝剝，裏面有蟲外面啄。',40,'全唐诗/poet.song.73000.json','["剝剝剝，裏面有蟲外面啄。", "多少茫茫瞌睡人，頂後一錐猶未覺。", "若不覺，更聽山僧剝剝剝。"]'),
('d34de51b-68e1-4497-8b31-761b83e90b32','贈陳成季','饒節','宋','宋诗','song-poetry','','[]','兩公待我以國士，是時公亦同在門。',32,'全唐诗/poet.song.73000.json','["兩公待我以國士，是時公亦同在門。", "今日江頭看使節，令人泪溼漢江雲。"]'),
('e48ff40c-a672-4658-8e6b-420adce99ad1','寄謝無逸','饒節','宋','宋诗','song-poetry','','[]','雲山低處堪投老，文史他年不療窮。',32,'全唐诗/poet.song.73000.json','["雲山低處堪投老，文史他年不療窮。", "富貴可求吾亦嬾，眼看餘了化王公。"]'),
('9cb86644-c778-4bff-b615-133bdbafcd66','佛米贊','饒節','宋','宋诗','song-poetry','','[]','時平主聖，萬國自靖。',100,'全唐诗/poet.song.73000.json','["時平主聖，萬國自靖。", "不殺而成，不征而正。", "矯矯虎臣，無所用命。", "移將東南，介我佛會。", "久聞吾曹，念佛三昧。", "喑嗚叱咤，化爲佛聲。", "三令五申，易爲佛名。", "一佛一米，爲米三升。", "自升而斗，自斗而斛。", "念之無窮，太倉不足。"]'),
('2244c905-0d8d-4f02-ab5d-3386e4669fce','句  其一','饒節','宋','宋诗','song-poetry','','[]','閒携經卷倚松立，試問客從何處來。',16,'全唐诗/poet.song.73000.json','["閒携經卷倚松立，試問客從何處來。"]'),
('d7e7d67d-9cf5-451f-8cb8-e3d82262b247','句  其二','饒節','宋','宋诗','song-poetry','','[]','政須送與王摩詰。',8,'全唐诗/poet.song.73000.json','["政須送與王摩詰。"]'),
('dea63b58-ea85-4be3-b5b1-451abc815360','頌','詹榮','宋','宋诗','song-poetry','','[]','木魚原來無肚腸，聲聲喚我出鑊湯。',32,'全唐诗/poet.song.73000.json','["木魚原來無肚腸，聲聲喚我出鑊湯。", "佛法原來無多子，王婆頭上戴丁香。"]'),
('54b6e863-3ad3-424d-b309-f2a970fe8d1e','岐王宮侍兒落髮爲尼','張叔夜','宋','宋诗','song-poetry','','[]','六尺輕羅染麴塵，金蓮步穩襯湘裙。',32,'全唐诗/poet.song.73000.json','["六尺輕羅染麴塵，金蓮步穩襯湘裙。", "從今不入襄王夢，剪盡巫山一朵雲。"]'),
('02cbe7e5-f9ec-4dec-8ed6-1528be176f7d','寄題靖安呂延平釣臺','張叔夜','宋','宋诗','song-poetry','','[]','豫章富人物，歷數煩僂指。',84,'全唐诗/poet.song.73000.json','["豫章富人物，歷數煩僂指。", "先生釣璜孫，盛德邈相似。", "却顧徐洪輩，瑣瑣詎足記。", "修竹照清漪，邂逅聊復爾。", "吾君邁周文，未省獵渭水。", "矧此江之湄，相距數千里。", "會遇偶有時，必爲蒼生起。"]'),
('b530b3dc-1b88-4e5f-8b15-8105c81f162e','句','馮澥','宋','宋诗','song-poetry','','[]','臘腊批紅玉，霜梨割紫金。',12,'全唐诗/poet.song.73000.json','["臘腊批紅玉，霜梨割紫金。"]'),
('145cb394-d58f-4713-8769-75862d4e14f7','挽張總管叔夜','董俊','宋','宋诗','song-poetry','','[]','南道勤王仗壯猷，襄陽果幸尚無憂。',32,'全唐诗/poet.song.73000.json','["南道勤王仗壯猷，襄陽果幸尚無憂。", "可憐一具英雄骨，不扈君王過白溝。"]'),
('81be133f-bb9e-4e24-829c-ab75fc56a348','清江曲  其一','蘇庠','宋','宋诗','song-poetry','','[]','屬玉雙飛水滿塘，菰蒲深處浴鴛鴦。',32,'全唐诗/poet.song.73000.json','["屬玉雙飛水滿塘，菰蒲深處浴鴛鴦。", "白蘋滿棹歸來晚，秋著蘆花一岸霜。"]'),
('0cba6bc7-98b6-417f-bce4-fa25f3a1c642','清江曲  其二','蘇庠','宋','宋诗','song-poetry','','[]','扁舟繫岸依林樾，蕭蕭兩鬢吹華髮。',32,'全唐诗/poet.song.73000.json','["扁舟繫岸依林樾，蕭蕭兩鬢吹華髮。", "萬事不理醉復醒，長占烟波弄明月。"]'),
('3ffd454d-2e35-4e48-a0c2-b6918d626dee','後清江曲  其一','蘇庠','宋','宋诗','song-poetry','','[]','層波渺渺山蒼蒼，輕霜隕木蓮葉黄。',32,'全唐诗/poet.song.73000.json','["層波渺渺山蒼蒼，輕霜隕木蓮葉黄。", "呼兒極浦下笭箵，社甕欲熟浮蛆香。"]'),
('bc463fe2-5a74-40fd-adc3-d2c2fb8797a6','後清江曲  其二','蘇庠','宋','宋诗','song-poetry','','[]','輕蓑淅瀝鳴秋雨，日暮乘流自相語。',32,'全唐诗/poet.song.73000.json','["輕蓑淅瀝鳴秋雨，日暮乘流自相語。", "一笛清風萬事休，白鳥翩翩落烟渚。"]'),
('3a5b8fa8-0d74-4a75-a2a3-9222fcede31d','臞庵','蘇庠','宋','宋诗','song-poetry','','[]','王郎臞庵摩詰詩，烟花遶舍江遶籬。',64,'全唐诗/poet.song.73000.json','["王郎臞庵摩詰詩，烟花遶舍江遶籬。", "石渠東觀了無夢，筆床茶竈行相期。", "古人已往不可作，甫里顧有今天隨。", "灣頭蟹舍豈著我，請具蓑笠懸牛衣。"]'),
('e40de758-9b93-4af3-9637-08845f7e9f38','草堂','蘇庠','宋','宋诗','song-poetry','','[]','笛弄松江明月，蓑披笠澤歸雲。',28,'全唐诗/poet.song.73000.json','["笛弄松江明月，蓑披笠澤歸雲。", "若話青霄快活，五侯何處如君。"]'),
('67a32ac8-9ee3-40f5-93ac-897565d4f2a6','浮天閣  其一','蘇庠','宋','宋诗','song-poetry','','[]','臞庵主人天與閑，回欄飛閣臨滄灣。',64,'全唐诗/poet.song.73000.json','["臞庵主人天與閑，回欄飛閣臨滄灣。", "晴波渺渺雁行落，坐見萬頃穿雲還。", "百年有底付鳥翼，未暇著脚鴛鸞間。", "徑須呼酒澆磈磊，莫遣暝色霾烟鬟。"]'),
('ceae9cb0-f66c-4c29-88be-d7a3a3c05b4d','浮天閣  其二','蘇庠','宋','宋诗','song-poetry','','[]','玉蟾飛入水晶宮，萬頃琉璃碎晚風。',32,'全唐诗/poet.song.73000.json','["玉蟾飛入水晶宮，萬頃琉璃碎晚風。", "詩就雲歸不知處，斷山零落有無中。"]'),
('af87633c-1391-4346-add0-34dffdf4a828','浮天閣  其三','蘇庠','宋','宋诗','song-poetry','','[]','秋落空江動碧虛，黄蘆洲渚雁飛初。',32,'全唐诗/poet.song.73000.json','["秋落空江動碧虛，黄蘆洲渚雁飛初。", "我來欲訪鴟夷子，爲掛西風十幅蒲。"]'),
('cf0f2e7b-fa07-4f32-b1b4-e9917c5a75f9','平遠堂  其一','蘇庠','宋','宋诗','song-poetry','','[]','柳外西風六幅蒲，野塘睡鴨對舂鉏。',32,'全唐诗/poet.song.73000.json','["柳外西風六幅蒲，野塘睡鴨對舂鉏。", "如何喚得王摩詰，畫作江南烟雨圖。"]'),
('74c5e52a-1692-4278-8d45-2130c3ac22c0','平遠堂  其二','蘇庠','宋','宋诗','song-poetry','','[]','寒蘆淅淅催秋晚，浦雨溟溟憶去年。',32,'全唐诗/poet.song.73000.json','["寒蘆淅淅催秋晚，浦雨溟溟憶去年。", "它日未埋黄土陌，爲君重賦補亡篇。"]'),
('53164ee8-4430-4aed-8857-71c2ab93a1bb','送舉書記歸天台','蘇庠','宋','宋诗','song-poetry','','[]','卷衲下蒼壁，夜光容暗投。',48,'全唐诗/poet.song.73000.json','["卷衲下蒼壁，夜光容暗投。", "人追道林輩，詩入杼山流。", "風吹蒹葭雨，雁橫江漢秋。", "須煩紫籐杖，聊與白雲留。"]'),
('8338ddcc-9b74-4338-8552-e6d2bb12becc','送天台則上人還浙東','蘇庠','宋','宋诗','song-poetry','','[]','溪南溪北鳥啼處，樹頭樹底梅已空。',32,'全唐诗/poet.song.73000.json','["溪南溪北鳥啼處，樹頭樹底梅已空。", "絕歎不如木上座，伴君千疊夕嵐中。"]'),
('0b3512f7-6e8d-4dc6-ac78-27d049d19893','送天台珪上人','蘇庠','宋','宋诗','song-poetry','','[]','雨暗蒹葭浦，烟青楊柳津。',48,'全唐诗/poet.song.73000.json','["雨暗蒹葭浦，烟青楊柳津。", "有勞修月手，來訪卧雲人。", "落筆向來事，無錐今歲貧。", "故山何處是，落日大江濱。"]'),
('77726d52-67ee-4a26-badf-bf6e10b49787','送呂山友遊天台','蘇庠','宋','宋诗','song-poetry','','[]','床頭蘿月厭同攀，發興東吳萬疊間。',64,'全唐诗/poet.song.73000.json','["床頭蘿月厭同攀，發興東吳萬疊間。", "森木已深溪上屋，瘦藤穿盡雨餘山。", "黄梅綠李看來熟，長簟北窗誰與閒。", "此別故應頻作惡，一樽何日慰勤艱。"]'),
('543ce230-65ec-475f-8619-0e2f4db77ef7','次劉晞顔韵','蘇庠','宋','宋诗','song-poetry','','[]','校書絕足騰飛黄，不數向來何與江。',32,'全唐诗/poet.song.73000.json','["校書絕足騰飛黄，不數向來何與江。", "錦囊詩句隨雲表，十襲未啟心先降。"]'),
('64a98188-7229-47ec-8b82-f9ecb3b9994d','送行','蘇庠','宋','宋诗','song-poetry','','[]','語別既不易，況與子同生。',24,'全唐诗/poet.song.73000.json','["語別既不易，況與子同生。", "如何携手好，忽作千里行。"]'),
('6ef4f3cd-9cb4-4995-bdb9-4c68175f0771','挽張彥知','蘇庠','宋','宋诗','song-poetry','','[]','敵騎乘秋入，妖氛擁賊營。',48,'全唐诗/poet.song.73000.json','["敵騎乘秋入，妖氛擁賊營。", "孤城控淮海，百口付柴荆。", "徒想回天力，空餘戀闕情。", "艱難思報主，炯炯寸心明。"]'),
('9d38adec-4849-42e6-9bfc-2e8ecbb7499c','送李巨源赴洮湖陳氏館','蘇庠','宋','宋诗','song-poetry','','[]','蟠胸歷歷鄴侯書，落筆奔奔走坂車。',32,'全唐诗/poet.song.73000.json','["蟠胸歷歷鄴侯書，落筆奔奔走坂車。", "辦作五言玉節信，直拚病渴馬相如。"]'),
('1051678b-8ee2-4af3-83c1-b5178e99baaa','詩一首','蘇庠','宋','宋诗','song-poetry','','[]','聊輟清都玉筍班，虎符猶得控荆蠻。',32,'全唐诗/poet.song.73000.json','["聊輟清都玉筍班，虎符猶得控荆蠻。", "已見五溪談笑了，坐追九辨典刑還。"]'),
('ccda9bea-b830-469a-a03f-f852a4a0fd8e','戲成小詩留子靜兄','蘇庠','宋','宋诗','song-poetry','','[]','秋霜一夜到枯荷，奈此江南秋色何。',32,'全唐诗/poet.song.73000.json','["秋霜一夜到枯荷，奈此江南秋色何。", "蘄君未作一成去，同聽竹窗鴻雁過。"]'),
('c5b22925-24cc-47d1-897d-6d24a55139f0','送錢仲韶機宜南歸天台','蘇庠','宋','宋诗','song-poetry','','[]','尺五城南客，能過仲蔚居。',48,'全唐诗/poet.song.73000.json','["尺五城南客，能過仲蔚居。", "烟霏深寂歷，雲樹晚扶疏。", "老去一無著，詩成百不如。", "喜無招隠作，仍免絕交書。"]'),
('4bfce736-224d-496e-a4d0-f69011aca772','題張公洞','蘇庠','宋','宋诗','song-poetry','','[]','銅棺之南山復山，捫蘿絕壁蘚苔斑。',32,'全唐诗/poet.song.73000.json','["銅棺之南山復山，捫蘿絕壁蘚苔斑。", "只今何處可容足，乞我石房雲一間。"]'),
('6c303407-243e-4a3c-a019-ad0bc90ed935','宿飛來峰下','蘇庠','宋','宋诗','song-poetry','','[]','吳中未歷佳山水，湖上懷思去惘然。',64,'全唐诗/poet.song.73000.json','["吳中未歷佳山水，湖上懷思去惘然。", "雲去雲歸兩峰寺，鷗飛鷗沒夕陽天。", "客愁官渡落花雨，歸夢下湖春水船。", "想得對床成夜語，何須隴月向人圓。"]'),
('bc85a2e4-6954-4af0-bfc8-decf92691344','送子經歸臨安','蘇庠','宋','宋诗','song-poetry','','["\u897f\u6e56"]','牛背行將老，鷗沙盟已寒。',48,'全唐诗/poet.song.73000.json','["牛背行將老，鷗沙盟已寒。", "蒓鱸付張翰，書札報任安。", "古學飽胸次，驚瀾翻筆端。", "西湖千頃月，留取醉眼看。"]'),
('637c5a2f-3fd2-4f88-b364-c18e5ec3d29b','陶隠居畫像贊','蘇庠','宋','宋诗','song-poetry','','[]','蕊珠妙言，字照編簡。',40,'全唐诗/poet.song.73000.json','["蕊珠妙言，字照編簡。", "雲霾三館，其人則遠。", "世衰道喪，完節者鮮。", "臨終之歎，作世和篇。"]'),
('cdf08df5-2a66-4d15-9f22-26ba6c9abb6e','惠安寺','蘇庠','宋','宋诗','song-poetry','','[]','沙溪烟絕雨纔通，無數深紅間淺紅。',32,'全唐诗/poet.song.73000.json','["沙溪烟絕雨纔通，無數深紅間淺紅。", "山店落英春寂寂，青旗吹盡柳花風。"]'),
('b427d2a7-6b3f-452e-b4b1-3f1b2abe464d','德友近在咫尺乃不相過因成小詩上呈','蘇庠','宋','宋诗','song-poetry','','[]','十日已吹梅信風，絕憐未許一尊同。',32,'全唐诗/poet.song.73000.json','["十日已吹梅信風，絕憐未許一尊同。", "喜君不減習主簿，愧我殊非龐德公。"]'),
('86fc5d48-c949-4c02-b321-052b4bb119f6','德友求薝蔔花栽戲作小詩代簡','蘇庠','宋','宋诗','song-poetry','','[]','問訊雲蘿小隠家，剡藤醉墨半欹斜。',32,'全唐诗/poet.song.73000.json','["問訊雲蘿小隠家，剡藤醉墨半欹斜。", "酒餘落筆已殊絕，發興不須薝蔔花。"]'),
('6cd3ca04-084a-4bdd-aa45-96a600d022c2','題唐頹山風漪軒','蘇庠','宋','宋诗','song-poetry','','[]','竹陰既疏明，流泉復清駛。',48,'全唐诗/poet.song.73000.json','["竹陰既疏明，流泉復清駛。", "佳響聞山禽，凉風澹然至。", "幽人此安禪，閱世一嬉戲。", "何必周八垠，是中有能事。"]'),
('f7ee826c-9307-47de-871f-fc56d586a7a1','至湖上','蘇庠','宋','宋诗','song-poetry','','[]','沙晚水痕碧，蕭蕭蒲葦秋。',48,'全唐诗/poet.song.73000.json','["沙晚水痕碧，蕭蕭蒲葦秋。", "鴻飛遵遠渚，木落見滄洲。", "藤杖吟還倚，風帘行可休。", "有懷誰共語，暝色起林丘。"]'),
('613e4fa6-f07a-4dae-a39c-d28e32b08e85','贈邑令章夏','蘇庠','宋','宋诗','song-poetry','','[]','弦歌武城宰，遺芳歎漢官。',48,'全唐诗/poet.song.73000.json','["弦歌武城宰，遺芳歎漢官。", "莫懷千載憂，且畢今日歡。", "亭午百吏散，曲肱謝喧煩。", "况看古錦句，落筆酬江山。"]'),
('22dc490a-f792-4539-b0b1-944097fbaddd','句  其一','蘇庠','宋','宋诗','song-poetry','','[]','但見金華仙伯語，筆端丘壑飽經心。',16,'全唐诗/poet.song.73000.json','["但見金華仙伯語，筆端丘壑飽經心。"]'),
