('a12356eb-5c1c-4d89-aca9-ac968512a96a','句  其一九','蘇庠','宋','宋诗','song-poetry','','[]','迎春不負千金諾。',8,'全唐诗/poet.song.73000.json','["迎春不負千金諾。"]'),
('d35ef6e0-cd5a-46ae-805e-4dd7f4581a2f','天台山中偶題','釋祖可','宋','宋诗','song-poetry','','[]','傴步入蘿徑，綿延趣最深。',72,'全唐诗/poet.song.73000.json','["傴步入蘿徑，綿延趣最深。", "僧居不知處，彷彿清磬音。", "石梁邀屢度，始見青松林。", "谷口未斜日，數峰生夕陰。", "凄風薄喬木，萬竅作龍吟。", "摩挲綠苔石，書此慰幽尋。"]'),
('39111a45-66d9-494d-8a2d-6279cd9da471','霜餘溪上','釋祖可','宋','宋诗','song-poetry','','[]','水似秋蛇巧作蟠，山如濃翠擁高鬟。',32,'全唐诗/poet.song.73000.json','["水似秋蛇巧作蟠，山如濃翠擁高鬟。", "清風明月元無主，乞我烟蘿茅數間。"]'),
('18fa58df-71ed-45f3-be4a-bf1d5b70c193','李伯時作淵明歸去來圖王性之刻於琢玉坊病僧祖可見而賦詩','釋祖可','宋','宋诗','song-poetry','','[]','坐上柴桑墟落烟，眼中百里舊山川。',64,'全唐诗/poet.song.73000.json','["坐上柴桑墟落烟，眼中百里舊山川。", "候門稚子似無恙，三徑巾車人絕憐。", "尚友當須今逸少，丹青寧復老龍眠。", "流傳匪獨遺怡玩，端使懦夫懷凜然。"]'),
('8258c502-d276-46cf-b1b2-9e0fb766d495','次吳伯江所藏文湖州山水韵','釋祖可','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','乘空作山川，妙絕借墨色。',108,'全唐诗/poet.song.73000.json','["乘空作山川，妙絕借墨色。", "曲折千里素幅間，來自吳興白蘋客。", "乃知瀟湘洞庭岸，平吞胸中寄筆力。", "清霜摇落江海空，如聞冥冥度驚鴻。", "重樓複閣底處所，使我絕欲空濛中。", "吳侯吳侯安用許，浪迫歸心赴翛渚。", "如何喚得江上船，一卧蒼波占烟雨。"]'),
('f85686ae-89a2-4323-bf20-79b013277688','書余逢時所作山水  其一','釋祖可','宋','宋诗','song-poetry','','[]','江勢卷十萬頃，村墅掩三四家。',28,'全唐诗/poet.song.73000.json','["江勢卷十萬頃，村墅掩三四家。", "落雁驚橫烟水，小舟欹著寒沙。"]'),
('e74eac6a-b2d7-4cf5-adbd-1054ac4b5512','書余逢時所作山水  其二','釋祖可','宋','宋诗','song-poetry','','[]','折葦非關秋色，飛鷗元自斜行。',28,'全唐诗/poet.song.73000.json','["折葦非關秋色，飛鷗元自斜行。", "坐上忽驚丘壑，窗間那有瀟湘。"]'),
('eb98b77c-fb9a-4122-a145-9dfb85a5bedb','書余逢時所作山水  其三','釋祖可','宋','宋诗','song-poetry','','[]','江南江北岸，飽歷此山川。',48,'全唐诗/poet.song.73000.json','["江南江北岸，飽歷此山川。", "誰信著筆力，盡驅來眼前。", "野橋分道路，古木薄風烟。", "我欲徑歸去，沙頭人挽船。"]'),
('4d412ce2-b960-40e7-bbad-9d43af0a3bd2','詠秦處士作枯松','釋祖可','宋','宋诗','song-poetry','','[]','秦郎真是舊摩詰，寫出崔巍霜雪姿。',32,'全唐诗/poet.song.73000.json','["秦郎真是舊摩詰，寫出崔巍霜雪姿。", "林壑卷簾相照映，坐令公子發幽思。"]'),
('15b73ee0-c74e-4eb6-9ab8-1e0397250a4b','求初老墨梅','釋祖可','宋','宋诗','song-poetry','','[]','手開玉璽心希有，乃得橫烟冰雪枝。',32,'全唐诗/poet.song.73000.json','["手開玉璽心希有，乃得橫烟冰雪枝。", "枯木堂中安用許，適堪病眼發新詩。"]'),
('725f8ce3-9aa5-47af-bb58-6a314c1dfa50','墨梅','釋祖可','宋','宋诗','song-poetry','','[]','不向江南冰雪底，乃於毫末發春妍。',32,'全唐诗/poet.song.73000.json','["不向江南冰雪底，乃於毫末發春妍。", "一枝無語淡相對，疑在竹橋烟雨邊。"]'),
('4d259cf6-a10c-4f73-94b1-fb3c266a5ad4','書性之所藏伯時木石屏  其一','釋祖可','宋','宋诗','song-poetry','','[]','此自是我輩物，而乃落君家房。',28,'全唐诗/poet.song.73000.json','["此自是我輩物，而乃落君家房。", "尚喜周旋顧盼，無憂犖确風霜。"]'),
('79e5de97-5e44-4d64-9d36-bd1ccc930158','書性之所藏伯時木石屏  其二','釋祖可','宋','宋诗','song-poetry','','[]','淡巃嵷烟雨色，老槎牙霜霰痕。',28,'全唐诗/poet.song.73000.json','["淡巃嵷烟雨色，老槎牙霜霰痕。", "想見湘岑落木，霧連江月昏昏。"]'),
('6495891d-f440-45c9-a0ea-d014dd60ed42','書性之所藏伯時木石屏  其三','釋祖可','宋','宋诗','song-poetry','','[]','胸中定自有此，筆端乃一見之。',28,'全唐诗/poet.song.73000.json','["胸中定自有此，筆端乃一見之。", "摧却岌峨天柱，來成咫尺峨嵋。"]'),
('ced0dc41-77f3-48a5-9cbb-f3ec25b4d57a','書秦處度所作松石','釋祖可','宋','宋诗','song-poetry','','[]','憐君作詩自無敵，遊戲詩餘畫成癖。',64,'全唐诗/poet.song.73000.json','["憐君作詩自無敵，遊戲詩餘畫成癖。", "高堂奮袖風雨來，霜幹雲根動秋色。", "長懷祝融天柱峰，萬年不死之喬松。", "觀君此畫已無斁，不復望雲支瘦筇。"]'),
('a0eeb10d-0a4a-47d5-91f5-ea8f79b9d7f0','觀壯輿所藏伯時馬','釋祖可','宋','宋诗','song-poetry','','[]','平生徒說追風足，厭見駑駘飽芻粟。',128,'全唐诗/poet.song.73000.json','["平生徒說追風足，厭見駑駘飽芻粟。", "劉侯爲出二馬圖，緬想權奇在坰牧。", "本朝不伐大宛城，公初得之無乃驚。", "胡沙燕山在吾目，短草落日低邊明。", "雄姿忽作風動壁，意氣騰驤欲無敵。", "前者驕矜後者馳，信矣能先鳥疾飛。", "圉人亦復神超然，亮作俗肉勤加鞭。", "吁嗟駿骨世定有，良樂不逢長棄捐。"]'),
('5a33a3a5-9e9f-4bf8-ada6-11f0205be7a8','廬山十八賢','釋祖可','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','不能晉室扶傾覆，盡作西方社裏人。',32,'全唐诗/poet.song.73000.json','["不能晉室扶傾覆，盡作西方社裏人。", "豈意一時希有事，翻令元亮兩眉顰。"]'),
('4258aaaf-2aa6-444d-9168-90882f8614f3','絕句','釋祖可','宋','宋诗','song-poetry','','[]','琴到無弦聽者希，古今唯有一鍾期。',32,'全唐诗/poet.song.73000.json','["琴到無弦聽者希，古今唯有一鍾期。", "幾回擬鼓陽春曲，月滿虛堂下指遲。"]'),
('42e81faa-27d8-4056-83a3-2e4a3977f5d1','靖節祠','釋祖可','宋','宋诗','song-poetry','','[]','靖節非傲世，带恥爲人束。',72,'全唐诗/poet.song.73000.json','["靖節非傲世，带恥爲人束。", "鬰然霜雪姿，受正如松獨。", "高歌歸去來，自種松與粟。", "寓意琴書間，處己審纓足。", "傾觴三徑醉，頹然忘寵辱。", "江山有遺跡，庶以拯流俗。"]'),
('64380604-ca89-4660-9743-58465e80d73f','香林許惠南溪茶作詩促之','釋祖可','宋','宋诗','song-poetry','','[]','午窗湯餠違煩渴，安得雲腴作短兵。',32,'全唐诗/poet.song.73000.json','["午窗湯餠違煩渴，安得雲腴作短兵。", "仙鼎望公能遣贈，只今兀坐聽歌聲。"]'),
('bbbd7d64-3a93-4d32-8a5b-8bc956006f1e','贈中上人','釋祖可','宋','宋诗','song-poetry','','[]','能來不能款，竟欲與公言。',48,'全唐诗/poet.song.73000.json','["能來不能款，竟欲與公言。", "促策望山去，未須違世喧。", "輕帆收落日，獨鳥向前村。", "我亦動歸思，一峰烟靄昏。"]'),
('963a1b6f-0de8-4802-b68b-a034a5415dcf','乞梅','釋祖可','宋','宋诗','song-poetry','','[]','朔風吹盡西山雪，合有早梅凌雪開。',32,'全唐诗/poet.song.73000.json','["朔風吹盡西山雪，合有早梅凌雪開。", "不應占看野塘上，分我一枝春色來。"]'),
('80b7912a-b4a0-4561-8970-89243345a4f0','乞霜柑','釋祖可','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','殊非海外羅浮樣，亦勝洞庭霜後黄。',32,'全唐诗/poet.song.73000.json','["殊非海外羅浮樣，亦勝洞庭霜後黄。", "此實君家能獨有，何時分餉齒牙香。"]'),
('ddd62a2e-2f0e-4cd2-91f8-6ca6699c499f','酬才上人送霜柑  其一','釋祖可','宋','宋诗','song-poetry','','[]','霜柑寄我莫言少，但得向人懷抱佳。',32,'全唐诗/poet.song.73000.json','["霜柑寄我莫言少，但得向人懷抱佳。", "渺渺新愁入思夢，晚雲連雁雪連沙。"]'),
('db8b8f36-e274-4af9-ad8f-f800cbaf9b65','酬才上人送霜柑  其二','釋祖可','宋','宋诗','song-poetry','','[]','日向南雲望幾回，無因懷抱得重開。',32,'全唐诗/poet.song.73000.json','["日向南雲望幾回，無因懷抱得重開。", "憑君莫惜錦囊句，盡作銀鈎蠆尾來。"]'),
('413e8b3e-c5db-4416-85ae-5ba8a443b8bc','乞菖蒲','釋祖可','宋','宋诗','song-poetry','','[]','飽聞雲根九節，不改四時鬰然。',28,'全唐诗/poet.song.73000.json','["飽聞雲根九節，不改四時鬰然。", "願見明窗棐几，淺葉瘦碧相鮮。"]'),
('e0f0b273-6952-4ef4-bf32-f7b4ad26753a','秋懷','釋祖可','宋','宋诗','song-poetry','','[]','霜禽驚呼山麓音，霜風急吹溪上林。',64,'全唐诗/poet.song.73000.json','["霜禽驚呼山麓音，霜風急吹溪上林。", "羲和攬轡不可緩，夏后苦身驚寸陰。", "橫河明明月皎皎，遠山蒼蒼水深深。", "哀鴻萬里繞雲陣，遊子不眠中夜心。"]'),
