('e0381f2d-18da-40dd-979e-fa3aeddffdb6','絕句','牧童','宋','宋诗','song-poetry','','["\u513f\u7ae5", "\u4e94\u5e74\u7ea7\u4e0b\u518c", "\u5c0f\u5b66\u53e4\u8bd7"]','草鋪橫野六七里，笛弄晚風三四聲。',32,'全唐诗/poet.song.73000.json','["草鋪橫野六七里，笛弄晚風三四聲。", "歸來飽飯黄昏後，不脫蓑衣卧月明。"]'),
('c8e78b46-5c61-4b6f-b96d-e808aaf7497b','偈三首  其一','釋元靜','宋','宋诗','song-poetry','','[]','君王了了，將帥惺惺。',20,'全唐诗/poet.song.73000.json','["君王了了，將帥惺惺。", "一回得勝，六國平寧。"]'),
('f04f3d13-7f31-4331-bd6b-b495c6428c2f','偈三首  其二','釋元靜','宋','宋诗','song-poetry','','[]','行年七十老躘踵，眼目精明耳不聾。',32,'全唐诗/poet.song.73000.json','["行年七十老躘踵，眼目精明耳不聾。", "忽地有人欺負我，一拳打倒過關東。"]'),
('c0a61f01-05a1-431b-9d10-2868c9a40a43','偈三首  其三','釋元靜','宋','宋诗','song-poetry','','[]','自己田園任運耕，祖宗基業力須爭。',32,'全唐诗/poet.song.73000.json','["自己田園任運耕，祖宗基業力須爭。", "悟須千聖頭邊坐，用向三塗底下行。"]'),
('61e32251-7753-40e0-95f6-312e9729668e','頌古六首 即心即佛。','釋元靜','宋','宋诗','song-poetry','','[]','即心即佛，鐵牛無骨。',36,'全唐诗/poet.song.73000.json','["即心即佛，鐵牛無骨。", "戲海獰龍，摩天俊鶻。", "西江吸盡未爲奇，火裏生蓮香拂拂。"]'),
('3a2eeaa1-240f-476b-8ba9-5ab22cfe0b4b','頌古六首 狗子無佛性。','釋元靜','宋','宋诗','song-poetry','','[]','趙州狗子無佛性，七佛如來合掌聽。',32,'全唐诗/poet.song.73000.json','["趙州狗子無佛性，七佛如來合掌聽。", "須彌岋崿舞三臺，海水騰波行正令。"]'),
('619ba329-8cdd-4844-a73a-a1854e594dbf','頌古六首 野狐。','釋元靜','宋','宋诗','song-poetry','','[]','長蛇偃月，鐵旗鐵鼓。',36,'全唐诗/poet.song.73000.json','["長蛇偃月，鐵旗鐵鼓。", "坐斷乾坤，輝騰今古。", "曾騎鐵馬入重城，手握金鞭賀太平。"]'),
('698de2cd-69a0-4e5f-b8f3-e4a059983f10','頌古六首 女子出定。','釋元靜','宋','宋诗','song-poetry','','[]','懷藏日月，八面玲瓏。',52,'全唐诗/poet.song.73000.json','["懷藏日月，八面玲瓏。", "袖裏金鎚，鮮血通紅。", "香風拂拂，華雨濛濛。", "兵隨印轉處，萬里長虹。", "將逐符行時，些子神通。"]'),
('db798c63-2ca9-456a-9e78-11c6a17d7cfb','頌古六首 僧問瑯琊清浄本然。','釋元靜','宋','宋诗','song-poetry','','[]','清浄本然云何，忽生山河大地。',44,'全唐诗/poet.song.73000.json','["清浄本然云何，忽生山河大地。", "大小瑯琊禪師，借人鼻孔出氣。", "出得氣，有巴鼻，昨夜那吒生八臂。"]'),
('4dcf8959-be14-40bb-8e87-bfdc6afddfd4','頌古六首 無縫塔。','釋元靜','宋','宋诗','song-poetry','','[]','皎潔天心月，朦朧徧九垓。',49,'全唐诗/poet.song.73000.json','["皎潔天心月，朦朧徧九垓。", "三秋黄葉落，二月牡丹開。", "每睹南來雁，常詢北方五臺。", "均提童子報，拾得在天台。"]'),
('b44ed01c-dc7a-49e3-94fa-cdfb54ab59a5','偈','僧某','宋','宋诗','song-poetry','','[]','因山見水，見水忘山。',20,'全唐诗/poet.song.73000.json','["因山見水，見水忘山。", "山水俱忘，理歸何所。"]'),
('c2a64f79-251b-409a-b462-e1f5cea8fde0','呈法演偈答倩女離魂話','普融知藏','宋','宋诗','song-poetry','','[]','二女合爲一媳婦，機輪截斷難回互。',32,'全唐诗/poet.song.73000.json','["二女合爲一媳婦，機輪截斷難回互。", "從來往返絕縱由，行人莫問來時路。"]'),
('2b7fa9e0-bd4b-4d82-b3c6-7da7deb95fea','詩一首','毛伯英','宋','宋诗','song-poetry','','[]','鐵鎖沉沉截碧江，風旗獵獵駐危檣。',32,'全唐诗/poet.song.73000.json','["鐵鎖沉沉截碧江，風旗獵獵駐危檣。", "禹門縱使高千丈，放過蛟龍也不妨。"]'),
('b9330e4f-4880-4ca4-8924-fc79d282fbcd','示李朝請偈','釋吉','宋','宋诗','song-poetry','','[]','家賊惱人孰奈何，千聖回機祇爲他。',120,'全唐诗/poet.song.73000.json','["家賊惱人孰奈何，千聖回機祇爲他。", "遍界遍空無影跡，無依無住絕籠羅。", "賊，賊，猛將雄兵收不得，疑殺天下老禪和，笑倒鬧市古彌勒。", "休，休，不用將心向外求，回頭瞥爾賊身露，和贓捉獲世無儔。", "世無儔，真可仰，從茲不復誇伎倆。", "怗怗安家樂業時，萬象森羅齊拊掌。"]'),
('daf56930-8600-44f3-9263-80296708bae9','藕','胡致隆','宋','宋诗','song-poetry','','[]','平生冰雪姿，七星羅心胸。',60,'全唐诗/poet.song.73000.json','["平生冰雪姿，七星羅心胸。", "豈無有絲毫，上裨天子聰。", "而不自薦達，胡爲乎泥中。", "沈痾政無頼，安得君從容。", "其子亦可憐，風味如乃翁。"]'),
('524121e2-00ef-49dc-a7d2-5d8c89cc17e8','瘞鶴銘詩','胡致隆','宋','宋诗','song-poetry','','[]','當年誰爲裹玄黄，潮打孤城草木荒。',64,'全唐诗/poet.song.73000.json','["當年誰爲裹玄黄，潮打孤城草木荒。", "華表竟無新信息，斷碑空有碎文章。", "雲埋紫蓋峰何在，烟鎖青田道正長。", "遥想華亭披道氅，夜隨明月過錢塘。"]'),
('8c3024b3-65df-437c-95e3-118490692bbc','題吳生畫桃源圖','胡致隆','宋','宋诗','song-poetry','','[]','王宰五日畫一石，左思十年賦三都。',64,'全唐诗/poet.song.73000.json','["王宰五日畫一石，左思十年賦三都。", "誰似今時吳道子，咄嗟能辦武陵圖。", "武陵不與人間隔，可憐舊日無尋覓。", "蒼蒼烟水只依然，試倩漁舟問消息。"]'),
('a34d71b4-dfe1-408b-b1d0-9d53fb1b4c55','冬寒','胡致隆','宋','宋诗','song-poetry','','[]','倚天松骨冷，背日海雲高。',24,'全唐诗/poet.song.73000.json','["倚天松骨冷，背日海雲高。", "淮上人垂櫜，閣中客贈袍。"]'),
('e3651025-80b3-46de-902b-6c43868b11c6','登鐵甕城','胡致隆','宋','宋诗','song-poetry','','[]','雉堞巍然歲月長，古今知閱幾興亡。',48,'全唐诗/poet.song.73000.json','["雉堞巍然歲月長，古今知閱幾興亡。", "吳王殿裏笙歌罷，煬帝城邊草木荒。", "萬里烟霞歸洞急，一川風月渡江忙。"]'),
('9ce6e9a7-920a-4d52-a55b-06988b46ee0f','星子樓','胡致隆','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','葛中藤杖竹籧篨，靜夜江樓縱目初。',64,'全唐诗/poet.song.73000.json','["葛中藤杖竹籧篨，靜夜江樓縱目初。", "海獸擎山出彭蠡，玉龍銜水下匡廬。", "三更雲盡猿啼露，十里月寒人捕魚。", "已問湖山借圭角，他年來此老漁樵。"]'),
('2d9878cf-9f93-4ed4-80ae-c3dfadda0b93','仰山','胡致隆','宋','宋诗','song-poetry','','[]','山下清泉迸石流，山前松竹自春秋。',64,'全唐诗/poet.song.73000.json','["山下清泉迸石流，山前松竹自春秋。", "猿吟古寺偏深處，雲集諸峰最上頭。", "一老有靈飛窣堵，二神無語鎖寒湫。", "諸天更在藤蘿外，欲到峰前恨未由。"]'),
('38c0cf67-7948-4e60-aa62-1583737af666','玉山道中','胡致隆','宋','宋诗','song-poetry','','[]','江南江北水茫茫，水闊山遥道路長。',64,'全唐诗/poet.song.73000.json','["江南江北水茫茫，水闊山遥道路長。", "細雨來時麋角解，春風歸去馬蹄香。", "市橋落日明官柳，古渡行人上野航。", "景物端宜入圖畫，孤城回首带斜陽。"]'),
('59fccb75-ad1a-477f-a95e-1982cb1fd56c','喜曹劉二從事見過','胡致隆','宋','宋诗','song-poetry','','[]','蕭蕭細雨鎖柴門，喜見風流二使君。',64,'全唐诗/poet.song.73000.json','["蕭蕭細雨鎖柴門，喜見風流二使君。", "俊逸萬春猶錄事，清新子建尚參軍。", "飄零世路詩千首，寥落江湖酒一尊。", "多病揚雄謝來往，暮年誰更可論文。"]'),
('86d966b9-6a52-41c9-8438-28ed00544d20','句  其一','胡致隆','宋','宋诗','song-poetry','','[]','金山頂上看回雁，鐵甕城西聽杜鵑。',16,'全唐诗/poet.song.73000.json','["金山頂上看回雁，鐵甕城西聽杜鵑。"]'),
('933ab271-195f-426d-ac94-f6462f762e7d','句  其二','胡致隆','宋','宋诗','song-poetry','','["\u6ed5\u738b\u9601"]','細雨滕王閣，春風孺子亭。',12,'全唐诗/poet.song.73000.json','["細雨滕王閣，春風孺子亭。"]'),
('df1fc638-e4b1-4610-b1c5-a6bfc207b50e','太華山','譚綸','宋','宋诗','song-poetry','','["\u534e\u5c71"]','樓閣憑天起，山門傍斗開。',60,'全唐诗/poet.song.73000.json','["樓閣憑天起，山門傍斗開。", "香烟凝碧落，瑞氣壓蒼苔。", "古殿藏金屋，仙人卧玉隈。", "泉飛千澗雪，風送萬峰雷。", "星辰光滿袖，疑是法鐙來。"]'),
('c2f37b85-7798-450d-b982-17379ac2f642','句','方勺','宋','宋诗','song-poetry','','[]','三十年前曾見夢，茲遊端可冠平生。',16,'全唐诗/poet.song.73000.json','["三十年前曾見夢，茲遊端可冠平生。"]'),
('c2d3ecf1-5961-4932-a8b4-fb6569e3dd02','廣勝寺','王荀','宋','宋诗','song-poetry','','[]','重遊蕭寺十年過，四望風烟景若何。',64,'全唐诗/poet.song.73000.json','["重遊蕭寺十年過，四望風烟景若何。", "東北嶺高明月遶，西南川遠夕陽多。", "地饒勝概連靈岳，民足豐年藉綠波。", "却笑山僧無忌憚，一生安處在巍峨。"]'),
('6bdd0f75-8455-4939-b450-85caca58c228','遊白鶴觀','李昭玘','宋','宋诗','song-poetry','','[]','春歸數十朝，八九不暇出。',132,'全唐诗/poet.song.73000.json','["春歸數十朝，八九不暇出。", "萌芽日夜發，百觜競撐突。", "駕言謁仙祠，古像懷彷彿。", "白鶴來何時，蒼檜暮蕭窣。", "雲霞斷人世，往事已荒忽。", "解纓濯泉流，深澈幾照骨。", "毛寒不敢視，下必有神物。", "昔人斯徜徉，音影詎磨沒。", "嗟予質汙下，見亦被呵咄。", "仰慚逍遥遊，未忍塵土汩。", "時須挹高風，爲我一吹拂。"]'),
('d5b1b2af-3c23-4228-adf8-20fe44480d4c','從張聖塗乞石','李昭玘','宋','宋诗','song-poetry','','[]','先生築高隠，趣好清且獨。',216,'全唐诗/poet.song.73000.json','["先生築高隠，趣好清且獨。", "雲龍峰上石，跋草自鏨斸。", "發竅號陰怪，窮根攬坤腹。", "山靈不敢愛，鞭叱滿崖谷。", "危躋已穿履，大載幾折軸。", "直欲起巖巖，未容買碌碌。", "心營合天造，指化出神速。", "突兀傲中巔，憑陵勇雙矗。", "獸蹲目睥睨，龍攫腰回蹙。", "縮脰立幽鳥，擎顱卧孤犢。", "鯨鱗老廉利，相角怒撐觸。", "軒昂鶴引咮，贔屭鼇跂足。", "騰空快高思，排峭驚醉目。", "伊余朅來遊，步百吟周復。", "願從乞其餘，伴我東牆竹。", "猿鶴莫相嗔，此客意非俗。", "常令月色照，敢使塵土辱。", "日待風雨來，起看空遶屋。"]'),
('72ac1102-6378-40f3-8622-0b687c81c744','送王子中南歸筠州','李昭玘','宋','宋诗','song-poetry','','[]','荆山美璞昔未發，鬼神訶守誰可奪。',112,'全唐诗/poet.song.73000.json','["荆山美璞昔未發，鬼神訶守誰可奪。", "妙工伐石强剖抉，試之烈火皎冰雪。", "長虹射天晝不滅，夜堂流光墮明月。", "堅厚粹溫函正氣，不許時人巧雕礪。", "羞與佩環爭細碎，直登丘壇薦天帝。", "世無琅玕來作貢，楚人未售空長慟。", "索價當高勿輕用，緹囊十襲須珍重。"]'),
('564e2426-6db3-4d2e-90dd-f98717f3ba34','送徐州舉人赴省試','李昭玘','宋','宋诗','song-poetry','','[]','淮夷之珠照夜明，泗濱之石聲泠泠。',128,'全唐诗/poet.song.73000.json','["淮夷之珠照夜明，泗濱之石聲泠泠。", "昔時大禹致方物，神光玉色羅廣庭。", "比年入獻多豪英，褒雄妙思相憑陵。", "飄飄束書去觀國，瘦馬踏雪鬚垂永。", "長廊白晝天宇清，落筆冉冉風雲生。", "千官拱笏赭袍近，碧溝新柳黄鸝鳴。", "金撾虎士傳姓名，魚龍卷尾隨雷聲。", "州人洗眼望歸期，會約春風載酒迎。"]'),
('10418643-3778-4b2b-b0bd-4ec9d0d4b37f','送李容甫歸北都','李昭玘','宋','宋诗','song-poetry','','[]','先生讀書不下堂，堂上有客語琅琅。',204,'全唐诗/poet.song.73000.json','["先生讀書不下堂，堂上有客語琅琅。", "弟子出觀如堵牆，怪君眉彩生光芒。", "北都晁夫子，一別久相望。", "君來道信問，使我開肺腸。", "三日不改服，猶覺芝蘭香。", "平生寡投分，一笑且云樂。", "慇懃發黄卷，鈍吻慳應□。", "大杵撞啞鐘，已厭音響惡。", "更慚河伯觀，未易窮海若。", "索寞歲華晚，颼颼黄葉秋。", "歸心劇流水，忽忽不可留。", "固知此鱣鯨，肯託尋常溝。", "直須見老聃，可化南榮儔。", "海州歲有沖天鵠，卵如萍實光琢玉，蜀鷄眇然何敢伏。", "羽成不須求日浴，一舉將驚萬人目。"]'),
('e43e6af2-bc0a-4b52-bfdc-f0dd58adb15e','雪堂詩寄子瞻','李昭玘','宋','宋诗','song-poetry','','[]','愁雲蔽日昏風發，鵝毛大片舞空闊。',192,'全唐诗/poet.song.73000.json','["愁雲蔽日昏風發，鵝毛大片舞空闊。", "陰崖冰壓木枝折，一鳥不飛人足絕。", "山翁口掉肩擁褐，斫竹撐茅勞架結。", "堂成不用巧丹涅，却畫東坡四山雪。", "羣石嶄嶄爭皎潔，門外堂間兩清洌。", "萬境一心同瑩徹，石床雲生濕肌髮。", "布被颼颼冷於鐵，半夜哀猿叫山月。", "山翁高哦響修越，不道妻啼憂米竭。", "世事薰膏付灰滅，長安高門奔請謁。", "赤日炙背沙埋轍，僕夫汗流馬吐舌。", "三謁不逢腹欲爇，怒氣恐成疽毒裂。", "狂走不須求扇暍，此堂一登能濯熱。"]'),
('4a142245-9152-45ee-91d2-16aa86120446','謝劉主簿見和乞石詩','李昭玘','宋','宋诗','song-poetry','','[]','官居太疏冷，門外少車跡。',240,'全唐诗/poet.song.73000.json','["官居太疏冷，門外少車跡。", "蕭蕭此君軒，爲我慰窮寂。", "貪饕起餘慕，遠乞南山石。", "形模太詭陋，此詠費搜摭。", "蝦蟆欲上甕，作氣屢跳躑。", "心知不可强，怒癭猶鼓息。", "但勞旁者觀，笑爾不量力。", "君能惠然來，抵鵲輕尺璧。", "明月投我懷，坐上光彩溢。", "神心巧鎸鑿，變化出胸臆。", "高言寫豪壯，健讀口終吃。", "衝風卷海濤，蕩潏迷四極。", "陣馬脫重圍，戰士皆辟易。", "使人魂魄沮，三日不敢食。", "嗟余性頑闇，兀兀寡知識。", "臃腫終天年，不願借雕飾。", "翻憐孤僻中，趣味得所適。", "拂石雲生手，誦詩風滿腋。", "此應長不饑，富貴乃毒腊。", "人生多苦辛，嗜好須自擇。"]'),
('7b83f134-6a57-4819-b496-10ae38efc1fa','昂昂千里駒','李昭玘','宋','宋诗','song-poetry','','[]','昂昂千里駒，逸氣吞九區。',120,'全唐诗/poet.song.73000.json','["昂昂千里駒，逸氣吞九區。", "東馳越夕兔，西走窮朝烏。", "關山一息過，躑躅疑有無。", "快哉穆天子，遠駕周四隅。", "嘶聲想雲海，弄影有天衢。", "昆丘距赤水，度足纔須臾。", "眷言芻粟恩，豈敢論形軀。", "雄心忽摧頓，倦步成躊躇。", "日暮路途遠，天寒毛鬣疏。", "此時垂耳心，可復輕疲駑。"]'),
('1dadb3c1-785e-4296-8dac-468db305a45b','泛泛水中鳬','李昭玘','宋','宋诗','song-poetry','','[]','泛泛水中鳬，上下聲相呼。',120,'全唐诗/poet.song.73000.json','["泛泛水中鳬，上下聲相呼。", "徜徉信波浪，澡濯羞泥汙。", "晴洲漾蘋荇，雨岸眠菰蒲。", "飲啄亦自足，飛遊誰我拘。", "侯門大池籞，富屋夸庖厨。", "何慚久垂翅，未願輕投軀。", "雖非黄鵠舉，幸與白鷺娛。", "逃烹笑窮雁，啄腐嗟饑烏。", "三秋熟粱稻，萬里開江湖。", "寄言澤中子，何用張羅□。"]'),
('130be9b3-3cee-434e-9115-5433319bd59a','飛鴻亭','李昭玘','宋','宋诗','song-poetry','','[]','平野浩空闊，危甍兀岧嶢。',144,'全唐诗/poet.song.73000.json','["平野浩空闊，危甍兀岧嶢。", "臘盡風日好，春回冰雪消。", "朱弦試揮手，度響何翛翛。", "此意復誰共，古人今寂寥。", "眷彼澤中鴻，欻起如回飆。", "悠然薄天末，去去不可招。", "愧無雙羽翰，萬里同飄颻。", "人生本蕭散，知慮勞煎燒。", "恈恈覘聲利，傴僂隨紛囂。", "安知出世間，造適皆逍遥。", "帝鄉果何在，久願追松喬。", "行歌歸去來，五斗空折腰。"]'),
('84d9cddc-a6cb-43c6-98ad-dd7ebd0d8f56','敺雀行','李昭玘','宋','宋诗','song-poetry','','[]','田間小兒杖敺雀，雀飛上枝不敢落，繞樹咒駡語聲惡。',142,'全唐诗/poet.song.73000.json','["田間小兒杖敺雀，雀飛上枝不敢落，繞樹咒駡語聲惡。", "三時耕鋤一時穫，老牛力盡石田薄。", "五龍作嗔風吐雹，赤烏燒雲龍見逐。", "南村賣桑北村熟，狐尾毿毿穗齊屋。", "縣門大書催賦粟，南關飛輓夜摩轂。", "掃舂縛箕十指禿。", "一米未炊汝先啄，直須殺汝償我腹。", "田父坐語兒，雀不暴人人亦饑。", "但令家雀千羣飽，莫使征西戰馬肥。"]'),
('21d8f410-26d9-43a4-afaa-149b4b2f0a7a','春日遊西池','李昭玘','宋','宋诗','song-poetry','','[]','雨餘風日暖，野塘春水滿。',48,'全唐诗/poet.song.73000.json','["雨餘風日暖，野塘春水滿。", "天影倒浮人，鏡光環射眼。", "蘭船不可上，漠漠低烟晚。", "歸路已埃塵，滄波鳬鵠遠。"]'),
('62a8f9ed-cc82-4edd-85f7-4e09e30e5ccc','觀江都王畫馬','李昭玘','宋','宋诗','song-poetry','','[]','落落名王唐帝孫，筆端飛洒只逡巡。',64,'全唐诗/poet.song.73000.json','["落落名王唐帝孫，筆端飛洒只逡巡。", "風雲絕足知何在，粉墨餘姿若有神。", "可信權奇盡龍種，不應腲脮失天真。", "驊騮寂寞龍眠死，更復何人接後塵。"]'),
('dd4e1db7-8829-47ea-8956-7de728e2f70b','暮冬書懷贈次膺四首  其一','李昭玘','宋','宋诗','song-poetry','','[]','一氣推遷星復回，人生常苦歲華催。',64,'全唐诗/poet.song.73000.json','["一氣推遷星復回，人生常苦歲華催。", "凍雲欲雪雁聲過，臘酒正香梅信來。", "晝夢每因啼鳥喚，柴門獨爲故人開。", "自憐衰晚無多事，心地都成一寸灰。"]'),
('293a16a0-82c8-4b13-97c3-a30de03acd2c','暮冬書懷贈次膺四首  其二','李昭玘','宋','宋诗','song-poetry','','[]','不住寒岩不姓龐，亦無短艇釣清江。',64,'全唐诗/poet.song.73000.json','["不住寒岩不姓龐，亦無短艇釣清江。", "門庭晝寂人欹枕，几案春生日上窗。", "五鼎甘心爭逐獸，萬夫落膽看尋橦。", "何如種取東皋秫，爛醉床頭酒百缸。"]'),
('bb2a9208-7fdf-4e4c-aa58-dfe3e42a6304','暮冬書懷贈次膺四首  其三','李昭玘','宋','宋诗','song-poetry','','[]','多病猶憑藥可醫，若爲換却鏡中絲。',64,'全唐诗/poet.song.73000.json','["多病猶憑藥可醫，若爲換却鏡中絲。", "人生得意一搔癢，世事循環千弈棋。", "幸有歸來陶令計，何須惆悵杜秋詩。", "慇懃田父勞相語，天命吾今不復疑。"]'),
('33aa1972-5a66-4189-8c33-f9214e6444e4','暮冬書懷贈次膺四首  其四','李昭玘','宋','宋诗','song-poetry','','[]','慚愧儒冠誤此身，塗窮何假問通津。',64,'全唐诗/poet.song.73000.json','["慚愧儒冠誤此身，塗窮何假問通津。", "門前羅雀正吾事，牆角負暄非世人。", "自喜小槽長有酒，獨驚華髮不便春。", "知君澤畔成新築，擬荷鋤犁去卜鄰。"]'),
('45a79067-9101-48a3-b2ca-51fe98326db0','出郭閒步','李昭玘','宋','宋诗','song-poetry','','[]','城市不在眼，始知天宇寬。',48,'全唐诗/poet.song.73000.json','["城市不在眼，始知天宇寬。", "田園休歲事，風物似江干。", "茅屋上斜照，水烟生晚寒。", "徑須追野老，笑語暫盤桓。"]'),
('88cdac7e-14af-4eaa-afc5-ae6ef63089cb','寇彥時自歷下歸携古鐵刀白石壓尺見贈因以二詩答之 白石壓尺','李昭玘','宋','宋诗','song-poetry','','[]','素質並琳瑯，磨礲若截肪。',48,'全唐诗/poet.song.73000.json','["素質並琳瑯，磨礲若截肪。", "動摇風莫慮，點污墨須防。", "色带泉流潤，聲含磬韵長。", "願登青玉案，時助寫雲章。"]'),
('8182648a-5ceb-4088-9955-752e157ea6df','寇彥時自歷下歸携古鐵刀白石壓尺見贈因以二詩答之 古鐵刀','李昭玘','宋','宋诗','song-poetry','','[]','戰地久埋沒，洪爐爲再燒。',48,'全唐诗/poet.song.73000.json','["戰地久埋沒，洪爐爲再燒。", "曾因土花缺，不逐血魂銷。", "擬借庖丁手，寧懸筆吏腰。", "柔鉛勿多忌，一割定相饒。"]'),
('9e7869d2-e43c-4dd2-9008-74dcf9e6d491','次韵庭玉弟暮春作','李昭玘','宋','宋诗','song-poetry','','[]','小雨廉纖春欲歸，桃花吹盡燕來遲。',32,'全唐诗/poet.song.73000.json','["小雨廉纖春欲歸，桃花吹盡燕來遲。", "閉門却有宜人處，簾幕陰陰睡起時。"]'),
('b322f8e0-37c2-458f-950e-13d632395ea9','戲贈閻漢臣廟令','李昭玘','宋','宋诗','song-poetry','','[]','香火餘金月十千，指呼巫覡示威權。',32,'全唐诗/poet.song.73000.json','["香火餘金月十千，指呼巫覡示威權。", "如何報得君王賜，瀝酒慇懃祝萬年。"]'),
('22fe5179-f370-441a-be88-82aae6a10388','又戲贈漢臣','李昭玘','宋','宋诗','song-poetry','','[]','蕭散官資近十千，不須親舊祝無權。',32,'全唐诗/poet.song.73000.json','["蕭散官資近十千，不須親舊祝無權。", "虎頭食肉非虛語，可待誰人報有年。"]'),
('916aa182-1583-4390-88d3-28c6a79618bd','睡起','李昭玘','宋','宋诗','song-poetry','','[]','病夫無酒破春愁，掃榻焚香作睡謀。',32,'全唐诗/poet.song.73000.json','["病夫無酒破春愁，掃榻焚香作睡謀。", "夢覺不知身是蝶，午鷄聲裏思悠悠。"]'),
('7474880e-7dec-45b1-9258-4801b1a8beaf','病中聞雨','李昭玘','宋','宋诗','song-poetry','','[]','官居寥落禁門東，秋滿長安一夜風。',32,'全唐诗/poet.song.73000.json','["官居寥落禁門東，秋滿長安一夜風。", "老病不眠成展轉，五更鐘鼓雨聲中。"]'),
('8b8030d0-521b-469a-b461-450ff83a83f4','弔劉孝嗣','李昭玘','宋','宋诗','song-poetry','','[]','富貴從來一羽輕，胸中萬卷復何營。',64,'全唐诗/poet.song.73000.json','["富貴從來一羽輕，胸中萬卷復何營。", "囊錢盡處布衾短，謗焰息時墳草生。", "一日得行須有命，百年不死是高名。", "瑶琴掛壁凝塵滿，無復當年流水聲。"]'),
('b425787e-064f-41fc-a283-7c0b820b2c74','經睢陽有感','李昭玘','宋','宋诗','song-poetry','','[]','昔日經由一夢同，高樓雖在舊游空。',64,'全唐诗/poet.song.73000.json','["昔日經由一夢同，高樓雖在舊游空。", "東流不改當年水，白首已成今日翁。", "梁苑衣冠共黄壤，隋堤楊柳幾春風。", "扁舟莫負南來興，咫尺吳松落眼中。"]'),
('275b842a-d078-4a02-b668-32fb2d163962','南游道中','李昭玘','宋','宋诗','song-poetry','','[]','玉鱠金虀昔未嘗，幾迴飛夢到滄浪。',64,'全唐诗/poet.song.73000.json','["玉鱠金虀昔未嘗，幾迴飛夢到滄浪。", "鄉關望處歸期晚，風水聲中去路長。", "梅使南來問行驛，雁聲北度下斜陽。", "囊錢未盡江湖近，擬買漁舟學漫郎。"]'),
('8fc7dbf5-8264-49b9-99f4-7fd92c4107ca','舟行阻雨','李昭玘','宋','宋诗','song-poetry','','[]','暮雨來何急，乘時助發生。',48,'全唐诗/poet.song.73000.json','["暮雨來何急，乘時助發生。", "水邊千樹暗，篷底一燈明。", "半夜起鄉思，空陂聞雁聲。", "春風故留客，不爲阻歸程。"]'),
('a1b0f25a-0b54-4d06-acbb-245f305c0b8c','道中書懷三首  其一','李昭玘','宋','宋诗','song-poetry','','[]','竹樹出平岸，人家藏遠烟。',48,'全唐诗/poet.song.73000.json','["竹樹出平岸，人家藏遠烟。", "片帆雲度水，雙槳雁隨船。", "綠變春回地，寒生雨後天。", "前途盡佳境，得意且留連。"]'),
('9042cd21-8e52-46ef-87d3-3b531d266bf5','道中書懷三首  其二','李昭玘','宋','宋诗','song-poetry','','[]','漸入臨淮路，移舟每問津。',48,'全唐诗/poet.song.73000.json','["漸入臨淮路，移舟每問津。", "行行風逆水，處處雨隨人。", "啼鳥如留客，幽花忽見春。", "白魚不論價，沽酒莫辭頻。"]'),
('4dbb3fec-b5aa-4a26-8005-fa5d5713cb54','道中書懷三首  其三','李昭玘','宋','宋诗','song-poetry','','[]','平野青蕪合，長橋綠樹低。',48,'全唐诗/poet.song.73000.json','["平野青蕪合，長橋綠樹低。", "客愁須白酒，春意屬黄鸝。", "落日鄉關遠，孤村烟水迷。", "清明能幾日，却過浙江西。"]'),
('32a81aec-f4b6-46f5-bbc0-2283c710b74d','過盱眙宿慈氏寺','李昭玘','宋','宋诗','song-poetry','','[]','行役經旬不自聊，强將登覽寄春醪。',64,'全唐诗/poet.song.73000.json','["行役經旬不自聊，强將登覽寄春醪。", "淮吞汴水長增急，城睍南峰不讓高。", "賈客正來喧萬井，夕陽初下艤千艘。", "明朝更作留連計，醉卧西窗聽夜濤。"]'),
('7dbc97f6-0ba9-409a-8e59-1af0fd2c0b43','宿慈氏遥碧齋有感','李昭玘','宋','宋诗','song-poetry','','[]','高僧邀我暫淹留，細話朱轓此屢遊。',64,'全唐诗/poet.song.73000.json','["高僧邀我暫淹留，細話朱轓此屢遊。", "不見清談飛麈尾，空流悲淚拂銀鈎。", "淮山勝絕千年在，人物才華一夢休。", "欲作招魂弔餘恨，晚烟疏雨不勝愁。"]'),
('143e6f3b-c8bf-43ad-9a75-5f983093f977','天長道中','李昭玘','宋','宋诗','song-poetry','','[]','細草眠黄犢，短籬穿綠楊。',48,'全唐诗/poet.song.73000.json','["細草眠黄犢，短籬穿綠楊。", "舂聲鵓鴣急，田徑蝍蛆長。", "地暖足春物，雨頻宜水鄉。", "羈懷不可話，倒橐酒須嘗。"]'),
('ef0a5646-8c00-4e25-aec7-a496f3c5f9d7','久雨','李昭玘','宋','宋诗','song-poetry','','[]','苦雨經旬久，溟濛勢未收。',48,'全唐诗/poet.song.73000.json','["苦雨經旬久，溟濛勢未收。", "細聲來短蓋，橫點透重裘。", "澗曲水流急，峰深雲氣浮。", "此行吾自喜，所念老農憂。"]'),
('5aba1e44-610d-4430-b86e-d53eec6bbf1c','南峰閒步','李昭玘','宋','宋诗','song-poetry','','[]','足健會真賞，眼明逃世紛。',48,'全唐诗/poet.song.73000.json','["足健會真賞，眼明逃世紛。", "風烟入詩畫，杖屨逐僧雲。", "水闊天疑盡，峰寒日易曛。", "羈人正愁思，城角不堪聞。"]'),
('4a6a8dd9-8830-4c3f-acc1-a45c4a4de2b2','登龍游寺','李昭玘','宋','宋诗','song-poetry','','[]','飛構起崔嵬，江晴宿霧開。',48,'全唐诗/poet.song.73000.json','["飛構起崔嵬，江晴宿霧開。", "風幡兩州見，花供四天來。", "日月依峰轉，魚龍觸石回。", "蓬壺在何處，更擬上層臺。"]'),
('9febd707-566b-4e76-9804-5656e86a964e','過虹縣有作','李昭玘','宋','宋诗','song-poetry','','[]','老態倦羈旅，不堪行舸催。',48,'全唐诗/poet.song.73000.json','["老態倦羈旅，不堪行舸催。", "風高鳥橫度，汀轉樹交回。", "雨過霧猶濕，春寒花未開。", "楚傖如見問，不爲米南來。"]'),
('71b8380d-e207-4aa5-a16d-d6511e13f827','過淮','李昭玘','宋','宋诗','song-poetry','','[]','東風吹雨過淮濱，草木精神一番新。',64,'全唐诗/poet.song.73000.json','["東風吹雨過淮濱，草木精神一番新。", "雁起沙隄烟隔水，寺藏松崦塔招人。", "盪胸長憶江湖月，瞇眼曾嫌京洛塵。", "誰道南來少知識，向人修竹特相親。"]'),
('085ca439-3828-4a3d-b1fc-7a0d89f59a74','登平山堂','李昭玘','宋','宋诗','song-poetry','','[]','斷檻欹簷風雨頻，不逢心賞爲重新。',64,'全唐诗/poet.song.73000.json','["斷檻欹簷風雨頻，不逢心賞爲重新。", "依稀疊嶂宛如畫，憔悴垂楊今復春。", "一闋高歌長在耳，後來佳客復何人。", "悠然未盡雲烟思，不見揚州十里塵。"]'),
('d31b2695-6df8-4b8b-b34e-812551eb0502','泊揚州城外','李昭玘','宋','宋诗','song-poetry','','[]','地占東南會，舟浮百貨通。',48,'全唐诗/poet.song.73000.json','["地占東南會，舟浮百貨通。", "惺忪喜淮粲，啁哳困吳農。", "春喚雁俱北，水將人更東。", "吾廬杳何在，天末暮霞紅。"]'),
('3db5c647-5a43-4de6-a6eb-5480dab39039','贈盱眙令王邦直','李昭玘','宋','宋诗','song-poetry','','[]','樽酒留連淮水邊，一燈相對共茫然。',64,'全唐诗/poet.song.73000.json','["樽酒留連淮水邊，一燈相對共茫然。", "退閒得計我華髮，撫字有聲君壯年。", "幸有高情種松竹，可無餘思落淮川。", "南金不用充行贐，古錦囊中乞數篇。"]'),
('c8b9b26d-14fa-446c-8028-7c4e6c9d581f','還家有作','李昭玘','宋','宋诗','song-poetry','','[]','還家春已晚，風雨誤歸期。',48,'全唐诗/poet.song.73000.json','["還家春已晚，風雨誤歸期。", "飲啖嬉兒笑，形容吠犬疑。", "江山猶似夢，巾篋謾多詩。", "未負東園醉，桃花正此時。"]'),
('ff03a062-5845-4048-b149-66f7e0647bc6','和程適正見贈二首  其一','李昭玘','宋','宋诗','song-poetry','','[]','壯歲干名幸起家，十年蹭蹬一長嗟。',64,'全唐诗/poet.song.73000.json','["壯歲干名幸起家，十年蹭蹬一長嗟。", "憑陵初託風前鷁，淘汰終隨浪底沙。", "沒得玄機問黄檗，却將齊物付南華。", "感君憐我貽佳句，一段秋光照晚霞。"]'),
('a90b3003-8fba-4de5-a3da-8c93a0f8af48','和程適正見贈二首  其二','李昭玘','宋','宋诗','song-poetry','','[]','簿領棲遲嘆陸沈，滔滔何處覓知音。',64,'全唐诗/poet.song.73000.json','["簿領棲遲嘆陸沈，滔滔何處覓知音。", "凌雲詞句豪難敵，似水交情老更深。", "鼷鼠飲河聊滿腹，白雲出岫本無心。", "從今收拾身閒計，洗竹鋤花日醉吟。"]'),
('781bab9c-ba77-483b-9a39-ff62642fcb32','北園書事三首  其一','李昭玘','宋','宋诗','song-poetry','','[]','葛巾茅屋自爲娛，門掩槐陰長夏初。',64,'全唐诗/poet.song.73000.json','["葛巾茅屋自爲娛，門掩槐陰長夏初。", "聒聒難休鳩喚婦，飛飛不定燕將雛。", "繞池曳策携雙鶴，架水澆花課小奴。", "麥飯滿甌葵數筯，丁寧車馬肯來無。"]'),
('571b9ea3-4724-4b2b-855d-4cec34cd389f','北園書事三首  其二','李昭玘','宋','宋诗','song-poetry','','[]','得喪有萬理，古今猶一區。',24,'全唐诗/poet.song.73000.json','["得喪有萬理，古今猶一區。", "鶴鳬元自足，蠻觸竟同枯。"]'),
('2a63e19b-04db-4a9a-b7f4-594b45be2a3c','北園書事三首  其三','李昭玘','宋','宋诗','song-poetry','','[]','十年蕭散愈身輕，弄筆翻書亦稱情。',64,'全唐诗/poet.song.73000.json','["十年蕭散愈身輕，弄筆翻書亦稱情。", "當案忽聞緣壁墮，隔池遥見啄苔行。", "靜疑多事非求福，老覺無心勝攝生。", "自愛吾廬人不到，何須谷口問歸耕。"]'),
('0028e8aa-3181-45fc-a04c-69d376e3f9a4','贈子常二首  其一','李昭玘','宋','宋诗','song-poetry','','[]','幽蘭一曲思無涯，炊熟黄粱日已斜。',64,'全唐诗/poet.song.73000.json','["幽蘭一曲思無涯，炊熟黄粱日已斜。", "閉戶終年心似水，讀書萬卷眼生花。", "汗流不舍浯溪刻，糧絕猶須北苑芽。", "束帛不來人已老，只將清白付吾家。"]'),
('8892151a-9e4d-4160-977f-038d635eb697','贈子常二首  其二','李昭玘','宋','宋诗','song-poetry','','[]','本無機械亦非愚，自信沈冥與世疏。',64,'全唐诗/poet.song.73000.json','["本無機械亦非愚，自信沈冥與世疏。", "一段畫圖冬卧雪，平生樂事日翻書。", "田園無暇供餘稅，風雨何堪卷敝廬。", "笑殺貴人門下客，不逢此老曳長裾。"]'),
('f6bcb284-648a-43c6-b7df-791a57907325','贈故人劉器之待制','李昭玘','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','文史當年共講磨，扁舟此地復經過。',64,'全唐诗/poet.song.73000.json','["文史當年共講磨，扁舟此地復經過。", "流年屈指夢相似，白髮論心喜倍多。", "寄眼偶懷梁苑雪，臨風猶駭洞庭波。", "從今燕坐參空寂，却笑天人被佛魔。"]'),
('c0c73f5d-bf78-4fdb-b3be-c59b0a42c68e','早秋書事二首  其一','李昭玘','宋','宋诗','song-poetry','','[]','正晝睡方起，門無雀可羅。',48,'全唐诗/poet.song.73000.json','["正晝睡方起，門無雀可羅。", "風池亂荷蓋，雨徑滿槐鵝。", "齒髮流年速，江湖歸興多。", "終期買船去，卧月扣舷歌。"]'),
('7307837a-e508-4b9b-9476-5fba72570a1b','早秋書事二首  其二','李昭玘','宋','宋诗','song-poetry','','[]','盡日與琴語，經旬無客過。',48,'全唐诗/poet.song.73000.json','["盡日與琴語，經旬無客過。", "蟬移鵲爭樹，魚散雨傾河。", "每悟酒如聖，不禁詩作魔。", "風聲稍蕭瑟，殘熱定無多。"]'),
('94cb258d-19f9-4ce6-8ef5-1ae88421769c','齒落','李昭玘','宋','宋诗','song-poetry','','[]','孽蟲負固飽羶葷，摧折纔能絕禍根。',64,'全唐诗/poet.song.73000.json','["孽蟲負固飽羶葷，摧折纔能絕禍根。", "每遇屠門慚大嚼，猶思夢澤欲平吞。", "初摇不爲脣先喪，已脫翻驚舌尚存。", "莫與時人作嘲笑，不如緘口學無言。"]'),
('beb9aac5-4907-40b2-9a74-728b9aa8ff85','髮白有感','李昭玘','宋','宋诗','song-poetry','','[]','剪媙無多日，星星已數莖。',48,'全唐诗/poet.song.73000.json','["剪媙無多日，星星已數莖。", "不空年可諱，端與事俱生。", "安得馬肝石，未嘗甘露羹。", "有情憐陸展，解與小兒爭。"]'),
('061f55c9-6b2a-45aa-9e5b-9b6c9e3b3e30','早秋','李昭玘','宋','宋诗','song-poetry','','[]','大暑不可怨，秋來終有時。',48,'全唐诗/poet.song.73000.json','["大暑不可怨，秋來終有時。", "露驚庭鵲睡，風動井梧枝。", "逐客長夜感，美人團扇悲。", "如何陶靖節，獨與菊花期。"]'),
('5bc2fd97-ebeb-4801-828d-02ede41deca6','贈漢臣','李昭玘','宋','宋诗','song-poetry','','[]','夫子以貧病，終身復凍饑。',48,'全唐诗/poet.song.73000.json','["夫子以貧病，終身復凍饑。", "捉衿無可攬，數米不成炊。", "何以謝蟋蟀，獨能留扊扅。", "徒勞問倉扁，王老是良醫。"]'),
('2495e986-cbc8-4eeb-8d7d-34e9d60001a7','八月十五日夜大雨','李昭玘','宋','宋诗','song-poetry','','[]','風伯遭讒不自停，鞭龍倒海勢如傾。',64,'全唐诗/poet.song.73000.json','["風伯遭讒不自停，鞭龍倒海勢如傾。", "胸中洗盡三年渴，□□□□□□□。", "□□□□□□□，千倉嘉穀入新耕。", "野人亦有充饑幸，相見春綿滿眼明。"]'),
('7f17dd71-1cf8-4686-9084-f1b8b8176125','九月八日雨作','李昭玘','宋','宋诗','song-poetry','','[]','盪滌驕陽勢已迴，徧流和氣入根荄。',64,'全唐诗/poet.song.73000.json','["盪滌驕陽勢已迴，徧流和氣入根荄。", "簷間點急侵燈落，枕底聲高带雁來。", "永夜故留人不寐，輕寒未放菊全開。", "明年麥價應如土，安用登高把酒盃。"]'),
('d81630de-2db8-40df-a653-a64d636d166c','北園偶成二首  其一','李昭玘','宋','宋诗','song-poetry','','[]','游宦歸來似繫匏，偶依河渚寄衡茅。',64,'全唐诗/poet.song.73000.json','["游宦歸來似繫匏，偶依河渚寄衡茅。", "以貧爲樂漫喜酒，與世無求非絕交。", "倚杖靜聞風過竹，枕書閒看燕爭巢。", "却憐多事揚夫子，更爲玄文作解嘲。"]'),
('879fe46e-f12b-4eba-a5c7-49ee042443aa','北園偶成二首  其二','李昭玘','宋','宋诗','song-poetry','','[]','酒昏便書榻，詩瘦怯寒葅。',48,'全唐诗/poet.song.73000.json','["酒昏便書榻，詩瘦怯寒葅。", "志大懷千駟，功高憶五湖。", "□□□□□，□□□□□。", "何如一盃粥，晴日照吾廬。"]'),
('987ffd7b-e406-4d68-ac85-a0b812b8d35e','送春','李昭玘','宋','宋诗','song-poetry','','[]','終日無人晝掩扉，綠陰庭草自相依。',64,'全唐诗/poet.song.73000.json','["終日無人晝掩扉，綠陰庭草自相依。", "輕寒曉覺池臺靜，半夜春隨風雨歸。", "恰似舊遊鶑獨語，略無餘恨燕爭飛。", "飄零不解東君意，却放楊花亂撲衣。"]'),
('1d785792-76a6-44a8-a3a9-69f4100260f0','有客携扇欲予題字因以一絕答之','李昭玘','宋','宋诗','song-poetry','','[]','平生自笑書成癖，運墨圓毫日幾回。',32,'全唐诗/poet.song.73000.json','["平生自笑書成癖，運墨圓毫日幾回。", "六角招人聊一戲，區區老媼復能來。"]'),
('1f682c56-dcbe-4787-bf73-470d7c9e0653','和鮑輦七夕四絕  其一','李昭玘','宋','宋诗','song-poetry','','[]','織女黄姑天一隅，九清飛馭盡通衢。',32,'全唐诗/poet.song.73000.json','["織女黄姑天一隅，九清飛馭盡通衢。", "年年須作秋風約，此事朦朧信有無。"]'),
('2fc62800-ce86-4b29-a46f-7f834ee38acd','和鮑輦七夕四絕  其二','李昭玘','宋','宋诗','song-poetry','','[]','奕奕流雲度太虛，盛陳瓜果望天衢。',32,'全唐诗/poet.song.73000.json','["奕奕流雲度太虛，盛陳瓜果望天衢。", "嘗聞刻楮三年久，一夕穿針乞得無。"]'),
('63283c28-5f20-42fe-b4a4-c67629969578','和鮑輦七夕四絕  其三','李昭玘','宋','宋诗','song-poetry','','[]','如何靈匹異人間，脈脈相望卒卒還。',32,'全唐诗/poet.song.73000.json','["如何靈匹異人間，脈脈相望卒卒還。", "不用蛛絲爭送巧，自知得拙半生閒。"]'),
('51b85e39-0cb1-4c67-95e4-b6cedb1909e2','和鮑輦七夕四絕  其四','李昭玘','宋','宋诗','song-poetry','','[]','一水盈盈會合難，古今雲路暫來還。',32,'全唐诗/poet.song.73000.json','["一水盈盈會合難，古今雲路暫來還。", "幾多靈鵲成橋去，獨有棲烏月底閒。"]'),
('689be189-4cf6-4f90-a9a6-3963205e352f','十月晦過舍弟庭玉處見諸人棋戰方酣頃之復過集者皆散獨枰尚在窗戶閴然因成三篇呈子常漢臣  其一','李昭玘','宋','宋诗','song-poetry','','[]','妙手固多暇，忿兵終易窮。',48,'全唐诗/poet.song.73000.json','["妙手固多暇，忿兵終易窮。", "戲餘歸一笑，戰罷失羣雄。", "風過雨雹息，天明星斗空。", "爛柯人已去，斜日上窗紅。"]'),
('5be452c1-7bae-4c56-8de4-4cd059147daa','十月晦過舍弟庭玉處見諸人棋戰方酣頃之復過集者皆散獨枰尚在窗戶閴然因成三篇呈子常漢臣  其二','李昭玘','宋','宋诗','song-poetry','','[]','一先雖自喜，百戰亦須窮。',48,'全唐诗/poet.song.73000.json','["一先雖自喜，百戰亦須窮。", "狡兔有三窟，連鷄無兩雄。", "霸成秦陌廣，騎去楚營空。", "老子無知解，頹然醉頰紅。"]'),
('b8a770ad-15e4-4991-9b1c-61bb041807c7','十月晦過舍弟庭玉處見諸人棋戰方酣頃之復過集者皆散獨枰尚在窗戶閴然因成三篇呈子常漢臣  其三','李昭玘','宋','宋诗','song-poetry','','[]','得失信偶爾，好謀徒自窮。',48,'全唐诗/poet.song.73000.json','["得失信偶爾，好謀徒自窮。", "前功竟何在，百戰漫爭雄。", "昧者甘守拙，高人成悟空。", "不如來飲酒，聽唱小桃紅。"]'),
('86d25ea7-2b03-4212-b6ae-dac0c76e7746','御試宿集英殿雨過有作呈敏甫學士','李昭玘','宋','宋诗','song-poetry','','[]','朝寒生廣陌，宿雨漲方池。',48,'全唐诗/poet.song.73000.json','["朝寒生廣陌，宿雨漲方池。", "霧柳和鴉重，風簾爲燕欹。", "□□□□□，□□□□□。", "多才惡摩詰，無日不成詩。"]'),
('934eccd7-c99b-40d7-9347-380004d0d28f','子常生日無以爲壽偶得團茶一餠因書拙詩一首藉之以獻','李昭玘','宋','宋诗','song-poetry','','[]','比年方貢競珍藏，膚理豐腴紫璧光。',64,'全唐诗/poet.song.73000.json','["比年方貢競珍藏，膚理豐腴紫璧光。", "虬膂左回分絕格，蒻衣十襲護新香。", "貴人恩澤纔浮賜，俗骨塵埃不合嘗。", "願作詩翁千歲壽，乘風聊復發清狂。"]'),
('88c13827-b345-40ab-81db-e9b86321c7b0','迎駕','李昭玘','宋','宋诗','song-poetry','','[]','端門萬騎錦衣紅，迤邐鳴矟下半空。',64,'全唐诗/poet.song.73000.json','["端門萬騎錦衣紅，迤邐鳴矟下半空。", "天極奧居黄道北，瑶池歸仗五雲中。", "金輿影度長廊日，法曲聲回廣殿風。", "泗水昔年曾夢到，拜恩何幸接鵷鴻。"]'),
('181a422b-1c1f-4ff7-9c1e-bc6e48a66c1d','喜晴寄張使君','李昭玘','宋','宋诗','song-poetry','','[]','使君仁術物同情，日望田疇祝頌成。',64,'全唐诗/poet.song.73000.json','["使君仁術物同情，日望田疇祝頌成。", "夜滴未休心欲折，朝陽初放眼先明。", "比年歲熟多中上，此事邊防繫重輕。", "食足訟稀真可樂，時傾盃酒話平生。"]'),
('d4e4c093-1498-471f-99b5-b8d1fc1330ad','无咎哀辭二首  其一','李昭玘','宋','宋诗','song-poetry','','[]','落落孤標氣吐虹，青雲指日黑頭公。',64,'全唐诗/poet.song.73000.json','["落落孤標氣吐虹，青雲指日黑頭公。", "兩行粉字平生盡，一曲龍吟萬事空。", "夾路衣冠如昨日，故園桃李又春風。", "朱弦雖在知音絕，樽酒今誰笑語同。"]'),
('38d1a0bb-441f-4197-85c3-b7e4f8388c51','无咎哀辭二首  其二','李昭玘','宋','宋诗','song-poetry','','[]','才屈千人未易量，妙年文采已飛揚。',64,'全唐诗/poet.song.73000.json','["才屈千人未易量，妙年文采已飛揚。", "終身祇得一麾守，後日空留萬丈光。", "風馭不來成寂絕，玉樓何在隔蒼茫。", "可堪回首魚峰路，滿崦青松照夕陽。"]'),
('be910fc5-66b6-4ce4-b8cd-cf6c53d15c86','送次膺赴詔二首  其一','李昭玘','宋','宋诗','song-poetry','','[]','辭章泛濫昔稱雄，飄泊文園偶未逢。',64,'全唐诗/poet.song.73000.json','["辭章泛濫昔稱雄，飄泊文園偶未逢。", "舊典鐃歌歸制作，盛時郊祀待形容。", "久無青眼憐高卧，新有宮詞落九重。", "異日錦衣還故里，却尋蓮社日相從。"]'),
('4bac58c2-a4b4-4c1f-8ad4-2602c991a781','送次膺赴詔二首  其二','李昭玘','宋','宋诗','song-poetry','','[]','青雲初上萬人看，中路摧頹鎩羽翰。',64,'全唐诗/poet.song.73000.json','["青雲初上萬人看，中路摧頹鎩羽翰。", "一日馳聲動黄閣，幾回飛夢繞長安。", "翩翾丹鳳來天上，寂寞雙松倚歲寒。", "自笑白頭冠尚在，十年塵土不堪彈。"]'),
('73e13a7c-c812-4178-a3e2-5a0d8aa7e5c6','次膺哀辭三首  其一','李昭玘','宋','宋诗','song-poetry','','[]','翻然矯首奉恩除，却似當年擢第初。',64,'全唐诗/poet.song.73000.json','["翻然矯首奉恩除，却似當年擢第初。", "憔悴九衢林下客，光明一軸錦裝書。", "馮陵河岳才無敵，繪畫乾坤思有餘。", "方板赤虯何太迫，君王曾未識相如。"]'),
('f961b53d-6eac-4b0b-8d94-aaec9b617dc8','次膺哀辭三首  其二','李昭玘','宋','宋诗','song-poetry','','[]','平昔弦觴浪自怡，暮年薦鶚有新知。',64,'全唐诗/poet.song.73000.json','["平昔弦觴浪自怡，暮年薦鶚有新知。", "蛾眉翻作黄昏哭，樂府空傳白紵詞。", "上國音塵隨夢斷，東山簫管結秋悲。", "風亭月觀依然在，遼鶴歸來復幾時。"]'),
('e2bb2f40-fa83-4667-a3ff-3f3a14518f66','次膺哀辭三首  其三','李昭玘','宋','宋诗','song-poetry','','[]','行止非人不自謀，飄然一葉信沉浮。',64,'全唐诗/poet.song.73000.json','["行止非人不自謀，飄然一葉信沉浮。", "躊躇去步迷三徑，奄忽平生閉一丘。", "韶樂已聞更雅奏，瑶池尤喜近中秋。", "無人解寫昇平事，惆悵騎鯨去不留。"]'),
('f6e418dd-a3a3-4b91-8e75-265806fa5c97','雨後二篇  其一','李昭玘','宋','宋诗','song-poetry','','[]','苦雨幾十日，滿庭多土花。',48,'全唐诗/poet.song.73000.json','["苦雨幾十日，滿庭多土花。", "行螺上牆屋，倒竹卧泥沙。", "澄景生凉吹，晴雲變晚霞。", "却愁清夜夢，無計逐池蛙。"]'),
('e39eac6e-3712-4738-8b98-57f8b81cc441','雨後二篇  其二','李昭玘','宋','宋诗','song-poetry','','[]','一氣不自息，四時如轉丸。',48,'全唐诗/poet.song.73000.json','["一氣不自息，四時如轉丸。", "月流天宇靜，風掠葉聲乾。", "紈扇已謝事，莎蟲將戒寒。", "登臨偶有得，不復計悲歡。"]'),
('e0891143-919c-4d1d-b9e9-18ce05491b7d','贈漢老姪琴','李昭玘','宋','宋诗','song-poetry','','[]','鄒嶧孤桐不可尋，汧公舊斲萬黄金。',64,'全唐诗/poet.song.73000.json','["鄒嶧孤桐不可尋，汧公舊斲萬黄金。", "顧余久有沈舟志，知子嘗懷欲炙心。", "便好安弦求妙趣，不須變雅作新音。", "席間弟子來傾耳，爲問何人屬意深。"]'),
('90255bd1-b5ca-4051-a6bb-8485e78d0561','某氏挽辭二首  其一','李昭玘','宋','宋诗','song-poetry','','[]','翟茀朝初罷，升堂拜已非。',48,'全唐诗/poet.song.73000.json','["翟茀朝初罷，升堂拜已非。", "凝塵孟光案，洒血老萊衣。", "奩鏡悲鸞舞，庭萱感露晞。", "西風原上路，無復板輿歸。"]'),
('c2dfd87e-a521-4e98-9d6e-468946016b61','某氏挽辭二首  其二','李昭玘','宋','宋诗','song-poetry','','[]','主饋齊家道，羞蘩肅婦功。',48,'全唐诗/poet.song.73000.json','["主饋齊家道，羞蘩肅婦功。", "疏封秦大國，致養漢三公。", "世事哀榮極，人生夢幻空。", "慈顔不可望，彤史有遺風。"]'),
('114c2bc7-55a8-40fb-b383-98378b78e0a0','摘果','李昭玘','宋','宋诗','song-poetry','','[]','霜靜百果熟，採摘將薦新。',72,'全唐诗/poet.song.73000.json','["霜靜百果熟，採摘將薦新。", "貯之黄金盤，絢爛如星陳。", "苞縢待嘉客，培溉昔已勤。", "君子務種德，所成非一身。", "公家有令恩，飣坐多驚人。", "纍纍萬石富，長笑木奴貧。"]'),
('64076b5b-a034-49a6-b5e7-a09f5850e676','培花','李昭玘','宋','宋诗','song-poetry','','[]','惜花如曼容，蠹實害心腹。',21,'全唐诗/poet.song.73000.json','["惜花如曼容，蠹實害心腹。", "養之近胎禍，動絕。"]'),
('3edd64b8-c882-4798-81b5-e99f3274eca1','贊潏水先生','李昭玘','宋','宋诗','song-poetry','','[]','結交頼有紫髯翁，鶴骨嶄嶄爛修目。',32,'全唐诗/poet.song.73000.json','["結交頼有紫髯翁，鶴骨嶄嶄爛修目。", "五言長城屹千丈，萬卷書樓聊一讀。"]');
